  "main.rs": "use radiate::tree::operation::{Op, Operation};
use radiate::tree::{NodeType, Tree};
use radiate::genetic::{Genetic, Problem};
use radiate::selection::TournamentSelection;
use radiate::crossover::SubtreeCrossover;
use radiate::mutation::SubtreeMutation;
use radiate::stop::MaxGenerations;
use rand::SeedableRng;
use rand_xoshiro::Xoshiro256PlusPlus;

// Custom operator: sqrt(x) + 1 with safety for negative inputs
struct SqrtPlusOne;

impl Operation for SqrtPlusOne {
    fn name(&self) -> String {
        "sqrtplusone".to_string()
    }

    fn evaluate(&self, inputs: &[f64]) -> f64 {
        if inputs.is_empty() {
            return 1.0;
        }
        // Clamp to non-negative for sqrt safety
        inputs[0].max(0.0).sqrt() + 1.0
    }

    fn arity(&self) -> usize {
        1
    }

    // Required for cloning boxed custom operations in radiate's tree structures
    fn clone_box(&self) -> Box<dyn Operation> {
        Box::new(SqrtPlusOne)
    }
}

// Symbolic regression problem: approximate f(x) = x² + x + 1
#[derive(Clone)]
struct RegressionProblem {
    inputs: Vec<Vec<f64>>,
    outputs: Vec<f64>,
}

impl Problem for RegressionProblem {
    type Individual = Tree;
    type Fitness = f64;

    fn fitness(&self, individual: &Tree) -> f64 {
        let mut mse = 0.0;
        for (i, input) in self.inputs.iter().enumerate() {
            let prediction = individual.evaluate(input);
            let error = prediction - self.outputs[i];
            mse += error * error;
        }
        mse /= self.inputs.len() as f64;
        // Higher fitness = better (minimize MSE)
        1.0 / (1.0 + mse)
    }
}

fn main() {
    // Generate training data for f(x) = x² + x + 1
    let mut inputs = Vec::new();
    let mut outputs = Vec::new();
    for x in -5..=5 {
        let x_val = x as f64;
        inputs.push(vec![x_val]);
        outputs.push(x_val * x_val + x_val + 1.0);
    }

    let problem = RegressionProblem { inputs, outputs };

    // Define node store WITH custom operator
    let store = vec![
        (
            NodeType::Vertex,
            vec![
                Op::add(),
                Op::sub(),
                Op::mul(),
                Op::pow(),
                // Register custom operator here
                Op::custom("sqrtplusone", Box::new(SqrtPlusOne)),
            ],
        ),
        (NodeType::Leaf, vec![Op::var(0)]),
    ];

    // Initialize RNG
    let mut rng = Xoshiro256PlusPlus::seed_from_u64(42);

    // Create initial population
    let population_size = 50;
    let population: Vec<Tree> = (0..population_size)
        .map(|_| Tree::new(&store, 2, 4, &mut rng))
        .collect();

    // Configure genetic algorithm
    let selection = TournamentSelection::new(3, 0.8);
    let crossover = SubtreeCrossover::new(0.85);
    let mutation = SubtreeMutation::new(&store, 0.1, 1, 3);
    let stop_condition = MaxGenerations::new(15); // Short run for demo

    let mut ga = Genetic::new(
        problem,
        population,
        selection,
        crossover,
        mutation,
        stop_condition,
        rng,
    );

    // Run evolution
    let (best_individual, best_fitness) = ga.run();

    // Output results
    println!("\nTraining complete!");
    println!("Best fitness: {:.6}", best_fitness);
    println!("\nBest program structure:");
    println!("{}", best_individual.display(&store));

    // Verify custom operator usage
    let program_str = best_individual.display(&store).to_string();
    if program_str.contains("sqrtplusone") {
        println!("\n✅ Custom operator 'sqrtplusone' was successfully used!");
    } else {
        println!("\nℹ️  Custom operator not in final solution (may appear in earlier generations)");
    }

    // Quick validation on sample points
    println!("\nValidation on sample points:");
    for &x in &[-2.0, 0.0, 2.0] {
        let pred = best_individual.evaluate(&[x]);
        let target = x * x + x + 1.0;
        println!("x={:>4.1} | Predicted: {:>6.2} | Target: {:>6.2}", x, pred, target);
    }
}"
}

