name = "critical_section_fetch_add_example"
version = "0.1.0"
edition = "2021"

[dependencies]
critical-section = "1.1.1"",
  "main.rs": "use core::sync::atomic::{AtomicUsize, Ordering};
use critical_section;

// Static variable simulating the channel_index field
static CHANNEL_INDEX: AtomicUsize = AtomicUsize::new(0);

fn main() {
    // Reset counter for predictable test
    CHANNEL_INDEX.store(0, Ordering::Relaxed);

    // First simulated fetch_add replacement
    let index1 = critical_section::with(|_| {
        let old_val = CHANNEL_INDEX.load(Ordering::Relaxed);
        CHANNEL_INDEX.store(old_val + 1, Ordering::Relaxed);
        old_val
    });
    assert_eq!(index1, 0, "First call should return initial value 0");
    assert_eq!(CHANNEL_INDEX.load(Ordering::Relaxed), 1, "Counter should be incremented to 1");

    // Second simulated fetch_add replacement
    let index2 = critical_section::with(|_| {
        let old_val = CHANNEL_INDEX.load(Ordering::Relaxed);
        CHANNEL_INDEX.store(old_val + 1, Ordering::Relaxed);
        old_val
    });
    assert_eq!(index2, 1, "Second call should return previous value 1");
    assert_eq!(CHANNEL_INDEX.load(Ordering::Relaxed), 2, "Counter should be incremented to 2");

    // Verify critical section prevents torn reads during modification
    let final_val = critical_section::with(|_| {
        let current = CHANNEL_INDEX.load(Ordering::Relaxed);
        // Simulate multi-step operation that must be atomic
        let intermediate = current * 2;
        CHANNEL_INDEX.store(intermediate, Ordering::Relaxed);
        intermediate
    });
    assert_eq!(final_val, 4, "Value after complex operation should be 4");

    println!("✓ All correctness checks passed!");
    println!("✓ Ordering::Relaxed is correct inside critical_section");
    println!("  - Critical section provides atomicity via interrupt masking");
    println!("  - No cross-core synchronization needed (single-core context)");
    println!("  - Relaxed ordering sufficient: critical section acts as full barrier");
    println!("  - Stronger orderings would add unnecessary overhead on Cortex-M0+");
}"
}

