{
  "Cargo.toml": "[package]
name = "nested_deserialize_example"
version = "0.1.0"
edition = "2021"

[dependencies]
serde = "1.0"
serde_json = "1.0"",
  "main.rs": "use serde::{Deserialize, Deserializer};
use serde::de::{
    self, Visitor, MapAccess, IgnoredAny, Error as DeError
};
use std::fmt;
use std::marker::PhantomData;

#[derive(Debug)]
struct A {
    x: usize,
    b: Vec<B>,
}

#[derive(Debug)]
enum B {
    B1 { value: u32 },
    B2 { name: String },
}

// Custom deserializer for B (handles nested structure)
impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        enum Field { Type, Value, Name }

        // Field visitor to parse keys in B's map
        struct FieldVisitor;
        impl<'de> Visitor<'de> for FieldVisitor {
            type Value = Field;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("`type`, `value`, or `name`")
            }

            fn visit_str<E>(self, value: &str) -> Result<Field, E>
            where
                E: de::Error,
            {
                match value {
                    "type" => Ok(Field::Type),
                    "value" => Ok(Field::Value),
                    "name" => Ok(Field::Name),
                    _ => Err(de::Error::unknown_field(value, FIELDS)),
                }
            }
        }

        const FIELDS: &[&str] = &["type", "value", "name"];

        struct BVisitor;
        impl<'de> Visitor<'de> for BVisitor {
            type Value = B;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("map with `type` field for B variant")
            }

            fn visit_map<V>(self, mut map: V) -> Result<B, V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut type_val = None;
                let mut value_val = None;
                let mut name_val = None;

                while let Some(key) = map.next_key_seed(FieldVisitor)? {
                    match key {
                        Field::Type => {
                            if type_val.is_some() {
                                return Err(de::Error::duplicate_field("type"));
                            }
                            type_val = Some(map.next_value::<String>()?);
                        }
                        Field::Value => {
                            if value_val.is_some() {
                                return Err(de::Error::duplicate_field("value"));
                            }
                            value_val = Some(map.next_value()?);
                        }
                        Field::Name => {
                            if name_val.is_some() {
                                return Err(de::Error::duplicate_field("name"));
                            }
                            name_val = Some(map.next_value()?);
                        }
                    }
                }

                let variant = type_val.ok_or_else(|| de::Error::missing_field("type"))?;
                match variant.as_str() {
                    "B1" => {
                        let value = value_val.ok_or_else(|| de::Error::missing_field("value"))?;
                        Ok(B::B1 { value })
                    }
                    "B2" => {
                        let name = name_val.ok_or_else(|| de::Error::missing_field("name"))?;
                        Ok(B::B2 { name })
                    }
                    _ => Err(de::Error::unknown_variant(&variant, &["B1", "B2"])),
                }
            }
        }

        deserializer.deserialize_map(BVisitor)
    }
}

// Custom deserializer for A (handles top-level structure and delegates to B)
impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        enum Field { X, B }

        // Field visitor to parse keys in A's map
        struct FieldVisitor;
        impl<'de> Visitor<'de> for FieldVisitor {
            type Value = Field;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("`x` or `b`")
            }

            fn visit_str<E>(self, value: &str) -> Result<Field, E>
            where
                E: de::Error,
            {
                match value {
                    "x" => Ok(Field::X),
                    "b" => Ok(Field::B),
                    _ => Err(de::Error::unknown_field(value, FIELDS)),
                }
            }
        }

        const FIELDS: &[&str] = &["x", "b"];

        struct AVisitor;
        impl<'de> Visitor<'de> for AVisitor {
            type Value = A;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("map with `x` and `b` fields")
            }

            fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut x_val = None;
                let mut b_val = None;

                while let Some(key) = map.next_key_seed(FieldVisitor)? {
                    match key {
                        Field::X => {
                            if x_val.is_some() {
                                return Err(de::Error::duplicate_field("x"));
                            }
                            x_val = Some(map.next_value()?);
                        }
                        Field::B => {
                            if b_val.is_some() {
                                return Err(de::Error::duplicate_field("b"));
                            }
                            // CRITICAL: This delegates to B's custom deserializer!
                            // serde will automatically use B's Deserialize impl for each element
                            b_val = Some(map.next_value()?);
                        }
                    }
                }

                let x = x_val.ok_or_else(|| de::Error::missing_field("x"))?;
                let b = b_val.ok_or_else(|| de::Error::missing_field("b"))?;
                Ok(A { x, b })
            }
        }

        deserializer.deserialize_map(AVisitor)
    }
}

fn main() {
    // Valid JSON matching our custom deserialization structure
    let json_data = r#"
    {
        "x": 42,
        "b": [
            { "type": "B1", "value": 100 },
            { "type": "B2", "name": "nested_example" },
            { "type": "B1", "value": 250, "extra_ignored": "field" }
        ]
    }
    "#;

    match serde_json::from_str::<A>(json_data) {
        Ok(a) => {
            println!("Deserialization successful!");
            println!("A {{ x: {}, b: {:?} }}", a.x, a.b);
        }
        Err(e) => {
            eprintln!("Deserialization failed: {}", e);
            std::process::exit(1);
        }
    }

    // Demonstrate error handling for invalid key (addresses user's runtime error concern)
    let invalid_json = r#"{ "X": 10, "b": [] }"#; // Note capital 'X'
    match serde_json::from_str::<A>(invalid_json) {
        Ok(_) => println!("Unexpected success on invalid key"),
        Err(e) => println!("Correctly rejected invalid key: {}", e),
    }
}
"
}

