  "main.rs": "use polars::prelude::*;
use polars::datatypes::{DataType, Field};
use polars::chunked_array::builder::ListChunkedBuilder;

fn main() -> PolarsResult<()> {
    // Create sample DataFrame with input column
    let df = df![
        "col1" => ["row0", "row1"]
    ]?;

    let lf = df.lazy();

    // Transform: map each string to a list of structs
    let lf = lf.with_column(
        col("col1")
            .map(
                move |s| {
                    let v_str = s.str()?;
                    // Define inner struct dtype for list elements
                    let inner_dtype = DataType::Struct(vec![
                        Field::new(PlSmallStr::from("c1"), DataType::String),
                        Field::new(PlSmallStr::from("c2"), DataType::String),
                    ]);

                    let mut builder = ListChunkedBuilder::new(
                        PlSmallStr::from("output"),
                        v_str.len(),
                        inner_dtype.clone(),
                    );

                    // Process each row in the chunk
                    for opt_s in v_str.into_iter() {
                        match opt_s {
                            Some(s_val) => {
                                // Generate struct values based on input string (matching example output)
                                let (c1_vals, c2_vals) = if s_val == "row0" {
