                                let c1_series = Series::new(PlSmallStr::from("c1"), c1_vals);
                                let c2_series = Series::new(PlSmallStr::from("c2"), c2_vals);
                                let struct_ca = StructChunked::new(
                                    PlSmallStr::from("row_structs"),
                                    &[c1_series, c2_series],
                                )?;

                                // Append struct array as single list element
                                builder.append_series(&struct_ca.into_series());
                            }
                            None => builder.append_null(),
                        }
                    }

                    Ok(builder.finish().into_series())
                },
                move |_, _| {
                    // Schema inference: output is List[Struct]
                    let inner_dtype = DataType::Struct(vec![
                        Field::new(PlSmallStr::from("c1"), DataType::String),
