    filter::LevelFilter,
    layer::SubscriberExt,
    reload,
    fmt,
    Registry,
    util::SubscriberInitExt,
};
use tracing_appender::non_blocking::WorkerGuard;
use std::{thread, time::Duration};

fn main() {
    // Setup file appender with non-blocking writer
    let file_appender = tracing_appender::rolling::never(".", "logfile.log");
    let (non_blocking_file, _guard) = tracing_appender::non_blocking(file_appender);

    // Create reloadable filter handle for CONSOLE layer only
    let (console_filter, console_reload_handle) = reload::Layer::new(LevelFilter::INFO);

    // Build subscriber with two independent layers
    let subscriber = Registry::default()
        // Console layer (stdout) with DYNAMIC filter
        .with(
            fmt::layer()
                .compact()
                .with_ansi(true)
                .with_filter(console_filter),
        )
        // File layer with STATIC DEBUG filter (unaffected by reload)
        .with(
            fmt::layer()
                .with_ansi(false)
                .with_writer(non_blocking_file)
                .with_filter(LevelFilter::DEBUG),
        );

    // Initialize global subscriber (ONLY ONCE)
    subscriber.init();

    // Log before filter change
    info!("=== BEFORE FILTER CHANGE ===");
    info!("Console shows INFO+, file shows DEBUG+");
    debug!("DEBUG msg: visible ONLY in file (console still at INFO)");
    thread::sleep(Duration::from_secs(1));

    // DYNAMICALLY CHANGE ONLY CONSOLE LAYER'S FILTER
    console_reload_handle
        .modify(|filter| *filter = LevelFilter::DEBUG)
        .expect("Failed to reload console filter");
    info!("✅ Console log level changed to DEBUG (file layer unchanged)");

    // Log after filter change
    info!("=== AFTER FILTER CHANGE ===");
    debug!("DEBUG msg: NOW visible in BOTH console and file");
    thread::sleep(Duration::from_secs(1));

    // Demonstrate independent control: change console back to WARN
    console_reload_handle
        .modify(|filter| *filter = LevelFilter::WARN)
        .expect("Failed to reload console filter");
    info!("ℹ️  Console changed to WARN (this INFO msg won't appear on console)");
    warn!("WARN msg: visible on console and in file");

    // Keep guard alive until end to flush logs
    drop(_guard);
    println!("\n✅ Check logfile.log for complete output (contains all DEBUG+ messages)");
    println!("✅ Console only showed messages matching its DYNAMIC filter levels");
}"
