/// Minimal Array implementation for demonstration
#[derive(Debug, Clone)]
pub struct Array<T> {
    store: Vec<T>,
    dims: Vec<usize>,
}

impl<T> Array<T> {
    pub fn new(store: Vec<T>, dims: Vec<usize>) -> Self {
        assert!(store.len() == dims.iter().product::<usize>(),
                "Store size must match product of dimensions");
        Array { store, dims }
    }

    /// Convert cartesian index to flat index (row-major)
    fn cartesian_to_flat(&self, index: &[usize]) -> usize {
        let mut flat = 0;
        let mut stride = 1;
        for (i, &dim) in self.dims.iter().rev().enumerate() {
            let pos = index[self.dims.len() - 1 - i];
            assert!(pos < dim, "Index out of bounds");
            flat += pos * stride;
            stride *= dim;
        }
        flat
    }

    /// Immutable indexing
    pub fn get(&self, index: &[usize]) -> &T {
        &self.store[self.cartesian_to_flat(index)]
    }

    /// Mutable indexing
    pub fn get_mut(&mut self, index: &[usize]) -> &mut T {
        let idx = self.cartesian_to_flat(index);
        &mut self.store[idx]
    }

    /// Create immutable iterator over all elements (row-major order)
    pub fn iter(&self) -> ArrayIter<T> {
        ArrayIter {
            array: self,
            current: vec![0; self.dims.len()],
            exhausted: false,
        }
    }

    /// Create mutable iterator over all elements (row-major order)
    /// Uses unsafe to resolve lifetime issues while guaranteeing non-overlapping access
    pub fn iter_mut(&mut self) -> ArrayIterMut<T> {
        let base_ptr = self.store.as_mut_ptr();
        ArrayIterMut {
            base_ptr,
            dims: self.dims.clone(),
            current: vec![0; self.dims.len()],
            exhausted: false,
            _marker: PhantomData,
        }
    }
}

/// Immutable iterator returning (index, &T)
pub struct ArrayIter<'a, T> {
    array: &'a Array<T>,
    current: Vec<usize>,
    exhausted: bool,
}

impl<'a, T> Iterator for ArrayIter<'a, T> {
    type Item = (Vec<usize>, &'a T);

    fn next(&mut self) -> Option<Self::Item> {
        if self.exhausted {
            return None;
        }

        let index = self.current.clone();

        // Increment index (row-major order)
        let mut carry = true;
        for i in (0..self.current.len()).rev() {
            if carry {
                if self.current[i] + 1 < self.array.dims[i] {
                    self.current[i] += 1;
                    carry = false;
                } else {
                    self.current[i] = 0;
                }
            }
        }

        if carry {
            self.exhausted = true;
        }

        Some((index, self.array.get(&index)))
    }
}

/// Mutable iterator returning (index, &mut T)
/// Uses raw pointer to avoid lifetime conflicts while ensuring safety:
/// - Only one mutable reference exists at a time
/// - Indices are guaranteed non-overlapping
/// - Base pointer valid for 'a (enforced by PhantomData)
pub struct ArrayIterMut<'a, T> {
    base_ptr: *mut T,
    dims: Vec<usize>,
    current: Vec<usize>,
    exhausted: bool,
    _marker: PhantomData<&'a mut T>,
}

impl<'a, T> Iterator for ArrayIterMut<'a, T> {
    type Item = (Vec<usize>, &'a mut T);

    fn next(&mut self) -> Option<Self::Item> {
        if self.exhausted {
            return None;
        }

        let index = self.current.clone();

        // Increment index (row-major order)
        let mut carry = true;
        for i in (0..self.current.len()).rev() {
            if carry {
                if self.current[i] + 1 < self.dims[i] {
                    self.current[i] += 1;
                    carry = false;
                } else {
                    self.current[i] = 0;
                }
            }
        }

        if carry {
            self.exhausted = true;
        }

        // SAFETY:
        // 1. base_ptr was created from a valid Array with lifetime 'a
        // 2. cartesian_to_flat produces valid in-bounds index (dims match original array)
        // 3. Each index is visited exactly once → no aliasing
        // 4. PhantomData ties lifetime to original borrow
        let flat_idx = {
            let mut flat = 0;
            let mut stride = 1;
            for (i, &dim) in self.dims.iter().rev().enumerate() {
                let pos = index[self.dims.len() - 1 - i];
                flat += pos * stride;
                stride *= dim;
            }
            flat
        };

        unsafe {
            let elem_ptr = self.base_ptr.add(flat_idx);
            Some((index, &mut *elem_ptr))
        }
    }
}

fn main() {
    // Create a 2x3 array: [[1, 2, 3], [4, 5, 6]]
    let mut arr = Array::new(vec![1, 2, 3, 4, 5, 6], vec![2, 3]);

    println!("Immutable iteration (original values):");
    for (idx, val) in arr.iter() {
        println!("Index {:?}: {}", idx, val);
    }

