use std::future::Future;
use std::pin::Pin;
use std::sync::Arc;

/// Example context type
pub struct Context(i32);

/// Event carrying async work that operates on `Context`
pub enum InnerAsyncEvent {
    DoWithContext {
        // Boxed closure that:
        // - Takes mutable ref to Context with any lifetime
        // - Returns a Send future valid for that lifetime
        // - Is itself Send for cross-thread transfer
        block: Box<
            dyn for<'a> Fn(
                &'a mut Context,
            ) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
                + Send,
        >,
    },
}

/// Helper to send async workloads cleanly.
/// 
/// # Why this works on stable Rust:
/// - Avoids unstable `AsyncFnOnce` by using standard `Fn` trait
/// - Requires futures to be `Send` explicitly
/// - Uses `Arc` for captured state (thread-safe)
/// - Higher-ranked lifetime ensures context borrowing safety
pub fn with_context_async<F>(
    work_sender: &mut mpsc::Sender<InnerAsyncEvent>,
    block: F,
) where
    F: for<'a> Fn(&'a mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
        + Send
        + 'static,
{
    let _ = work_sender.send(InnerAsyncEvent::DoWithContext {
        block: Box::new(block),
    });
}

#[tokio::main]
async fn main() {
    let (mut tx, mut rx) = mpsc::channel(10);

    // Example 1: Simple async operation (no captured state)
    with_context_async(&mut tx, |ctx| {
        Box::pin(async move {
            ctx.0 += 1;
            println!("[Event 1] Context incremented to: {}", ctx.0);
        })
    });

    // Example 2: Capturing external state safely with Arc
    let bonus = Arc::new(42);
    with_context_async(&mut tx, move |ctx| {
        let bonus = Arc::clone(&bonus);
        Box::pin(async move {
            ctx.0 += *bonus;
            println!("[Event 2] Added bonus {}: context = {}", *bonus, ctx.0);
        })
    });

    // Spawn worker thread to process events
    tokio::spawn(async move {
        let mut ctx = Context(0);
        while let Some(event) = rx.recv().await {
            if let InnerAsyncEvent::DoWithContext { block } = event {
                block(&mut ctx).await;
            }
        }
        println!("\n✅ Final context value: {}", ctx.0);
        println!("✅ All events processed successfully!");
    });

    // Cleanup: close channel and wait for worker
    drop(tx);
    tokio::time::sleep(tokio::time::Duration::from_millis(50)).await;
}
