use expectrl::{spawn, Session};
use nix::fcntl::{fcntl, FcntlArg, OFlag};
use nix::unistd::RawFd;
use std::io::{Read, Write};
use std::thread;
use std::time::Duration;
use tauri::Manager;

/// Sets a file descriptor to non-blocking mode
fn set_nonblocking(fd: RawFd) -> nix::Result<()> {
    let flags = OFlag::from_bits_truncate(fcntl(fd, FcntlArg::F_GETFL)?);
    fcntl(fd, FcntlArg::F_SETFL(flags | OFlag::O_NONBLOCK))?;
    Ok(())
}

/// PTY handler thread: owns session, handles I/O without mutex contention
fn spawn_pty_handler(
    mut session: Session,
    rx: Receiver<Vec<u8>>,
    app_handle: tauri::AppHandle,
) -> Result<thread::JoinHandle<()>> {
    // Get master FD and set non-blocking
    let fd = session.get_master_fd();
    set_nonblocking(fd).context("Failed to set PTY non-blocking")?;

    let handler = thread::spawn(move || {
        let mut read_buf = [0u8; 4096];
        let mut write_buf = Vec::new();
        let mut session_closed = false;

        while !session_closed {
            // Prioritize writing pending data
            if !write_buf.is_empty() {
                match session.write(&write_buf) {
                    Ok(n) => {
                        // Remove written bytes
                        let _ = write_buf.drain(..n);
                    }
                    Err(e) if e.kind() == std::io::ErrorKind::WouldBlock => {
                        // Kernel buffer full, retry next iteration
                    }
                    Err(e) => {
                        eprintln!("PTY write error: {}", e);
                        break;
                    }
                }
            }

            // Process new writes from channel
            while let Ok(data) = rx.try_recv() {
                write_buf.extend_from_slice(&data);
            }

            // Read available PTY output
            match session.read(&mut read_buf) {
                Ok(0) => {
                    // EOF - child process exited
                    let _ = app_handle.emit_all("agent-output", "[process terminated]\r\n");
                    session_closed = true;
                    break;
                }
                Ok(n) => {
                    // Forward output to frontend (simulated via stdout + event)
                    let output = String::from_utf8_lossy(&read_buf[..n]).to_string();
                    print!("{}", output);
                    let _ = app_handle.emit_all("agent-output", output);
                }
                Err(e) if e.kind() == std::io::ErrorKind::WouldBlock => {
                    // No data available - continue
                }
                Err(e) => {
                    eprintln!("PTY read error: {}", e);
                    break;
                }
            }

            // Prevent busy-looping (10ms balances responsiveness and CPU)
            thread::sleep(Duration::from_millis(10));
        }
        println!("\nPTY handler thread exited");
    });

    Ok(handler)
}

#[tauri::command]
fn send_to_agent(message: String, state: tauri::State<'_, AppState>) -> Result<(), String> {
    // Convert to bytes (xterm.js sends raw sequences including \r for Enter)
    let bytes = message.as_bytes().to_vec();
