  "Cargo.toml": "[package]
name = "try_poll_example"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["full"] }
futures = "0.3"",
  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll};
use futures::task::noop_waker;

/// Polls a future exactly once.
/// 
/// Returns:
/// - `Ok(output)` if future completed immediately
/// - `Err(pinned_future)` if future returned Pending (caller may spawn)
fn try_poll_once<F: Future>(future: F) -> Result<F::Output, Pin<Box<F>>> {
    let mut pinned = Box::pin(future);
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);

    match pinned.as_mut().poll(&mut cx) {
        Poll::Ready(output) => Ok(output),
        Poll::Pending => Err(pinned),
    }
}

#[tokio::main]
async fn main() {
    // CASE 1: Future that resolves immediately
    let immediate_fut = async { 42 };
    match try_poll_once(immediate_fut) {
        Ok(val) => println!("[CASE 1] Got immediate value: {}", val),
        Err(pinned) => {
            // Should never reach here for this future
            tokio::spawn(async move {
                let v = pinned.await;
                println!("[CASE 1] Spawned task got: {}", v);
            });
        }
    }

    // CASE 2: Future that yields (requires async execution)
    let yielding_fut = async {
        tokio::time::sleep(tokio::time::Duration::from_millis(1)).await;
        100
    };

    match try_poll_once(yielding_fut) {
        Ok(val) => println!("[CASE 2] Unexpected immediate value: {}", val),
        Err(pinned) => {
            // Spawn task to complete the pending future
            tokio::spawn(async move {
                let v = pinned.await;
                println!("[CASE 2] Spawned task got value after yield: {}", v);
            });
        }
    }

    // Allow time for spawned tasks to complete
    tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
    println!("Main completed");
}"
}

