{
  "Cargo.toml": "[package]
name = "serde_demo"
version = "0.1.0"
edition = "2021"

[dependencies]
serde = { version = "1.0", features = ["derive"] }
serde_json = "1.0"",
  "main.rs": "use std::fs;
use std::path::{Path, PathBuf};
use serde::Deserialize;
use serde_json::Value;

#[derive(Deserialize, Debug)]
struct A {
    path_list: Vec<PathBuf>,
}

/// Resolve JSON Pointer (RFC 6901) against a JSON document
fn resolve_json_pointer(doc: &Value, pointer: &str) -> Option<Value> {
    if pointer.is_empty() {
        return Some(doc.clone());
    }
    if !pointer.starts_with('/') {
        return None;
    }
    // Split pointer into tokens (skip initial empty token from leading '/')
    let tokens: Vec<&str> = pointer.split('/').skip(1).collect();
    let mut current = doc;

    for token in tokens {
        // Unescape JSON Pointer escapes: ~1 -> /, ~0 -> ~
        let unescaped = token.replace("~1", "/").replace("~0", "~");
        current = match current {
            Value::Object(map) => map.get(&unescaped)?,
            Value::Array(arr) => {
                let idx = unescaped.parse::<usize>().ok()?;
                if idx < arr.len() {
                    &arr[idx]
                } else {
                    return None;
                }
            }
            _ => return None,
        };
    }
    Some(current.clone())
}

/// Resolve a single $ref string to a JSON value
fn resolve_ref(ref_str: &str, base_dir: &Path) -> Value {
    // Split into file path and JSON pointer parts at first '#'
    let (file_part, pointer_part) = ref_str.split_once('#').unwrap_or((ref_str, ""));

    // Resolve referenced file path (relative to base_dir)
    let file_path = if Path::new(file_part).is_absolute() {
        PathBuf::from(file_part)
    } else {
        base_dir.join(file_part)
    };

    // Read and parse referenced file
    let content = fs::read_to_string(&file_path)
        .unwrap_or_else(|e| panic!("Failed to read referenced file {:?}: {}", file_path, e));
    let target_doc: Value = serde_json::from_str(&content)
        .unwrap_or_else(|e| panic!("Failed to parse JSON in {:?}: {}", file_path, e));

    // Resolve JSON pointer within referenced document
    if pointer_part.is_empty() {
        target_doc
    } else {
        resolve_json_pointer(&target_doc, pointer_part)
            .unwrap_or_else(|| panic!("Failed to resolve pointer '{}' in {:?}", pointer_part, file_path))
    }
}

/// Recursively resolve all $ref objects in a JSON value
fn resolve_json_refs(value: &mut Value, base_dir: &Path) {
    match value {
        Value::Object(obj) => {
            // Check if this object is a $ref container
            if let Some(ref_node) = obj.get("$ref") {
                if let Some(ref_str) = ref_node.as_str() {
                    // Replace entire object with resolved value
                    let resolved = resolve_ref(ref_str, base_dir);
                    *value = resolved;
                    // Recurse into resolved value (may contain nested $refs)
                    resolve_json_refs(value, base_dir);
                    return; // Skip processing original object children
                }
            }
            // Process all child values in object
            for (_, v) in obj.iter_mut() {
                resolve_json_refs(v, base_dir);
            }
        }
        Value::Array(arr) => {
            // Process all elements in array
            for v in arr.iter_mut() {
                resolve_json_refs(v, base_dir);
            }
        }
        _ => {}
    }
}

fn main() {
    // Read and parse b.json
    let b_json_str = fs::read_to_string("b.json").expect("Failed to read b.json");
    let mut b_value: Value = serde_json::from_str(&b_json_str).expect("Failed to parse b.json");

    // Use current directory as base for resolving relative references
    let base_dir = std::env::current_dir().expect("Failed to get current directory");

    // Resolve all $ref references in the JSON tree
    resolve_json_refs(&mut b_value, &base_dir);

    // Deserialize resolved JSON into target struct
    let a_obj: A = serde_json::from_value(b_value).expect("Deserialization failed after reference resolution");

    // Output resolved paths
    for p in &a_obj.path_list {
        println!("{}", p.display());
    }
}"
}

