/// Handler that removes preceding whitespace before inserting char
struct SmartInsertHandler {
    insert_char: String,
}

impl SmartInsertHandler {
    fn new(c: char) -> Self {
        Self {
            insert_char: c.to_string(),
        }
    }
}

impl ConditionalEventHandler for SmartInsertHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();
        let line_before = &line[..pos];

        // Find last non-whitespace character before cursor
        if let Some(last_non_ws) = line_before.rfind(|c: char| !c.is_whitespace()) {
            // Calculate whitespace count between last non-WS char and cursor
            if let Some(ws_count) = pos.checked_sub(last_non_ws + 1) {
                if ws_count > 0 {
                    // Chain commands using Macro (requires rustyline >=11.0.0):
                    // 1. Move cursor back to start of whitespace
                    // 2. Delete whitespace region
                    // 3. Insert target character (cursor auto-advances after insert)
                    return Some(Cmd::Macro(vec![
                        Cmd::Move(Movement::BackwardChar(ws_count as RepeatCount)),
                        Cmd::Replace(
                            Movement::ForwardChar(ws_count as RepeatCount),
                            Some(String::new()),
                        ),
                        Cmd::Insert(self.insert_char.clone()),
                    ]));
                }
            }
        }
        // No whitespace to clean: insert character normally
        Some(Cmd::Insert(self.insert_char.clone()))
    }
}

fn bind_smart_insert(editor: &mut Editor<SqlHelper, DefaultHistory>, key: char) {
    let event = KeyEvent::new(key, rustyline::Modifiers::NONE);
    let handler = SmartInsertHandler::new(key);
    let handler = EventHandler::Conditional(Box::new(handler));
    editor.bind_sequence(event, handler).ok();
}

fn main() {
    let config = Config::builder()
        .completion_type(CompletionType::List)
        .edit_mode(EditMode::Emacs)
        .auto_add_history(true)
        .build();

    let helper = SqlHelper;
    let mut editor = Editor::with_config(config);
    editor.set_helper(Some(helper));

    // Enable standard tab completion
    editor.bind_sequence(
        rustyline::KeyPress::Tab,
        EventHandler::Simple(Cmd::Complete),
    );

    // Fix cursor behavior for '.' and ','
    bind_smart_insert(&mut editor, '.');
    bind_smart_insert(&mut editor, ',');

    println!("SQL CLI Demo (rustyline cursor fix)");
    println!("Test cases:");
    println!("  1. Type 'SELECT bo<TAB>.' → becomes 'SELECT book.' (cursor AFTER dot)");
    println!("  2. Type 'author<TAB>,' → becomes 'author,' (cursor AFTER comma)");
    println!("  3. Type 'x   .' → becomes 'x.' (whitespace auto-removed)");
