type FlusterResult<T> = Result<T, FlusterError>;

/// Converts LanceDB ISO date string (with or without fractional seconds) to Unix timestamp in seconds
pub fn date_string_to_int(d: &str) -> FlusterResult<i64> {
    // Try parsing with fractional seconds first (requires dot + digits), then without
    let dt = NaiveDateTime::parse_from_str(d, "%Y-%m-%dT%H:%M:%S%.f")
