use std::io::{self, Write};
use std::time::{Duration, Instant};

/// Cleanup guard for terminal state
struct TerminalGuard;

impl Drop for TerminalGuard {
    fn drop(&mut self) {
        let _ = disable_raw_mode();
        let _ = execute!(io::stdout(), LeaveAlternateScreen);
    }
}

fn main() -> io::Result<()> {
    // Setup terminal
    enable_raw_mode()?;
    let mut stdout = io::stdout();
    execute!(stdout, EnterAlternateScreen, Clear(ClearType::All))?;
    let _guard = TerminalGuard; // Ensures cleanup on exit

    // Initial display
    writeln!(stdout, "TUI Event Loop Demo")?;
    writeln!(stdout, "====================")?;
    writeln!(stdout, "• UI updates every second (fixed tick)")?;
    writeln!(stdout, "• Input handled immediately")?;
    writeln!(stdout, "• Press 'q' to quit\n")?;
    stdout.flush()?;

    let mut last_tick = Instant::now();
    let tick_rate = Duration::from_secs(1);
    let mut tick_count = 0;

    loop {
        // Calculate time until next tick (clamped to 0 if overdue)
        let timeout = tick_rate.saturating_sub(last_tick.elapsed());

        // Non-blocking check for events with timeout
        if poll(timeout)? {
            // Handle input immediately when available
            if let Event::Key(key) = event::read()? {
                writeln!(stdout, "[INPUT] Key pressed: {:?}", key.code)?;

                if key.code == KeyCode::Char('q') {
                    writeln!(stdout, "\nQuitting application...")?;
                    break;
                }
            }
        } else {
            // Handle fixed-rate UI update (tick)
            tick_count += 1;
            let now = last_tick + tick_rate * tick_count;
            writeln!(
                stdout,
                "[TICK]  Update #{} | Simulated time: {}.{}",
                tick_count,
                now.as_secs() % 60,
                now.subsec_millis() / 100
            )?;
            last_tick = Instant::now();
        }

        // Always flush output to ensure immediate display
        stdout.flush()?;
    }

    // Final cleanup messages (guard will handle terminal state)
    writeln!(stdout, "\nTerminal restored. Goodbye!")?;
    stdout.flush()?;
    Ok(())
}"
}

