    _interactable: bool,
    _is_top_level: bool,
) -> bool {
    false
}

// ===== Core container handling macros =====
/// Macro to generate downcast branches for Vec<T> and Option<T> for multiple types
macro_rules! downcast_containers {
    ($value_mut:expr, $ui:expr, $title:expr, $interactable:expr, $($T:ty),*) => {
        $({
            if let Some(v) = $value_mut.downcast_mut::<Vec<$T>>() {
                list_property($ui, $title, v, $interactable);
                return;
            }
            if let Some(o) = $value_mut.downcast_mut::<Option<$T>>() {
                option_propery($ui, $title, o, $interactable);
                return;
            }
        })*
    };
}

// ===== Generic container property handlers =====
fn list_property<T>(ui: &mut Ui, title: &str, value_mut: &mut Vec<T>, interactable: bool)
where
    T: Default + Clone + 'static,
{
    egui::CollapsingHeader::new(title)
        .default_open(true)
        .enabled(interactable)
        .show(ui, |ui| {
            ui.horizontal_top(|ui| {
                if ui.button("➕ Add").clicked() {
                    value_mut.push(T::default());
                }
                ui.add_space(5.0);
                ui.label(format!("({} items)", value_mut.len()));
            });

            let mut remove_idx = None;
            for (i, item) in value_mut.iter_mut().enumerate() {
                ui.horizontal(|ui| {
                    downcast_property(ui, &format!("[{}]", i), item, interactable);
                    if ui.button("❌").on_hover_text("Remove").clicked() {
                        remove_idx = Some(i);
                    }
                });
            }
            if let Some(idx) = remove_idx {
                value_mut.remove(idx);
            }
        });
}

fn option_propery<T>(ui: &mut Ui, title: &str, value_mut: &mut Option<T>, interactable: bool)
where
    T: Default + Clone + 'static,
{
    let mut is_none = value_mut.is_none();

    ui.horizontal(|ui| {
        ui.label(title);
        ui.add_space(10.0);
        bool_property(ui, "None", &mut is_none, interactable);

        if is_none {
            *value_mut = None;
        } else {
            ui.add_space(5.0);
            if let Some(inner) = value_mut.as_mut() {
                downcast_property(ui, "", inner, interactable);
            } else {
                *value_mut = Some(T::default());
            }
        }
    });
}

// ===== Unified downcast dispatcher =====
fn downcast_property(ui: &mut Ui, title: &str, value_mut: &mut (dyn Any + 'static), interactable: bool) {
    // Handle base types first
    if let Some(v) = value_mut.downcast_mut::<String>() {
        string_property(ui, title, v, interactable);
        return;
    }
    if let Some(v) = value_mut.downcast_mut::<i32>() {
        i_property(ui, title, v, interactable);
        return;
    }
    if let Some(v) = value_mut.downcast_mut::<f32>() {
        f_property(ui, title, v, interactable);
        return;
    }
    if let Some(v) = value_mut.downcast_mut::<usize>() {
        i_property(ui, title, v, interactable);
        return;
    }
    if let Some(v) = value_mut.downcast_mut::<bool>() {
        bool_property(ui, title, v, interactable);
        return;
    }
    if downcast_all_enum_properties(value_mut, ui, title, interactable, true) {
        return;
    }
    if let Some(v) = value_mut.downcast_mut::<NamedTypeValue>() {
        namedvalue_property(ui, title, v, interactable);
        return;
    }
    if let Some(v) = value_mut.downcast_mut::<ArgumentNamedValue>() {
        argnamedvalue_property(ui, title, v, interactable);
        return;
    }

    // Handle ALL container types (Vec/Option) for supported inner types in one macro invocation
    downcast_containers!(
        value_mut,
        ui,
        title,
        interactable,
        String,
        i32,
        f32,
        bool,
        usize,
        DataType,
        ValueType,
        NamedTypeValue,
        ArgumentNamedValue
    );

    // Fallback for unknown types
    ui.label(
        RichText::new(format!("⚠️ Field '{}' has unsupported type", title))
            .color(Color32::LIGHT_RED)
            .italics(),
    );
}

// ===== Example application state =====
#[derive(Default, Clone)]
struct ExampleData {
    name: String,
    count: i32,
    ratio: f32,
    active: bool,
    tags: Vec<String>,
    scores: Vec<i32>,
    metadata: Option<NamedTypeValue>,
    nullable_id: Option<usize>,
    items: Vec<ArgumentNamedValue>,
}

// ===== Main application =====
struct DowncastApp {
    data: ExampleData,
}

impl DowncastApp {
    fn new() -> Self {
        Self {
            data: ExampleData {
                name: "Property Inspector".to_string(),
                count: 42,
                ratio: 3.14,
                active: true,
                tags: vec!["rust".to_string(), "egui".to_string()],
                scores: vec![95, 87, 100],
                metadata: Some(NamedTypeValue {
                    name: "version".to_string(),
                    value: 1,
                }),
                nullable_id: Some(7),
                items: vec![
                    ArgumentNamedValue { arg: "input".to_string() },
                    ArgumentNamedValue { arg: "output".to_string() },
                ],
            },
        }
    }
}

impl eframe::App for DowncastApp {
    fn update(&mut self, ctx: &Context, _frame: &mut eframe::Frame) {
        egui::CentralPanel::default().show(ctx, |ui| {
            ui.heading("Inspectable Properties");
            ui.add_space(10.0);

            egui::ScrollArea::vertical().show(ui, |ui| {
                // Dispatch each field through the unified downcaster
                downcast_property(ui, "Name", &mut self.data.name as &mut dyn Any, true);
                downcast_property(ui, "Count", &mut self.data.count as &mut dyn Any, true);
                downcast_property(ui, "Ratio", &mut self.data.ratio as &mut dyn Any, true);
                downcast_property(ui, "Active", &mut self.data.active as &mut dyn Any, true);
                downcast_property(ui, "Tags", &mut self.data.tags as &mut dyn Any, true);
                downcast_property(ui, "Scores", &mut self.data.scores as &mut dyn Any, true);
                downcast_property(ui, "Metadata", &mut self.data.metadata as &mut dyn Any, true);
                downcast_property(ui, "Nullable ID", &mut self.data.nullable_id as &mut dyn Any, true);
                downcast_property(ui, "Items", &mut self.data.items as &mut dyn Any, true);

                // Demonstrate unknown type handling
                let mut unknown: Vec<Vec<i32>> = vec![];
                downcast_property(ui, "Nested Vec (unsupported)", &mut unknown as &mut dyn Any, false);
            });

            ui.add_space(10.0);
            ui.label(
                RichText::new("✅ Container types (Vec/Option) handled generically!")
                    .color(Color32::LIGHT_GREEN)
                    .small(),
            );
        });
    }
}

fn main() {
    let native_options = eframe::NativeOptions {
        initial_window_size: Some(egui::vec2(500.0, 600.0)),
        ..Default::default()
    };

    eframe::run_native(
        "Downcast Container Example",
        native_options,
        Box::new(|_cc| Box::new(DowncastApp::new())),
    )
    .unwrap();
}"
}

