use signal_hook::iterator::Signals;
use termion::raw::IntoRawMode;

#[derive(Debug)]
enum Message {
    Quit,
    Signal(i32),
}

fn yield_signals(sender: Sender<Message>) {
    // Listen to termination signals + SIGUSR1 (our thread stop signal)
    let mut signals = Signals::new(&[
        libc::SIGINT,
        libc::SIGTERM,
        libc::SIGUSR1,
    ])
    .expect("Failed to create signal iterator");

    for sig in signals.forever() {
        if sig == libc::SIGUSR1 {
            // Internal stop signal - exit thread cleanly
            break;
        }
        // Forward other signals to main event loop
        if sender.send(Message::Signal(sig)).is_err() {
            break; // Channel closed, exit thread
        }
    }
}

fn yield_keys(sender: Sender<Message>, stop: Arc<AtomicBool>) {
