    let _raw_stdout = io::stdout()
        .into_raw_mode()
        .expect("Failed to set raw mode");

    // Enable non-blocking stdin reads
    let fd = libc::STDIN_FILENO;
    let orig_flags = unsafe { libc::fcntl(fd, libc::F_GETFL) };
    if orig_flags < 0 {
        eprintln!("Failed to get stdin flags");
        return;
    }

    if unsafe { libc::fcntl(fd, libc::F_SETFL, orig_flags | libc::O_NONBLOCK) } < 0 {
        eprintln!("Failed to set stdin non-blocking");
        return;
    }

    let mut stdin = io::stdin();
    let mut buf = [0u8; 1];

    loop {
        // Check shutdown flag FIRST to avoid unnecessary I/O
        if stop.load(Ordering::SeqCst) {
            break;
        }

        match stdin.read(&mut buf) {
            Ok(1) => {
                // Handle 'q' key to trigger graceful shutdown
                if buf[0] == b'q' {
                    let _ = sender.send(Message::Quit);
                }
                // Note: Real apps would parse full termion events here
            }
            Ok(0) => break, // EOF
            Err(e) => {
                if e.kind() == io::ErrorKind::WouldBlock {
                    thread::sleep(Duration::from_millis(10));
                } else {
                    eprintln!("Stdin read error: {}", e);
                    break;
                }
            }
        }
    }

    // Restore stdin blocking mode
    unsafe {
        libc::fcntl(fd, libc::F_SETFL, orig_flags);
    }
    // _raw_stdout drops here, restoring terminal mode
}

fn trigger_shutdown(stop_key: &Arc<AtomicBool>) {
    // Signal key thread to exit
    stop_key.store(true, Ordering::SeqCst);

    // Wake up signal thread by sending SIGUSR1
    unsafe {
        libc::kill(libc::getpid(), libc::SIGUSR1);
    }
}

fn main() {
    let (tx, rx) = mpsc::channel();
    let stop_key = Arc::new(AtomicBool::new(false));
    let stop_key_clone = Arc::clone(&stop_key);

    // Spawn signal handler thread
    let tx_sig = tx.clone();
    let signal_handle = thread::spawn(move || {
        yield_signals(tx_sig);
    });

    // Spawn keyboard handler thread
    let tx_key = tx.clone();
    let key_handle = thread::spawn(move || {
        yield_keys(tx_key, stop_key_clone);
    });

    println!("Event loop running. Press 'q' or send SIGINT (Ctrl+C) to quit.");

    // Main event loop
    for msg in rx {
        match msg {
            Message::Quit => {
                println!("\nQuit command received. Shutting down...");
                trigger_shutdown(&stop_key);
                break;
            }
            Message::Signal(sig) => {
                if sig == libc::SIGINT || sig == libc::SIGTERM {
                    println!("\nTermination signal received. Shutting down...");
                    trigger_shutdown(&stop_key);
                    break;
                }
            }
        }
    }

    // Close channel to prevent threads from blocking on send
    drop(tx);

    // Wait for worker threads to exit cleanly
    signal_handle.join().expect("Signal thread panicked");
    key_handle.join().expect("Key thread panicked");

    println!("Shutdown complete. Terminal restored.");
}
