/// Context holding global drag state
#[derive(Clone, Copy)]
struct DragContext {
    dragged_id: Signal<Option<usize>>,
    mouse_pos: Signal<ElementPoint>,
}

impl DragContext {
    fn new() -> Self {
        Self {
            dragged_id: Signal::new(None),
            mouse_pos: Signal::new(ElementPoint { x: 0.0, y: 0.0 }),
        }
    }
}

/// Provider component that tracks global drag state
#[component]
fn DragProvider(children: Element) -> Element {
    let drag_ctx = use_context_provider(|| DragContext::new());

    rsx! {
        div {
            id: "drag-area",
            width: "100%",
            height: "100vh",
            background_color: "#f0f0f0",
            // Only track mouse when dragging is active
            onmousemove: move |evt| {
                if drag_ctx.dragged_id.peek().is_some() {
                    drag_ctx.mouse_pos.set(evt.element_coordinates());
                }
            },
            onmouseup: move |_| {
                drag_ctx.dragged_id.set(None);
            },
            onmouseleave: move |_| {
                drag_ctx.dragged_id.set(None);
            },
            {children}
        }
    }
}

/// Draggable SVG point component
#[component]
fn Point(id: usize, x: f64, y: f64) -> Element {
    let mut position = use_signal(|| (x, y));
    let drag_ctx = use_context::<DragContext>();

    // Update position ONLY when this point is actively dragged
    // This effect runs ONLY when mouse_pos or dragged_id changes
    // Non-dragged points never subscribe to mouse_pos changes
    use_effect(use_reactive!(
        [drag_ctx.mouse_pos, drag_ctx.dragged_id],
        move || {
            if *drag_ctx.dragged_id.read() == Some(id) {
                let pos = drag_ctx.mouse_pos.read();
                position.set((pos.x, pos.y));
            }
        }
    ));

    rsx! {
        circle {
            cx: position.read().0,
            cy: position.read().1,
            r: 12.0,
            fill: match *drag_ctx.dragged_id.read() {
