        self.highlighter.highlight_char(line, pos)
    }
}

impl Validator for ReplHelper {
    fn validate(&self, ctx: &mut ValidationContext) -> rustyline::Result<ValidationResult> {
        let input = ctx.input();
        let mut balance = 0;

        // Simple validator: check for balanced curly braces
        // Returns Incomplete if braces are unbalanced, Valid otherwise
        for c in input.chars() {
            match c {
                '{' => balance += 1,
                '}' => {
                    balance -= 1;
                    if balance < 0 {
                        // Early exit on invalid state (more closers than openers)
                        return Ok(ValidationResult::Invalid(Some("Unmatched closing brace".into())));
                    }
                }
