  "main.rs": "use radiate::prelude::*;

fn main() {
    // Define custom unary operator: sqrt(|x|) + 1
    // Note: Takes absolute value to avoid NaN from negative inputs
    let sqrtplusone = Op::custom("sqrtplusone", |args| {
        if args.is_empty() {
            0.0
        } else {
            // Use first argument only (unary operation)
            // Handle negative values safely
            args[0].abs().sqrt() + 1.0
        }
    });

    // Build operator store:
    // - Vertex nodes: predefined binary ops + our custom unary op
    //   (custom op will use first child's value, ignore others in binary context)
    // - Leaf nodes: input variable and constants
    let store = vec![
        (
            NodeType::Vertex,
            vec![
                Op::add(),
                Op::mul(),
                sqrtplusone, // Our custom operator
                Op::sub(),
            ],
        ),
        (
            NodeType::Leaf,
            vec![
                Op::var(0),      // Input variable x₀
                Op::constant(1.0),
                Op::constant(2.0),
                Op::constant(3.0),
            ],
        ),
    ];

    // Create population with single individual for demonstration
    // Min depth=2, Max depth=4 ensures non-trivial tree structure
    let mut population = Population::new(&store, 1, 2, 4);
    let tree = &population.individuals[0].program;

    // Test evaluation with sample input [x₀ = 9.0]
    let input = [9.0];
    let result = tree.evaluate(&input);

    // Output results
    println!("=".repeat(60));
    println!("Custom Operator Example: sqrtplusone(x) = sqrt(|x|) + 1");
    println!("=".repeat(60));
    println!("\nGenerated Tree Structure:");
    println!("{:#?}", tree);
    println!("\nEvaluation Details:");
