use std::marker::PhantomData;

// Minimal Meta definition matching original usage
pub struct Meta {
    pub name: Option<String>,
}

// Resource trait as implied by original code
pub trait Resource {
    type DynamicType: Default;
    fn meta(&self) -> Meta;
    fn group(dynamic_type: &Self::DynamicType) -> Cow<str>;
    fn kind(dynamic_type: &Self::DynamicType) -> Cow<str>;
}

// FIXED: Removed lifetime parameter and store owned strings
// This avoids borrowing from local `dynamic_type` while maintaining zero-copy
// for static strings (via into_owned() which is cheap for &'static str)
#[derive(Debug, Clone)]
pub struct ResourceRef<R: Resource>
where
    R::DynamicType: Default,
{
    type_: PhantomData<R>,
    dynamic_type: R::DynamicType,
    group: Option<String>,
    kind: String,
    name: String,
}

impl<R: Resource> ResourceRef<R>
where
    R::DynamicType: Default,
{
    pub fn new(resource: R) -> Self {
        let name = resource
            .meta()
            .name
            .as_deref()
            .expect("Resource must have a name");
        Self::new_named(name)
    }

    pub fn new_named(name: &str) -> Self {
        let dynamic_type = R::DynamicType::default();
        // Convert Cows to owned strings immediately
        // This is safe: no references to local `dynamic_type` escape
        let group_cow = R::group(&dynamic_type);
        let kind_cow = R::kind(&dynamic_type);

        let group = if group_cow.is_empty() {
            None
        } else {
            Some(group_cow.into_owned())
        };
        let kind = kind_cow.into_owned();

        Self {
            type_: PhantomData,
            dynamic_type,
            group,
            kind,
            name: name.to_string(),
        }
    }

    pub fn group(&self) -> Option<&str> {
        self.group.as_deref()
    }

    pub fn kind(&self) -> &str {
        &self.kind
    }

    pub fn name(&self) -> &str {
        &self.name
    }
}

