pub struct TestResource {
    name: String,
}

impl Resource for TestResource {
    type DynamicType = ();

    fn meta(&self) -> Meta {
        Meta {
            name: Some(self.name.clone()),
        }
    }

    // Returns borrowed static strings (common real-world case)
    fn group(_dt: &()) -> Cow<str> {
        Cow::Borrowed("apps")
    }

    fn kind(_dt: &()) -> Cow<str> {
        Cow::Borrowed("deployments")
    }
}

