#[derive(Debug, Clone, Default)]
pub struct DynamicResource {
    name: String,
    group_val: String,
    kind_val: String,
}

impl Resource for DynamicResource {
    type DynamicType = (String, String); // Simulates dynamic data

    fn meta(&self) -> Meta {
        Meta {
            name: Some(self.name.clone()),
        }
    }

    fn group(dt: &Self::DynamicType) -> Cow<str> {
        Cow::Borrowed(&dt.0)
    }

    fn kind(dt: &Self::DynamicType) -> Cow<str> {
        Cow::Borrowed(&dt.1)
    }
}

fn main() {
    println!("=== Test 1: Static strings (zero alloc for group/kind) ===");
    let res1 = TestResource {
        name: "nginx".to_string(),
    };
    let ref1 = ResourceRef::new(res1);
    println!("Group: {:?}", ref1.group());
    println!("Kind: {}", ref1.kind());
    println!("Name: {}", ref1.name());

    println!("\n=== Test 2: new_named constructor ===");
    let ref2 = ResourceRef::<TestResource>::new_named("redis");
    println!("Group: {:?}", ref2.group());
    println!("Kind: {}", ref2.kind());
    println!("Name: {}", ref2.name());

    println!("\n=== Test 3: Dynamic strings (owned conversion) ===");
    let res3 = DynamicResource {
        name: "custom-app".to_string(),
        group_val: "custom-group".to_string(),
        kind_val: "custom-kind".to_string(),
    };
    let ref3 = ResourceRef::new(res3);
    println!("Group: {:?}", ref3.group());
    println!("Kind: {}", ref3.kind());
    println!("Name: {}", ref3.name());

    println!("\n✅ All tests completed successfully!");
    println!("💡 Key insight: Converting Cow to owned String at construction");
    println!("   avoids lifetime issues while keeping API clean.");
    println!("   For &'static str inputs, into_owned() is very cheap.");
}"
}

