  "main.rs": "fn tokenize(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current = String::new();
    let mut in_single_quote = false;

    for c in input.chars() {
        if in_single_quote {
            if c == '\'' {
                in_single_quote = false;
            } else {
                current.push(c);
            }
        } else {
            match c {
                '\'' => in_single_quote = true,
                c if c.is_whitespace() => {
                    if !current.is_empty() {
                        tokens.push(current.clone());
                        current.clear();
                    }
                }
                _ => current.push(c),
            }
        }
    }

    if !current.is_empty() {
        tokens.push(current);
    }

    tokens
}

fn main() {
    let input = " one  ' two  'three    four";
    let tokens = tokenize(input);
    println!("{} args:", tokens.len());
    for token in tokens {
        println!("<{}>", token);
    }
}"
}

