  "main.rs": "use tokio::signal;
use tokio::time::Duration;
use tokio_stream::{StreamExt, wrappers::BroadcastStream};
use tokio::sync::broadcast;

#[derive(Debug, Clone)]
pub struct Event {
    pub data: String,
}

#[derive(Debug)]
pub struct RecvError;

pub fn events_channel() -> (EventSender, EventStreamFactory) {
    let (tx, _) = broadcast::channel(20);
    (EventSender { tx: tx.clone() }, EventStreamFactory { tx })
}

#[derive(Debug, Clone)]
pub struct EventSender {
    tx: broadcast::Sender<Event>,
}

impl EventSender {
    /// Returns error if channel is closed or full
    pub fn send(&self, event: Event) -> Result<(), broadcast::error::SendError<Event>> {
        self.tx.send(event)
    }
}

pub struct EventStreamFactory {
    tx: broadcast::Sender<Event>,
}

impl EventStreamFactory {
    /// Creates a stream of events. Stream terminates on channel closure.
    pub fn all_events(&self) -> impl StreamExt<Item = Result<Event, RecvError>> + Send + 'static {
        BroadcastStream::new(self.tx.subscribe()).filter_map(|res| {
            match res {
                Ok(event) => Some(Ok(event)),
                // Convert all broadcast errors to our RecvError
                // Stream consumer should terminate on any error (including Closed)
                Err(_) => Some(Err(RecvError)),
            }
        })
    }

    /// Closes the broadcast channel. All active receivers will eventually
    /// receive RecvError after buffer exhaustion. Senders will fail immediately.
    pub fn close(&self) {
        self.tx.close();
    }
}

#[tokio::main]
async fn main() {
    let (event_sender, factory) = events_channel();

    // Spawn sender task
    let sender_handle = tokio::spawn({
        let sender = event_sender.clone();
        async move {
            let mut interval = tokio::time::interval(Duration::from_secs(1));
            let mut count = 0;
            loop {
                interval.tick().await;
                count += 1;
                let event = Event {
                    data: format!("Event #{}", count),
                };

                // Stop sender if channel is closed
                if sender.send(event).is_err() {
                    eprintln!("[Sender] Channel closed, terminating");
                    break;
                }
            }
        }
    });

    // Spawn receiver task
    let receiver_handle = tokio::spawn({
        let mut stream = factory.all_events();
        async move {
            while let Some(result) = stream.next().await {
                match result {
                    Ok(event) => println!("[Receiver] {}", event.data),
                    Err(_) => {
                        eprintln!("[Receiver] Stream terminated (channel closed)");
                        break;
                    }
                }
            }
        }
    });

    // Wait for shutdown signal
    println!("Service running. Press Ctrl+C to shutdown...");
    signal::ctrl_c()
        .await
        .expect("Failed to listen for Ctrl+C");

    println!("\n⚠️  Shutdown signal received. Closing broadcast channel...");
    factory.close();

    // Wait for tasks to clean up
    let _ = sender_handle.await;
    let _ = receiver_handle.await;

    println!("✅ Shutdown complete");
}
"
}

