    (|$ctx:ident| $body:block) => {
        Box::new(move |$ctx: &mut Context| {
            Box::pin(async move { $body })
        })
    };
}

/// Helper to send async workload to worker thread
/// Takes pre-wrapped closure matching InnerAsyncEvent's requirements
pub fn with_context_async(
    sender: &mut mpsc::Sender<InnerAsyncEvent>,
    block: Box<
        dyn for<'a> Fn(&'a mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
            + Send,
    >,
) {
    let _ = sender.send(InnerAsyncEvent::DoWithContext { block });
}

