use nix::fcntl::{fcntl, FcntlArg, OFlag};
use nix::pty::{openpty, Winsize};
use nix::sys::termios::{tcgetattr, tcsetattr, SetArg, Termios};
use nix::unistd::{close, dup2, execvp, fork, setsid, ForkResult, Pid};
use serde::{Deserialize, Serialize};
use std::fs::File;
use std::io::{ErrorKind, Read, Write};
use std::os::unix::io::{AsRawFd, FromRawFd, RawFd};
use std::sync::mpsc::{channel, Receiver, Sender};
use std::sync::{Arc, Mutex};
use std::thread;
use std::time::Duration;
use tauri::{Emitter, Manager, State};

#[derive(Debug, thiserror::Error)]
enum AgentError {
    #[error("PTY setup failed: {0}")]
    PtySetup(String),
    #[error("Process spawn failed: {0}")]
    Spawn(String),
    #[error("I/O error: {0}")]
    Io(String),
}

#[derive(Clone, Serialize)]
struct OutputEvent {
    data: String,
}

#[derive(Clone, Serialize)]
struct StatusEvent {
    status: String, // "started", "exited"
}

struct AgentHandle {
    write_tx: Sender<Vec<u8>>,
    pid: Pid,
}

struct AppState {
    agent: Arc<Mutex<Option<AgentHandle>>>,
}

impl AppState {
    fn new() -> Self {
        Self {
            agent: Arc::new(Mutex::new(None)),
        }
    }
}

fn set_nonblocking(fd: RawFd) -> Result<(), AgentError> {
    let flags = fcntl(fd, FcntlArg::F_GETFL).map_err(|e| AgentError::Io(e.to_string()))?;
    let new_flags = OFlag::from_bits_truncate(flags) | OFlag::O_NONBLOCK;
    fcntl(fd, FcntlArg::F_SETFL(new_flags))
        .map_err(|e| AgentError::Io(e.to_string()))?;
    Ok(())
}

fn spawn_agent(
    cmd: &str,
    args: &[&str],
    write_tx: Sender<Vec<u8>>,
    app_handle: tauri::AppHandle,
) -> Result<Pid, AgentError> {
    let pty = openpty(
        None,
        Some(Winsize {
            ws_row: 24,
            ws_col: 80,
            ws_xpixel: 0,
            ws_ypixel: 0,
        }),
    )
    .map_err(|e| AgentError::PtySetup(e.to_string()))?;

    // Configure terminal attributes for raw-ish mode
    if let Ok(mut termios) = tcgetattr(pty.slave) {
        // Minimal setup for interactive use
        termios.input_flags &= !(nix::sys::termios::InputFlags::IGNBRK
            | nix::sys::termios::InputFlags::BRKINT
            | nix::sys::termios::InputFlags::PARMRK
            | nix::sys::termios::InputFlags::ISTRIP
            | nix::sys::termios::InputFlags::INLCR
            | nix::sys::termios::InputFlags::IGNCR
            | nix::sys::termios::InputFlags::ICRNL
            | nix::sys::termios::InputFlags::IXON);
        termios.output_flags &= !nix::sys::termios::OutputFlags::OPOST;
        termios.control_flags |= nix::sys::termios::ControlFlags::CS8;
        termios.local_flags &= !(nix::sys::termios::LocalFlags::ECHO
            | nix::sys::termios::LocalFlags::ECHONL
            | nix::sys::termios::LocalFlags::ICANON
            | nix::sys::termios::LocalFlags::ISIG
            | nix::sys::termios::LocalFlags::IEXTEN);
        termios.control_chars[nix::sys::termios::SpecialCharacterIndices::VMIN as usize] = 1;
        termios.control_chars[nix::sys::termios::SpecialCharacterIndices::VTIME as usize] = 0;
        let _ = tcsetattr(pty.slave, SetArg::TCSANOW, &termios);
    }

    match unsafe { fork() } {
        Ok(ForkResult::Parent { child }) => {
            // Parent process
            close(pty.slave).map_err(|e| AgentError::PtySetup(e.to_string()))?;

            // Convert master FD to owned File
            let master_file = unsafe { File::from_raw_fd(pty.master) };
            set_nonblocking(master_file.as_raw_fd())?;

            // Spawn I/O thread
            thread::spawn(move || {
                let app_handle = app_handle.clone();
                let mut master = master_file;
                let mut write_buf = Vec::new();
                let mut exited = false;

                // Notify frontend that agent started
                let _ = app_handle.emit("agent-status", StatusEvent {
                    status: "started".into(),
                });

                while !exited {
                    // Process pending writes
                    while let Ok(data) = write_tx.try_recv() {
                        write_buf.extend_from_slice(&data);
                    }

                    if !write_buf.is_empty() {
                        match master.write(&write_buf) {
                            Ok(n) => {
                                write_buf.drain(..n);
                            }
                            Err(e) if e.kind() == ErrorKind::WouldBlock => {
                                // Buffer full, retry next iteration
                            }
                            Err(e) => {
                                eprintln!("[PTY Write Error] {}", e);
                                break;
                            }
                        }
                    }

                    // Read available output
                    let mut read_buf = [0u8; 4096];
                    match master.read(&mut read_buf) {
                        Ok(0) => {
                            exited = true; // EOF - process exited
                        }
                        Ok(n) => {
                            let output = String::from_utf8_lossy(&read_buf[..n]).to_string();
                            let _ = app_handle.emit("agent-output", OutputEvent { data: output });
                        }
                        Err(e) if e.kind() == ErrorKind::WouldBlock => {
                            // No data available yet
                        }
                        Err(e) => {
                            eprintln!("[PTY Read Error] {}", e);
                            exited = true;
                        }
                    }

                    thread::sleep(Duration::from_millis(5));
                }

                // Notify frontend of exit
                let _ = app_handle.emit("agent-status", StatusEvent {
                    status: "exited".into(),
                });
                close(master.as_raw_fd()).ok();
            });

            Ok(child)
        }
        Ok(ForkResult::Child) => {
            // Child process
            close(pty.master).ok();

            // Set slave as stdin/stdout/stderr
            dup2(pty.slave, libc::STDIN_FILENO).ok();
            dup2(pty.slave, libc::STDOUT_FILENO).ok();
            dup2(pty.slave, libc::STDERR_FILENO).ok();

            if pty.slave > libc::STDERR_FILENO {
                close(pty.slave).ok();
            }

            // Create new session
            let _ = setsid();

            // Execute command
            let c_args: Vec<std::ffi::CString> = std::iter::once(std::ffi::CString::new(cmd).unwrap())
                .chain(args.iter().map(|s| std::ffi::CString::new(*s).unwrap()))
                .collect();
            let c_strs: Vec<_> = c_args.iter().map(|s| s.as_c_str()).collect();

            execvp(c_strs[0], &c_strs).ok();
            std::process::exit(1);
        }
        Err(e) => Err(AgentError::Spawn(e.to_string())),
    }
}

#[tauri::command]
fn start_agent(state: State<AppState>, app_handle: tauri::AppHandle) -> Result<(), String> {
    // Example: spawn bash (replace with your agent path)
    let (write_tx, write_rx) = channel();

    match spawn_agent("/bin/bash", &["-i"], write_tx, app_handle.clone()) {
        Ok(pid) => {
            *state.agent.lock().unwrap() = Some(AgentHandle {
                write_tx,
                pid,
            });
            Ok(())
        }
        Err(e) => {
            let _ = app_handle.emit("agent-status", StatusEvent {
                status: format!("error: {}", e),
            });
            Err(e.to_string())
        }
    }
}

#[tauri::command]
fn send_to_agent(
    state: State<AppState>,
    data: String,
) -> Result<(), String> {
    let agent_opt = state.agent.lock().unwrap();
    if let Some(agent) = agent_opt.as_ref() {
        // Convert to bytes (preserve control sequences from xterm.js)
        agent.write_tx.send(data.into_bytes()).map_err(|e| e.to_string())?;
        Ok(())
    } else {
        Err("No active agent session".into())
    }
}

#[tauri::command]
fn stop_agent(state: State<AppState>) -> Result<(), String> {
    let mut guard = state.agent.lock().unwrap();
    if let Some(agent) = guard.take() {
        // Send EOF (Ctrl+D) to gracefully terminate
        let _ = agent.write_tx.send(vec![0x04]);
        // Note: For forceful termination, use nix::sys::signal::kill
        Ok(())
    } else {
        Err("No active agent session".into())
    }
}

fn main() {
    tauri::Builder::default()
        .manage(AppState::new())
        .invoke_handler(tauri::generate_handler![
            start_agent,
            send_to_agent,
            stop_agent
        ])
        .setup(|app| {
            // Frontend would call start_agent on mount
            // and handle "agent-output"/"agent-status" events
            Ok(())
        })
        .run(tauri::generate_context!())
        .expect("error while running tauri application");
}"
}

