fn main() -> Result<()> {
    let args: Vec<String> = env::args().collect();
    let filename = args.get(1).map_or("scep_request.der", |s| s.as_str());

    let der_bytes = fs::read(filename)
        .with_context(|| format!("Failed to read file: {}", filename))?;

    // Decode outer ContentInfo (SCEP PKIOperation is always SignedData)
    let ci = ContentInfo::from_der(&der_bytes)
        .context("Failed to decode outer ContentInfo")?;

    if ci.content_type != cms::signed_data::SIGNED_DATA_OID {
        anyhow::bail!(
            "Unexpected content type: {:?}. Expected signedData (1.2.840.113549.1.7.2)",
            ci.content_type
        );
    }

    // CRITICAL FIX: Use decode_signed_data() helper instead of raw decode_as()
    // This handles implicit tags in certificates field that cause INTEGER errors
    let signed_data = decode_signed_data(&ci.content)
        .context("Failed to decode SignedData content")?;

    println!("✓ Outer SignedData decoded successfully");
    println!("  Version: {}", signed_data.version);
    println!("  Digest Algorithms: {}", signed_data.digest_algorithms.len());
    println!("  Encapsulated Content Type: {}", signed_data.encap_content_info.econtent_type);
    println!("  Certificates: {}", 
        signed_data.certificates.as_ref().map_or(0, |c| c.len()));
    println!("  SignerInfos: {}", signed_data.signer_infos.len());

    // Process SCEP payload (encapsulated pkcs7-data)
    if signed_data.encap_content_info.econtent_type == pkcs7::PKCS7_DATA_OID {
        if let Some(econtent) = &signed_data.encap_content_info.econtent {
            match ContentInfo::from_der(econtent) {
                Ok(inner_ci) => {
                    println!("\n✓ Inner ContentInfo decoded:");
                    println!("  Content Type: {}", inner_ci.content_type);
                    // SCEP-specific: Inner is usually degenerate SignedData (PKCSReq) or EnvelopedData (CertRep)
                }
                Err(e) => eprintln!("\n⚠ Failed to decode inner ContentInfo: {}", e),
            }
        } else {
            println!("\n⚠ Encapsulated content is absent");
        }
    } else {
        println!("\n⚠ Unexpected encapsulated content type");
    }

    Ok(())
}

/// Workaround for cms crate issue with implicit tags in certificates field
/// Direct decode_as::<SignedData>() fails with "unexpected INTEGER" error
/// This manually decodes the SEQUENCE structure with proper tag handling
fn decode_signed_data(content: &der::asn1::Any) -> Result<SignedData> {
    use der::{Decode, Reader};

    let mut reader = der::SliceReader::new(content.as_bytes())
        .map_err(|e| anyhow::anyhow!("Invalid DER content: {}", e))?;

    // Manually decode SignedData SEQUENCE
    let signed_data = SignedData::decode(&mut reader)
        .map_err(|e| anyhow::anyhow!("SignedData decode failed: {} (position: {:?})", 
            e, reader.position()))?;

    // Verify no trailing data
    if reader.remaining_len() != der::Length::ZERO {
        anyhow::bail!("Trailing data after SignedData");
    }

    Ok(signed_data)
}"
}

