fn try_poll<F>(mut future: F) -> TryPollResult<F::Output, F>
where
    F: Future + Unpin,
{
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);
    match Pin::new(&mut future).poll(&mut cx) {
        Poll::Ready(output) => TryPollResult::Ready(output),
        Poll::Pending => TryPollResult::Pending(future),
    }
}

#[tokio::main]
async fn main() {
    println!("=== Test 1: Immediately ready future ===");
    let fut1 = ready(42);
    match try_poll(fut1) {
        TryPollResult::Ready(value) => println!("✅ Got value synchronously: {}", value),
        TryPollResult::Pending(_) => println!("❌ Unexpected pending state"),
    }

    println!("\n=== Test 2: Future pending on first poll ===");
    // Create a future that returns Pending on first poll, Ready on second
    let count = Arc::new(AtomicUsize::new(0));
    let count_clone = count.clone();
    let future = poll_fn(move |_cx| {
        let current = count_clone.fetch_add(1, Ordering::SeqCst);
        if current == 0 {
            Poll::Pending
        } else {
            Poll::Ready(100)
        }
    });

    match try_poll(future) {
        TryPollResult::Ready(value) => println!("❌ Unexpected immediate ready: {}", value),
        TryPollResult::Pending(fut) => {
            println!("⏳ Future pending after first poll - spawning task");
            tokio::spawn(async move {
                let value = fut.await;
                println!("✅ Spawned task got value after await: {}", value);
            });
        }
    }

    // Allow spawned task time to complete
    tokio::time::sleep(tokio::time::Duration::from_millis(50)).await;
    println!("\n✅ Main completed successfully");
}"
