/// Handler that deletes trailing whitespace before cursor and inserts the key,
/// leaving cursor positioned AFTER the inserted character.
struct SmartInsertHandler {
    key: char,
}

impl SmartInsertHandler {
    fn new(key: char) -> Self {
        SmartInsertHandler { key }
    }
