impl ConditionalEventHandler for SmartInsertHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();
        let before_cursor = &line[..pos];

        // Count consecutive whitespace characters at the end of the substring before cursor
        let trailing_ws_count = before_cursor
            .chars()
            .rev()
            .take_while(|c| c.is_whitespace())
            .count();

        if trailing_ws_count > 0 {
            // Delete trailing whitespace THEN insert key (cursor ends after inserted char)
