use tokio::sync::OnceCell;

/// Simplified config for demonstration (no Docker)
#[derive(Debug, Clone)]
struct DbConfig {
    port: u16,
    postgres_password: String,
}

/// Demonstrates safe client caching for default database
struct DbContainer {
    db_config: DbConfig,
    // Caches CLIENT (not connection task) for default 'postgres' database
    // Connection stays alive because:
    // 1. Stored Client is never dropped until DbContainer drops
    // 2. Each usage clones the Client handle (cheap atomic refcount)
    // 3. Connection task remains alive while any Client clone exists
    default_client: OnceCell<Client>,
}

impl DbContainer {
    fn new(db_config: DbConfig) -> Self {
        Self {
            db_config,
            default_client: OnceCell::const_new(),
        }
    }

    /// Connect to database:
    /// - None: Returns CLONE of cached default database client (postgres)
    /// - Some(name): Returns new client for target DB (not cached)
    async fn connect(&self, db_name: Option<&str>) -> Result<Client, tokio_postgres::Error> {
        if let Some(dbname) = db_name {
            // Non-default DB: fresh connection (not cached)
            let conn_str = format!(
                "host=localhost port={} user=postgres password={} dbname={}",
                self.db_config.port,
                self.db_config.postgres_password,
                dbname
            );
            let (client, conn) = tokio_postgres::connect(&conn_str, NoTls).await?;

            // Critical: Spawn connection task to drive protocol
            tokio::spawn(async move {
                if let Err(e) = conn.await {
                    eprintln!("[NON-DEFAULT DB] Connection error: {}", e);
                }
            });
            Ok(client)
        } else {
            // Default DB (postgres): Initialize cache ONCE, then clone handle
            let client = self
                .default_client
                .get_or_init(|| async {
                    let conn_str = format!(
                        "host=localhost port={} user=postgres password={} dbname=postgres",
                        self.db_config.port,
                        self.db_config.postgres_password
                    );
                    let (client, conn) = tokio_postgres::connect(&conn_str, NoTls)
                        .await
                        .expect("Failed to connect to default 'postgres' database");

                    // Spawn connection task - kept alive by cached Client + clones
                    tokio::spawn(async move {
                        if let Err(e) = conn.await {
                            eprintln!("[DEFAULT DB] Connection error: {}", e);
                        }
                    });
                    client // Stored in OnceCell
                })
                .await;

            // Return CLONE of cached client (not reference!)
            // This is safe: Client is Sync + cheap to clone (channel handle)
            Ok(client.clone())
        }
    }

    async fn create_database(&self, name: &str) -> Result<(), tokio_postgres::Error> {
        let client = self.connect(None).await?; // Uses cached client clone
