/// Thread for signal handling with graceful shutdown
fn yield_signals(sender: Sender<Message>, stop_flag: Arc<AtomicBool>) {
    let mut signals = Signals::new(&[SIGINT, SIGTERM]).expect("Failed to create signal iterator");

    loop {
        if stop_flag.load(Ordering::Relaxed) {
            break;
        }

        // Process all pending signals without blocking
        for sig in signals.pending() {
            if sender.send(Message::Signal(sig)).is_err() {
                break;
            }
