        }

        match stdin.read(&mut buffer) {
            Ok(1) => {
                // Handle 'q' for clean quit
                if buffer[0] == b'q' {
                    let _ = sender.send(Message::Quit);
                    break;
                }
                // Convert printable ASCII to char
                if buffer[0].is_ascii_alphanumeric() || buffer[0] == b' ' {
                    let _ = sender.send(Message::Key(buffer[0] as char));
                }
            }
            Ok(0) => break, // EOF
            Err(e) if e.kind() == io::ErrorKind::WouldBlock => {
                thread::sleep(Duration::from_millis(10));
                continue;
            }
            Err(_) => break,
        }
    }

    // Explicitly drop to restore terminal state before thread exit
    drop(stdout);
}

