            Message::Quit => {
                println!("\n[MAIN] Quit command received. Initiating shutdown...");
                break;
            }
        }
    }

    // Signal all threads to stop
    stop_flag.store(true, Ordering::Relaxed);

    // Clean up threads
    signal_thread.join().expect("Signal thread panicked");
    key_thread.join().expect("Key thread panicked");

    // Final terminal cleanup
    write!(io::stdout(), "{}{}", termion::cursor::Show, termion::clear::AfterCursor).unwrap();
    println!("\n✅ All threads stopped gracefully. Program exited cleanly.");
}
