name = "async_trait_example"
version = "0.1.0"
edition = "2021"

[dependencies]
async-trait = "0.1"
tokio = { version = "1", features = ["full"] }
anyhow = "1.0"",
  "main.rs": "use async_trait::async_trait;
use std::path::Path;
use anyhow::{Result, anyhow};
use std::time::Duration;

#[async_trait]
pub trait RemoteActions {
    async fn change_path(&mut self, from: &Path, to: &Path) -> Result<()>;
    async fn remove_repo(&mut self, path: &Path) -> Result<()>;
    async fn add_repo(&mut self, path: &Path) -> Result<()>;
    fn get_element(&self, num: usize) -> Result<String>;
}

#[derive(Debug)]
struct ProductionRemote {
    elements: Vec<String>,
}

impl ProductionRemote {
    fn new() -> Self {
        ProductionRemote {
            elements: vec!["prod_repo".to_string(), "backup_repo".to_string()],
        }
    }
}

#[async_trait]
impl RemoteActions for ProductionRemote {
    async fn change_path(&mut self, from: &Path, to: &Path) -> Result<()> {
        println!("[PROD] Moving {:?} -> {:?}", from, to);
        tokio::time::sleep(Duration::from_millis(50)).await;
        Ok(())
    }

    async fn remove_repo(&mut self, path: &Path) -> Result<()> {
        println!("[PROD] Deleting {:?}", path);
        tokio::time::sleep(Duration::from_millis(50)).await;
        Ok(())
    }

    async fn add_repo(&mut self, path: &Path) -> Result<()> {
        println!("[PROD] Cloning to {:?}", path);
        tokio::time::sleep(Duration::from_millis(50)).await;
        Ok(())
    }

    fn get_element(&self, num: usize) -> Result<String> {
        self.elements.get(num)
            .cloned()
            .ok_or_else(|| anyhow!("Invalid index {}", num))
    }
}

#[derive(Debug)]
struct TestRemote {
    elements: Vec<String>,
}

impl TestRemote {
    fn new() -> Self {
        TestRemote {
            elements: vec!["mock_item_0".to_string(), "mock_item_1".to_string()],
        }
    }
}

#[async_trait]
impl RemoteActions for TestRemote {
    async fn change_path(&mut self, _from: &Path, _to: &Path) -> Result<()> {
        // Noop for tests
        Ok(())
    }

    async fn remove_repo(&mut self, _path: &Path) -> Result<()> {
        Ok(())
    }

    async fn add_repo(&mut self, _path: &Path) -> Result<()> {
        Ok(())
    }

    fn get_element(&self, num: usize) -> Result<String> {
        self.elements.get(num)
            .cloned()
            .ok_or_else(|| anyhow!("Test index error: {}", num))
    }
}

#[tokio::main]
async fn main() -> Result<()> {
    println!("=== Production Strategy ===");
    let mut prod: Box<dyn RemoteActions> = Box::new(ProductionRemote::new());
    prod.add_repo(Path::new("/repos/main")).await?;
    prod.change_path(Path::new("/repos/old"), Path::new("/repos/new")).await?;
    println!("Repo name: {}\n", prod.get_element(0)?);

    println!("=== Test Strategy (Noop) ===");
    let mut test: Box<dyn RemoteActions> = Box::new(TestRemote::new());
    test.add_repo(Path::new("/test/repo")).await?; // Silent
    test.remove_repo(Path::new("/garbage")).await?; // Silent
    println!("Mock value: {}", test.get_element(1)?);

    println!("\n✅ Trait is dyn-compatible and strategies interchangeable!");
    Ok(())
}"
}

