  "Cargo.toml": "[package]
name = "nested_parallel_example"
version = "0.1.0"
edition = "2021"

[dependencies]
rayon = "1.8"",
  "main.rs": "use rayon::prelude::*;

fn main() {
    // Example nested vector with varying inner sizes
    let a: Vec<Vec<usize>> = vec![
        vec![10, 20, 30],
        vec![40],
        vec![50, 60, 70, 80],
        vec![],
        vec![90, 100],
    ];

    // Apply function in parallel while preserving structure
    // Using nested parallel iteration: outer vector parallelized first,
    // then each inner vector processed in parallel
    let result: Vec<Vec<String>> = a
        .par_iter()
        .map(|inner| {
            inner
                .par_iter()
                .map(|&x| format!("processed_{}", x)) // Example transformation
                .collect()
        })
        .collect();

    // Verify structure preservation and output
    println!("Original structure:");
    for (i, inner) in a.iter().enumerate() {
        println!("  [{}]: {:?}", i, inner);
    }

    println!("\nProcessed result:");
    for (i, inner) in result.iter().enumerate() {
        println!("  [{}]: {:?}", i, inner);
    }

    // Validation: Check structure matches original
    assert_eq!(a.len(), result.len(), "Outer vector length mismatch");
    for (i, (orig, proc)) in a.iter().zip(result.iter()).enumerate() {
        assert_eq!(orig.len(), proc.len(), "Inner vector length mismatch at index {}", i);
    }
    println!("\n✓ Structure preserved successfully!");
}"
}

