    println!("- Each call returned the PRE-increment value");
    println!("- Values incremented sequentially: 0 -> 1 -> 2");
    println!("- Relaxed ordering is CORRECT inside critical section:");
    println!("  * Critical section provides atomicity barrier");
    println!("  * No cross-core/interrupt interference possible");
    println!("  * Stronger ordering would add unnecessary overhead");
