use rxrust::scheduler::LocalScheduler;
use std::cell::RefCell;
use std::convert::Infallible;
use std::rc::Rc;

type ObservableBool = LocalBoxedObservableClone<'static, bool, Infallible>;

type Scheduler = Rc<RefCell<LocalScheduler>>;

fn nand(name: String, a: ObservableBool, b: ObservableBool) -> ObservableBool {
    a.combine_latest(b, move |x, y| (x, y))
        .distinct()
        .tap(move |(x, y)| print!("nand {name} ({x}, {y})"))
        .map(|(x, y)| !(x && y))
        .tap(|v| println!(" = {v}"))
        .box_it_clone()
}

fn flipflop(
    scheduler: Scheduler,
    s: ObservableBool,
    r: ObservableBool,
) -> (
    ObservableBool,
    ObservableBool,
    Vec<LocalSubscription<Infallible>>,
) {
    // Stable initial state: Q=1 (r2), Q'=0 (s2)
    let s2 = Local::behavior_subject::<bool, Infallible>(false); // Q' initial = 0
    let r2 = Local::behavior_subject::<bool, Infallible>(true);  // Q initial = 1

    let s2_obs = s2.clone().box_it_clone();
    let r2_obs = r2.clone().box_it_clone();

    let q1 = nand("S".into(), s, s2_obs).box_it_clone(); // Output Q
    let q2 = nand("R".into(), r, r2_obs).box_it_clone(); // Output Q'

    // Defer feedback updates to avoid RefCell borrow conflicts
    let sub1 = q1
        .clone()
        .observe_on(scheduler.clone())
        .subscribe(move |v| {
            r2.next(v);
        });

    let sub2 = q2
        .clone()
        .observe_on(scheduler.clone())
        .subscribe(move |v| {
            s2.next(v);
        });

    (q1, q2, vec![sub1, sub2])
}

fn main() {
    let scheduler = Rc::new(RefCell::new(LocalScheduler::new()));
    let mut s = Local::behavior_subject::<bool, Infallible>(true);
    let mut r = Local::behavior_subject::<bool, Infallible>(true);

    let (q1, q2, _feedback_subs) = flipflop(
        scheduler.clone(),
        s.clone().box_it_clone(),
        r.clone().box_it_clone(),
    );

    // Subscribe to outputs (deferred to scheduler)
    let _output_sub = q1
        .clone()
        .combine_latest(q2.clone(), |a, b| (a, b))
        .observe_on(scheduler.clone())
        .subscribe(|(q, qn)| println!("Output: (Q={q}, Q'={qn})"));

    // Process initial state emissions
    scheduler.borrow_mut().drain();

    println!("\n--- Step 1: S=false (Set) ---");
    s.next(false);
    scheduler.borrow_mut().drain();

    println!("\n--- Step 2: S=true (Hold) ---");
    s.next(true);
    scheduler.borrow_mut().drain();

    println!("\n--- Step 3: R=false (Reset) ---");
    r.next(false);
    scheduler.borrow_mut().drain();

    println!("\n--- Step 4: R=true (Hold) ---");
    r.next(true);
    scheduler.borrow_mut().drain();

    println!("\nSimulation complete");
}"
