        if idx.len() != self.dims.len() {
            return None;
        }

        // Convert nD index to flat index (row-major)
        let mut flat_idx = 0;
        for (i, &dim_idx) in idx.iter().enumerate() {
            if dim_idx >= self.dims[i] {
                return None;
            }
            let stride: usize = self.dims[i+1..].iter().product();
            flat_idx += dim_idx * stride;
        }

        self.store.get(flat_idx)
    }

    // Safe indexing for mutable access
    pub fn get_mut(&mut self, idx: &[usize]) -> Option<&mut T> {
        if idx.len() != self.dims.len() {
            return None;
        }

        let mut flat_idx = 0;
        for (i, &dim_idx) in idx.iter().enumerate() {
            if dim_idx >= self.dims[i] {
                return None;
            }
            let stride: usize = self.dims[i+1..].iter().product();
            flat_idx += dim_idx * stride;
        }

        self.store.get_mut(flat_idx)
    }
}

// ===== IMMUTABLE ITERATOR (Working) =====
pub struct ArrayIterator<'a, T> {
    array: &'a Array<T>,
    current: Vec<usize>,
    done: bool,
}

impl<'a, T> ArrayIterator<'a, T> {
    pub fn new(array: &'a Array<T>) -> Self {
        Self {
            array,
            current: vec![0; array.dims.len()],
            done: array.store.is_empty(),
        }
    }

    fn increment(&mut self) -> bool {
        if self.done {
            return false;
        }

        // Increment index in row-major order
        for i in (0..self.current.len()).rev() {
            if self.current[i] + 1 < self.array.dims[i] {
                self.current[i] += 1;
                return true;
            }
            self.current[i] = 0;
        }
        self.done = true;
        false
    }
}

impl<'a, T> Iterator for ArrayIterator<'a, T> {
    type Item = (Vec<usize>, &'a T);

    fn next(&mut self) -> Option<Self::Item> {
        if self.done {
            return None;
        }

        let idx = self.current.clone();
        let value = self.array.get(&idx).unwrap();
        self.increment();
        Some((idx, value))
    }
}

// ===== MUTABLE ITERATOR (Working Solution) =====
// Key insight: Cannot hold &'a mut Array<T> while returning &'a mut T
// Solution: Use raw pointer with strict safety constraints
pub struct ArrayIteratorMut<'a, T> {
    // Safety invariant: ptr is valid for reads/writes for lifetime 'a
    // and points to the start of the backing storage
    ptr: *mut T,
    dims: Vec<usize>,
    current: Vec<usize>,
    done: bool,
    _phantom: std::marker::PhantomData<&'a mut T>,
}

impl<'a, T> ArrayIteratorMut<'a, T> {
    pub fn new(array: &'a mut Array<T>) -> Self {
        // Safety: array.store is guaranteed to be valid for 'a
        // We immediately transfer ownership of the mutable borrow to this iterator
        // No other mutable references to array.store can exist while iterator lives
        let ptr = array.store.as_mut_ptr();
        Self {
            ptr,
            dims: array.dims.clone(),
            current: vec![0; array.dims.len()],
            done: array.store.is_empty(),
            _phantom: std::marker::PhantomData,
        }
    }

    fn flat_index(&self) -> usize {
        let mut idx = 0;
        for (i, &dim_idx) in self.current.iter().enumerate() {
            let stride: usize = self.dims[i+1..].iter().product();
            idx += dim_idx * stride;
        }
        idx
    }

    fn increment(&mut self) -> bool {
        if self.done {
            return false;
        }

        for i in (0..self.current.len()).rev() {
            if self.current[i] + 1 < self.dims[i] {
                self.current[i] += 1;
                return true;
            }
            self.current[i] = 0;
        }
        self.done = true;
        false
    }
}

impl<'a, T> Iterator for ArrayIteratorMut<'a, T> {
    type Item = (Vec<usize>, &'a mut T);

    fn next(&mut self) -> Option<Self::Item> {
        if self.done {
            return None;
        }

        let flat_idx = self.flat_index();
        let current_idx = self.current.clone();

        // SAFETY JUSTIFICATION:
        // 1. ptr was created from a valid &'a mut Array<T> with non-empty storage
        // 2. flat_idx is guaranteed valid by iterator logic (checked during increment)
        // 3. Each flat_idx is unique per iteration (row-major order)
        // 4. No other references to this memory exist (enforced by &mut self in next())
        // 5. Lifetime 'a matches original array's borrow scope
        let value = unsafe {
            &mut *self.ptr.add(flat_idx)
        };

        self.increment();
        // SAFETY: We return a reference with lifetime 'a tied to original array
        // The iterator's existence prevents overlapping mutable accesses
        Some((current_idx, value))
    }
}

// ===== DEMONSTRATION =====
fn main() {
    println!("=== Immutable Iterator Demo ===");
    let arr = Array::new(vec![10, 20, 30, 40, 50, 60], vec![2, 3]);

    for (idx, val) in ArrayIterator::new(&arr) {
        println!("Index {:?}: {}", idx, val);
    }

    println!("\n=== Mutable Iterator Demo (doubling values) ===");
    let mut arr_mut = Array::new(vec![1, 2, 3, 4, 5, 6], vec![2, 3]);

    for (_, val) in ArrayIteratorMut::new(&mut arr_mut) {
        *val *= 2;
    }

    println!("Modified array:");
    for (idx, val) in ArrayIterator::new(&arr_mut) {
        println!("Index {:?}: {}", idx, val);
    }

    println!("\n=== Safety Demonstration ===");
    println!("Mutable iterator ensures:");
    println!("- Unique access per element (no aliasing)");
    println!("- Valid indices only (bounds-checked in flat_index)");
    println!("- Lifetime tied to original array borrow");
    println!("\n⚠️  Critical: Never hold multiple items from mutable iterator!");
    println!("   Iterator design prevents this via &mut self in next()");
}

// ===== WHY ORIGINAL APPROACH FAILED =====
// The original mutable iterator attempted:
//   array: &'a mut Array<T>
//   fn next(&mut self) -> Option<(&'a mut T)>
//
// This fails because:
// 1. Returning &'a mut T requires the reference to live for 'a
// 2. But the borrow of `self` in next() only lives for the call duration
// 3. Compiler cannot verify the reference won't outlive the method call
// 4. Additionally, holding &'a mut Array<T> while creating new &'a mut T
//    would violate Rust's aliasing rules (multiple mutable borrows)
//
// Solution used here:
// - Store raw pointer instead of &'a mut Array<T>
// - Use unsafe to create references with lifetime 'a
// - Enforce safety invariants through iterator design:
//   * Unique indices per iteration
//   * No external access during iteration
//   * Bounds checking in index calculation
//
// Alternative safe approach (not shown):
// Use closure-based iteration: array.apply_mut(|idx, val| { ... })
// This avoids Iterator trait limitations but changes API"
}

