                Some(s_noun) if s_noun.matches_filter(f_noun) => {},
                _ => return false,
            }
        }

        // CRITICAL DESIGN NOTES:
        // 1. Non-Option fields (preposition, common) are SKIPPED
        //    - Cannot distinguish "filter didn't set" vs "filter set to default"
        //    - Requires filter JSON to ONLY specify Option fields
        // 2. For Option fields: filter=None means "don't check this field"
        // 3. Recursion works because all nested types implement FilterMatch
        true
    }
}

fn main() {
    // ===== EXAMPLE 1: Stress filter matches =====
    let word1 = DictWordMetadata {
        stress: Some(Stress::Oxitona),
        noun: None,
        gender: None,
        preposition: false,
        common: true,
    };
    let filter1 = DictWordMetadata {
        stress: Some(Stress::Oxitona), // Only this field is checked
        noun: None,
        gender: None,
        preposition: true,  // Ignored (non-Option field)
        common: false,      // Ignored (non-Option field)
    };
    assert!(word1.matches_filter(&filter1), "Example 1 failed");
    println!("✓ Example 1: Stress filter matches");

    // ===== EXAMPLE 2: Nested noun filter =====
    let word2 = DictWordMetadata {
        noun: Some(NounData {
            plural: Some(true),
            irregular: false,
        }),
        stress: None,
        gender: None,
        preposition: false,
        common: false,
    };
    let filter2 = DictWordMetadata {
        noun: Some(NounData {
            plural: Some(true), // Checked recursively
            irregular: true,    // Ignored (non-Option in nested struct)
        }),
        stress: None,
        gender: None,
        preposition: false,
        common: false,
    };
    assert!(word2.matches_filter(&filter2), "Example 2 failed");
    println!("✓ Example 2: Nested noun filter matches");

    // ===== EXAMPLE 3: Mismatched stress =====
    let word3 = DictWordMetadata {
        stress: Some(Stress::Paroxitona),
        ..Default::default()
    };
    assert!(!word3.matches_filter(&filter1), "Example 3 failed");
    println!("✓ Example 3: Mismatched stress correctly rejected");

    // ===== EXAMPLE 4: Filter specifies gender but word doesn't have it =====
    let word4 = DictWordMetadata {
        gender: None,
        ..Default::default()
    };
    let filter4 = DictWordMetadata {
        gender: Some(Gender::Masculine),
        ..Default::default()
    };
    assert!(!word4.matches_filter(&filter4), "Example 4 failed");
    println!("✓ Example 4: Missing gender correctly rejected");

    // ===== EXAMPLE 5: Empty filter matches everything =====
    let empty_filter = DictWordMetadata {
        noun: None,
        stress: None,
        gender: None,
        preposition: false, // Ignored
        common: false,      // Ignored
    };
    assert!(word1.matches_filter(&empty_filter), "Example 5a failed");
    assert!(word2.matches_filter(&empty_filter), "Example 5b failed");
    println!("✓ Example 5: Empty filter matches all words");

    // ===== KEY GUIDANCE SUMMARY =====
    println!("\n=== IMPLEMENTATION GUIDANCE ===");
    println!("1. CRITICAL: Change filter representation!");
    println!("   - Current approach (same struct) cannot distinguish unset vs default for non-Option fields");
    println!("   - BETTER: Create dedicated Filter struct where EVERY field is Option<T>");
    println!("     Example: struct DictWordFilter {{ stress: Option<Stress>, ... }}");
    println!("2. If stuck with current approach:");
    println!("   - Only use Option fields in filters");
    println!("   - Never filter on non-Option fields (preposition, common, etc.)");
    println!("3. Recursion works via FilterMatch trait:");
    println!("   - Implement for all nested types (NounData, VerbData, etc.)");
    println!("   - For Option fields: check only if filter has Some(value)");
    println!("   - Skip non-Option fields entirely in matching logic");
    println!("4. Alternative approach: Use serde_json::Value for filter");
    println!("   - Parse filter as generic JSON value");
    println!("   - Traverse metadata struct matching only present keys");
    println!("   - Avoids trait boilerplate but requires manual path handling");
    println!("\nThis example demonstrates the trait-based recursive approach.");
    println!("For production: Strongly consider dedicated Filter struct with all Option fields.");
}

// Helper for cleaner test data
impl Default for DictWordMetadata {
    fn default() -> Self {
        Self {
            noun: None,
            stress: None,
            gender: None,
            preposition: false,
            common: false,
        }
    }
}

impl Default for NounData {
    fn default() -> Self {
        Self {
            plural: None,
            irregular: false,
        }
    }
}"
