  "main.rs": "use std::{
    collections::HashMap,
    fs::{self, File},
    io::{Read, Seek, SeekFrom, Write},
    path::PathBuf,
};
use bevy::{
    asset::{AssetLoader, AssetPath, AsyncReadSeek, LoadContext, LoadedAsset},
    prelude::*,
    utils::BoxedFuture,
};
use image::{ImageBuffer, Rgba};
use lazy_static::lazy_static;
use std::sync::Mutex;

// ===== ARCHIVE FORMAT UTILS =====
/// Simple archive format: [num_files: u32], then for each file:
/// [filename_len: u32][filename][offset: u64][size: u64], followed by concatenated data
fn create_test_archive(path: &std::path::Path) -> anyhow::Result<()> {
    if path.exists() {
        return Ok(());
    }

    fs::create_dir_all(path.parent().unwrap())?;
    let mut archive = File::create(path)?;

    // Create a tiny red PNG (16x16)
    let img = ImageBuffer::<Rgba<u8>, _>::from_pixel(16, 16, Rgba([255, 0, 0, 255]));
    let mut png_bytes = Vec::new();
    img.write_to(&mut png_bytes, image::ImageOutputFormat::Png)?;

    // Calculate header size for single file
    let filename = "red_square.png";
    let filename_len = filename.len() as u32;
    // Header: num_files (4) + filename_len (4) + filename + offset (8) + size (8)
    let header_size = 4 + 4 + filename_len + 8 + 8;
    let data_offset = header_size as u64;
    let data_size = png_bytes.len() as u64;

    // Write header
    archive.write_all(&1u32.to_le_bytes())?; // num_files
    archive.write_all(&filename_len.to_le_bytes())?;
    archive.write_all(filename.as_bytes())?;
    archive.write_all(&data_offset.to_le_bytes())?;
    archive.write_all(&data_size.to_le_bytes())?;
    archive.write_all(&png_bytes)?;

    Ok(())
}

// ===== LAZY ARCHIVE INDEX CACHE =====
lazy_static! {
    static ref ARCHIVE_CACHE: Mutex<HashMap<String, ArchiveIndex>> = Mutex::new(HashMap::new());
}

#[derive(Debug, Clone)]
struct ArchiveIndex {
    file_path: PathBuf,
    entries: HashMap<String, (u64, u64)>, // filename -> (offset, size)
}

impl ArchiveIndex {
    fn load(archive_path: &str) -> anyhow::Result<Self> {
        let mut cache = ARCHIVE_CACHE.lock().unwrap();
        if let Some(cached) = cache.get(archive_path) {
            return Ok(cached.clone());
        }

        // Resolve actual filesystem path (simplified for example)
        let assets_dir = std::env::current_dir()?.join("assets");
        let file_path = assets_dir.join(archive_path);

        if !file_path.exists() {
            anyhow::bail!("Archive not found: {:?}", file_path);
        }

        let mut file = File::open(&file_path)?;
        let mut buf = [0u8; 4];
        file.read_exact(&mut buf)?;
        let num_files = u32::from_le_bytes(buf);

        let mut entries = HashMap::new();
        for _ in 0..num_files {
            file.read_exact(&mut buf)?;
            let name_len = u32::from_le_bytes(buf) as usize;
            let mut name_buf = vec![0u8; name_len];
            file.read_exact(&mut name_buf)?;
            let name = String::from_utf8(name_buf)?;

            let mut offset_buf = [0u8; 8];
            file.read_exact(&mut offset_buf)?;
            let offset = u64::from_le_bytes(offset_buf);

            file.read_exact(&mut offset_buf)?;
            let size = u64::from_le_bytes(offset_buf);

            entries.insert(name, (offset, size));
        }

        let index = ArchiveIndex { file_path, entries };
        cache.insert(archive_path.to_string(), index.clone());
        Ok(index)
    }

    fn read_entry(&self, filename: &str) -> anyhow::Result<Vec<u8>> {
        let (offset, size) = self.entries.get(filename)
            .ok_or_else(|| anyhow::anyhow!("File not in archive: {}", filename))?;

        let mut file = File::open(&self.file_path)?;
        file.seek(SeekFrom::Start(*offset))?;
        let mut buf = vec![0u8; *size as usize];
        file.read_exact(&mut buf)?;
        Ok(buf)
    }
}

// ===== CUSTOM ASSET LOADER FOR ARCHIVED IMAGES =====
#[derive(Default)]
struct ArchivedImageLoader;

impl AssetLoader for ArchivedImageLoader {
    type Asset = Image;
    type Settings = ();
    type Error = anyhow::Error;

    fn extensions(&self) -> &[&str] {
        // Handles paths like: "archive.myarchive#texture.png"
        // We use a virtual extension to intercept these requests
        &["archived_png"]
    }

    fn load<'a>(
        &'a self,
        _reader: &'a mut dyn AsyncReadSeek,
        _settings: Self::Settings,
        load_context: &'a mut LoadContext,
    ) -> BoxedFuture<'a, Result<Self::Asset, Self::Error>> {
        Box::pin(async move {
            let asset_path = load_context.path().to_str().unwrap();
            // Parse virtual path: "archive.myarchive#texture.png.archived_png"
            let clean_path = asset_path.strip_suffix(".archived_png").unwrap_or(asset_path);
            let parts: Vec<&str> = clean_path.split('#').collect();
            if parts.len() != 2 {
                return Err(anyhow::anyhow!("Invalid archived asset path: {}", asset_path));
            }

            let (archive_path, internal_path) = (parts[0], parts[1]);
            let index = ArchiveIndex::load(archive_path)?;
            let data = index.read_entry(internal_path)?;

            // Decode image data
            let img = image::load_from_memory(&data)?;
            let rgba = img.into_rgba8();
            let dimensions = rgba.dimensions();

            Ok(Image::from_dynamic(rgba.into(), true))
        })
    }
}

// ===== BEVY APP SETUP =====
fn setup(mut commands: Commands, server: Res<AssetServer>) {
    // Request image from archive using virtual path format
    // Format: "<archive_path>#<internal_path>.archived_png"
    let texture_handle: Handle<Image> = server.load("test_archive.myarchive#red_square.png.archived_png");

    commands.spawn(Camera2dBundle::default());
    commands.spawn(SpriteBundle {
        texture: texture_handle,
        transform: Transform::from_scale(Vec3::splat(4.0)),
        ..default()
    });
}

fn main() {
    // Generate test archive before Bevy starts
    let archive_path = std::env::current_dir()
        .unwrap()
        .join("assets/test_archive.myarchive");
    create_test_archive(&archive_path).expect("Failed to create test archive");

    App::new()
        .add_plugins(DefaultPlugins.set(AssetPlugin {
            // Critical: Prevent Bevy from watching .myarchive files directly
            watch_for_changes: false,
            ..default()
        }))
        .init_asset_loader::<ArchivedImageLoader>()
        .add_systems(Startup, setup)
        .run();
}"
}

