        all_blob_names.len(),
        list_start.elapsed().as_secs_f32()
    );

    // Download and parse with controlled concurrency
    let download_start = Instant::now();
    info!("[Azure] Starting downloads with 50 concurrent requests");
    const MAX_CONCURRENT: usize = 50;
    let container_ref = Arc::new(container_client);

    let trades: Vec<TradeData> = stream::iter(all_blob_names)
