#[derive(Debug)]
enum B {
    Variant1(String),
    Variant2(i32),
}

// Custom deserializer for enum B (array representation: ["Variant", value])
impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<B, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct BVisitor;

        impl<'de> Visitor<'de> for BVisitor {
            type Value = B;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("an array with [variant_name, value]")
            }

            fn visit_seq<V>(self, mut seq: V) -> Result<B, V::Error>
            where
                V: SeqAccess<'de>,
            {
                let variant: String = seq
                    .next_element()?
                    .ok_or_else(|| de::Error::invalid_length(0, &"expected variant name"))?;

                match variant.as_str() {
                    "Variant1" => {
                        let value: String = seq
                            .next_element()?
                            .ok_or_else(|| de::Error::invalid_length(1, &"expected string value"))?;
                        Ok(B::Variant1(value))
                    }
                    "Variant2" => {
                        let value: i32 = seq
                            .next_element()?
                            .ok_or_else(|| de::Error::invalid_length(1, &"expected i32 value"))?;
                        Ok(B::Variant2(value))
                    }
                    _ => Err(de::Error::unknown_variant(
                        &variant,
                        &["Variant1", "Variant2"],
                    )),
                }
            }
        }

        deserializer.deserialize_seq(BVisitor)
    }
}

// Custom deserializer for struct A (map representation)
impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<A, D::Error>
    where
        D: Deserializer<'de>,
    {
        // Field identifiers for A's map keys (case-insensitive matching)
        #[derive(Deserialize)]
        #[serde(field_identifier, rename_all = "lowercase")]
        enum Field {
            X,
            B,
        }

        struct AVisitor;

        impl<'de> Visitor<'de> for AVisitor {
            type Value = A;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("a JSON object with 'x' and 'b' fields")
            }

            fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut x = None;
                let mut b = None;

                while let Some(key) = map.next_key()? {
                    match key {
                        Field::X => {
                            if x.is_some() {
                                return Err(de::Error::duplicate_field("x"));
                            }
                            x = Some(map.next_value()?);
                        }
                        Field::B => {
