  "Cargo.toml": "[package]
name = "websocket-origin-check"
version = "0.1.0"
edition = "2021"

[dependencies]
axum = "0.7.5"
tokio = { version = "1.36", features = ["full"] }
tower-http = { version = "0.5.2", features = ["cors"] }
",
  "main.rs": "use axum::{
    extract::{Path, State, ws::{WebSocket, WebSocketUpgrade}},
    http::{header::CONTENT_TYPE, HeaderValue, Method, StatusCode, Request, Response},
    middleware::{self, Next},
    response::IntoResponse,
    Router,
    body::Body,
};
use tower_http::cors::CorsLayer;
use std::net::SocketAddr;

/// State containing allowed origin for WebSocket connections
#[derive(Clone)]
struct OriginCheckState {
    allowed_origin: String,
}

/// Middleware to validate Origin header for WebSocket upgrades
async fn check_origin<B>(
    State(state): State<OriginCheckState>,
    req: Request<B>,
    next: Next<B>,
) -> Result<Response, Response> {
    // Extract and validate Origin header
    let origin = req.headers().get("origin").ok_or_else(|| {
        Response::builder()
            .status(StatusCode::FORBIDDEN)
            .body(Body::empty())
            .unwrap()
    })?;

    let origin_str = origin.to_str().map_err(|_| {
        Response::builder()
            .status(StatusCode::BAD_REQUEST)
            .body(Body::empty())
            .unwrap()
    })?;

    // Strict origin comparison (browsers send lowercase origins)
    if origin_str != state.allowed_origin {
        return Err(Response::builder()
            .status(StatusCode::FORBIDDEN)
            .body(Body::empty())
            .unwrap());
    }

    Ok(next.run(req).await)
}

/// WebSocket handler (origin already validated by middleware)
async fn client_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
) -> impl IntoResponse {
    println!("✅ WebSocket connection established for session: {}", session_id);
    ws.on_upgrade(move |socket| handle_socket(socket, session_id))
}

/// WebSocket message handler
async fn handle_socket(mut socket: WebSocket, session_id: String) {
    while let Some(msg) = socket.recv().await {
        match msg {
            Ok(msg) => {
                if socket.send(msg).await.is_err() {
                    break;
                }
            }
            Err(e) => {
                eprintln!("❌ WebSocket error for session {}: {:?}", session_id, e);
                break;
            }
        }
    }
    println!("🔌 WebSocket connection closed for session: {}", session_id);
}

#[tokio::main]
async fn main() {
    // Configure origin validation state (matches browser-sent origin format)
    let origin_state = OriginCheckState {
        allowed_origin: "https://www.example.com".to_string(),
    };

    // Apply origin check middleware ONLY to WebSocket route
    let ws_route = axum::routing::get(client_handler)
        .layer(middleware::from_fn_with_state(
            origin_state.clone(),
            check_origin,
        ));

    // Build application with CORS for non-WebSocket routes
    let app = Router::new()
        .route("/client/:session_id", ws_route)
        .layer(
            CorsLayer::new()
                .allow_origin("https://www.example.com".parse::<HeaderValue>().unwrap())
                .allow_methods([Method::GET, Method::POST])
                .allow_headers([CONTENT_TYPE]),
        );

    // Start server
    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    println!("🚀 Server running at http://{}", addr);
    println!("🔒 WebSocket connections ONLY allowed from: https://www.example.com");

    axum::Server::bind(&addr)
        .serve(app.into_make_service())
        .await
        .unwrap();
}
"
}

