// Simple owned token type (no lifetimes required)
#[derive(PartialEq, Clone, Debug)]
enum Token {
    Num(u64),
    Ident(String),
}

impl std::fmt::Display for Token {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Token::Num(n) => write!(f, "Num({})", n),
            Token::Ident(s) => write!(f, "Ident({})", s),
        }
    }
}

// Fixed trait design: Tokens are owned (no lifetime parameters)
pub trait BaseParser {
    type InputToken: PartialEq + std::fmt::Display;
    type Input<'src>: Input<'src, Token = Self::InputToken, Span = SimpleSpan>
    where
        Self: 'src;
    type Output;

    fn parser<'src>() -> impl Parser<'src, Self::Input<'src>, Self::Output, extra::Default>
    where
        Self: 'src;

    fn parse_this<'src>(input: Self::Input<'src>) -> Result<Self::Output, Vec<String>>
    where
        Self: 'src,
    {
        Self::parser()
            .parse(input)
            .into_result()
            .map_err(|errors| errors.into_iter().map(|e| e.to_string()).collect())
    }
}

// BaseSliceParser no longer parameterized by 'src
// Constraint moved to method implementation requirements
pub trait BaseSliceParser: BaseParser {
    fn parse_this_owned(input: Vec<Self::InputToken>) -> Result<Self::Output, Vec<String>> {
        // input.as_slice() has lifetime tied to this function scope
        // Compiler verifies Self::Input<'_> = &'_ [Token] at implementation site
        Self::parse_this(input.as_slice())
    }
}

// Concrete parser implementation
struct NumberParser;

impl BaseParser for NumberParser {
    type InputToken = Token;
    type Input<'src> = &'src [Token];
    type Output = u64;

    fn parser<'src>() -> impl Parser<'src, Self::Input<'src>, Self::Output, extra::Default> {
        // Parse a single Num token
        any().try_map(|token, span| match token {
            Token::Num(n) => Ok(n),
            _ => Err(Rich::custom(span, "expected number token")),
        })
    }
}

impl BaseSliceParser for NumberParser {}

