}

/// Stage 1: Demonstrates span rehydration pattern
async fn stage1(ctx: &RequestContext) {
    // Rehydrate parent context ONLY for child span creation
    let parent_context = ctx.parent_span.context();
    let _guard = parent_context.attach(); // Sets OTel context for current thread
    let child_span = tracing::span!(tracing::Level::INFO, "stage1");
    drop(_guard); // Critical: release context immediately after span creation

    // Instrument entire async block with child span
    async move {
        tracing::info!("Stage 1 processing started");
        tokio::time::sleep(Duration::from_millis(15)).await;
        tracing::info!("Stage 1 processing completed");
    }
    .instrument(child_span)
    .await;
