async fn stage2(ctx: &RequestContext) {
    let parent_context = ctx.parent_span.context();
    let _guard = parent_context.attach();
    let child_span = tracing::span!(tracing::Level::INFO, "stage2");
    drop(_guard);

    async move {
        tracing::info!("Stage 2 processing started");
        tokio::time::sleep(Duration::from_millis(10)).await;
        tracing::info!("Stage 2 processing completed");

        // Nested operation example
        {
            let _upstream_span = tracing::span!(tracing::Level::INFO, "upstream_call").entered();
            tracing::info!("Making upstream call");
            tokio::time::sleep(Duration::from_millis(5)).await;
        }
