  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll};
use futures::task::noop_waker_ref;

enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Attempts to poll a future once in the current context.
/// - If ready: returns the value immediately
/// - If pending: spawns a Tokio task to await the future and returns Pending
fn try_poll<F, X>(future: F) -> TryPollResult<X>
where
    F: Future<Output = X> + Send + 'static,
    X: Send + 'static,
{
    let mut future = Box::pin(future);
    let waker = noop_waker_ref();
    let mut cx = Context::from_waker(waker);

    match future.as_mut().poll(&mut cx) {
        Poll::Ready(value) => TryPollResult::Ready(value),
        Poll::Pending => {
            tokio::spawn(async move {
                let result = future.await;
                println!("[Spawned task] Future completed with: {:?}", result);
            });
            TryPollResult::Pending
        }
    }
}

#[tokio::main]
async fn main() {
    println!("=== Test 1: Immediate future ===");
    let immediate_future = async { 42 };
    match try_poll(immediate_future) {
        TryPollResult::Ready(val) => println!("✅ Got value immediately: {}", val),
        TryPollResult::Pending => println!("❌ Unexpected pending state"),
    }

    println!("\n=== Test 2: Pending future (sleep) ===");
    let delayed_future = async {
        tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
        "Result from spawned task"
    };
    match try_poll(delayed_future) {
        TryPollResult::Ready(_) => println!("❌ Unexpected ready state"),
        TryPollResult::Pending => println!("⏳ Future was pending - spawned background task"),
    };

    println!("\n(Main waiting for spawned task to complete...)");
    tokio::time::sleep(tokio::time::Duration::from_millis(150)).await;
    println!("\n✅ Main function completed successfully");
}"
}

