#[derive(Debug)]
enum FlusterError {
    FailToParseDate,
}

impl fmt::Display for FlusterError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Date parsing failed")
    }
