type FlusterResult<T> = Result<T, FlusterError>;

/// Converts LanceDB ISO date string (with optional fractional seconds, no timezone)
/// to Unix timestamp in milliseconds as i64
pub fn date_string_to_int(d: &str) -> FlusterResult<i64> {
    // Try formats: with fractional seconds first (handles 1-9 digits), then without
    let dt_naive = NaiveDateTime::parse_from_str(d, "%Y-%m-%dT%T%.f")
        .or_else(|_| NaiveDateTime::parse_from_str(d, "%Y-%m-%dT%T"))
        .map_err(|_| FlusterError::FailToParseDate)?;

    // Assume UTC (Unix timestamps are UTC-based)
    let dt_utc = Utc.from_utc_datetime(&dt_naive);
    Ok(dt_utc.timestamp_millis())
}

