use rustyline::event::{ConditionalEventHandler, Event, EventContext, RepeatCount};
use rustyline::keys::Movement;

/// Custom event handler that removes preceding whitespace when typing '.' or ','
struct SmartPunctHandler {
    insert_char: char,
}

impl SmartPunctHandler {
    fn new(c: char) -> Self {
        SmartPunctHandler { insert_char: c }
    }
}

impl ConditionalEventHandler for SmartPunctHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();

        // Only process if cursor isn't at start
        if pos == 0 {
            return Some(Cmd::Insert(self.insert_char.to_string()));
        }

        // Check characters before cursor for whitespace
        let prefix = &line[..pos];
        if let Some(last_non_ws) = prefix.rfind(|c: char| !c.is_whitespace()) {
            let ws_start = last_non_ws + 1;
            if ws_start < pos {
                // Whitespace exists before cursor - replace it
                let ws_count = pos - ws_start;
                let movement = Movement::BackwardChar(ws_count as RepeatCount);
                return Some(Cmd::Replace(movement, Some(self.insert_char.to_string())));
            }
        }

        // No whitespace to remove - insert normally
        Some(Cmd::Insert(self.insert_char.to_string()))
    }
}

/// Binds smart handler to specified punctuation character
fn bind_smart_punct(editor: &mut Editor<SqlHelper>, c: char) {
    let event = KeyEvent::new(c, Modifiers::NONE);
    let handler = SmartPunctHandler::new(c);
    editor.bind_sequence(event, EventHandler::Conditional(Box::new(handler))).ok();
}

/// Minimal SQL-aware helper with tab completion
struct SqlHelper;

impl Helper for SqlHelper {}

impl Completer for SqlHelper {
    type Candidate = Pair;

    fn complete(
        &self,
        line: &str,
        pos: usize,
        _ctx: &Context<'_>,
    ) -> Result<(usize, Vec<Pair>), ReadlineError> {
        // Simple completion for demonstration
        let word_start = line[..pos]
            .rfind(|c: char| c.is_whitespace() || c == '>' || c == ';')
            .map(|i| i + 1)
            .unwrap_or(0);

        let word = &line[word_start..pos];

        let candidates = match word {
            "bo" => vec![Pair {
                display: "book".into(),
                replacement: "book ".into(), // Note trailing space
            }],
            "ti" => vec![Pair {
                display: "title".into(),
                replacement: "title ".into(),
            }],
            "au" => vec![Pair {
                display: "author".into(),
                replacement: "author ".into(),
            }],
            _ => vec![],
        };

        Ok((word_start, candidates))
    }
}

impl Hinter for SqlHelper {
    type Hint = String;
    fn hint(&self, _line: &str, _pos: usize, _ctx: &Context<'_>) -> Option<String> {
        None
    }
