            Err(err) => {
                eprintln!("Error: {:?}", err);
                break;
            }
        }
    }

    println!("\nDemo terminated. Key behaviors:");
    println!("- After 'bo<TAB>' becomes 'book ', typing '.' → 'book.' with cursor AFTER dot");
    println!("- Same behavior for commas");
    println!("- Normal insertion when no preceding whitespace");
