        };

        // Create pool with NoTls (matches original code)
        let admin_pool = cfg
            .create_pool(Some(mgr_config), NoTls)
            .expect("Failed to create admin connection pool");

        Self {
            db_config,
            admin_pool,
        }
    }

    /// Creates a new database and initializes its schema
    pub async fn create_database(&self, name: &str) -> Result<(), tokio_postgres::Error> {
        // Get validated connection from pool (handles reconnection if needed)
        let client = self
            .admin_pool
            .get()
            .await
            .map_err(|e| tokio_postgres::Error::Io(std::io::Error::new(std::io::ErrorKind::Other, format!("Pool error: {}", e))))?;

        // Create database using pooled admin connection
        client
            .execute(&format!("CREATE DATABASE \"{}\"", name), &[])
            .await?;

        // Connect directly to new DB for schema initialization (short-lived)
        let conn_str = format!(
            "host=localhost port={} user=postgres password={} dbname={}",
            self.db_config.port, self.db_config.postgres_password, name
        );
        let (client, conn) = tokio_postgres::connect(&conn_str, NoTls).await?;

        // Spawn connection driver
        tokio::spawn(async move {
            if let Err(e) = conn.await {
                eprintln!("Connection error in new DB: {}", e);
            }
        });

        // Initialize schema (example query)
        client
            .batch_execute("CREATE TABLE IF NOT EXISTS initialized (id SERIAL);")
            .await?;
        Ok(())
    }

    /// Drops a database after terminating active connections
    pub async fn drop_database(&self, name: &str) -> Result<u64, tokio_postgres::Error> {
        let client = self
            .admin_pool
            .get()
            .await
            .map_err(|e| tokio_postgres::Error::Io(std::io::Error::new(std::io::ErrorKind::Other, format!("Pool error: {}", e))))?;

