//! 4. Main thread prints pending messages above prompt using rl.print_message()
//! 5. Prompt + current input buffer automatically restored

use rustyline::error::ReadlineError;
use rustyline::Editor;
use std::sync::mpsc::{channel, TryRecvError};
use std::thread;
use std::time::Duration;
use nix::sys::signal;
use nix::unistd;

// Signal handler (does nothing - only exists to interrupt syscalls)
extern "C" fn sigusr1_handler(_: nix::sys::signal::SigNum) {}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Setup SIGUSR1 handler BEFORE spawning child thread
    unsafe {
        signal::signal(signal::Signal::SIGUSR1, signal::SigHandler::Handler(sigusr1_handler))
            .expect("Failed to set SIGUSR1 handler");
    }

    let (tx, rx) = channel();

    // Spawn child process thread (bash demo)
    thread::spawn(move || {
        // Start bash with periodic output for demonstration
        // Replace with your target REPL command
        let mut child = std::process::Command::new("bash")
            .arg("-c")
            .arg(r#"
                echo "[Child REPL started - type commands below]"
                echo "Try: date, whoami, or 'sleep 1 && echo async output'"
                PS1="child> "
                while read -p "child> " cmd; do
                    if [ "$cmd" = "exit" ]; then
                        echo "[Child exiting]"
                        break
                    fi
                    eval "$cmd" 2>&1 | while IFS= read -r line; do
                        echo "$line"
                    done
                done
            "#)
            .stdout(std::process::Stdio::piped())
            .stderr(std::process::Stdio::piped())
            .spawn()
            .expect("Failed to spawn child REPL");

        // Capture stdout
        let stdout = child.stdout.take().expect("Failed to capture stdout");
        let reader = std::io::BufReader::new(stdout);

        // Forward all child output to main thread
        for line in reader.lines() {
            if let Ok(line) = line {
                // Critical: Send output THEN trigger signal
                if tx.send(line).is_err() {
                    break; // Main thread exited
                }
                // Send SIGUSR1 to self to interrupt readline
                let pid = unistd::getpid();
                let _ = signal::kill(pid, signal::Signal::SIGUSR1);
            } else {
                break;
            }
        }

        // Cleanup: Ensure child process terminates
        let _ = child.wait();
    });

    let mut rl = Editor::<()>::new()?;
    rl.set_helper(None);

    println!("\nParent REPL started. Child output will appear above prompt.");
    println!("Type 'exit' to quit parent. Child accepts bash commands.\n");

    loop {
        match rl.readline("> ") {
            Ok(line) => {
                let trimmed = line.trim();
                rl.add_history_entry(trimmed)?;

                // Exit command handling
                if trimmed == "exit" {
                    println!("\nExiting parent REPL...");
                    break;
                }

                // Optional: Forward command to child stdin here
                // (Requires capturing child.stdin in thread and channel)
                println!("Parent received: '{}'", trimmed);
            }

            // Signal interrupted readline - process pending child output
            Err(ReadlineError::Interrupted) => {
                let mut msg_count = 0;
                loop {
                    match rx.try_recv() {
                        Ok(msg) => {
                            // Print ABOVE current prompt without corruption
                            rl.print_message(&msg)?;
                            msg_count += 1;
                        }
                        Err(TryRecvError::Empty) => break,
                        Err(TryRecvError::Disconnected) => {
                            eprintln!("\n[Child process terminated]");
                            break;
                        }
