                }
                // Redraw prompt automatically happens on next readline iteration
                if msg_count > 0 {
                    // Force visual separation after multiple messages
                    if msg_count > 1 {
                        rl.print_message("")?; // Blank line
                    }
                    continue; // Immediately redraw prompt with buffer
                }
            }

            Err(ReadlineError::Eof) | Err(ReadlineError::Io(_)) => break,
            Err(e) => {
                eprintln!("\nReadline error: {:?}", e);
                break;
            }
        }
    }

    Ok(())
}
"
}

