// Type alias for boxed response body
type BoxBody = http_body_util::combinators::BoxBody<Bytes, Box<dyn std::error::Error + Send + Sync>>;

// Convert tokio::fs::File into streaming hyper response body
async fn file_to_response_body(
    file: tokio::fs::File,
    metadata: std::fs::Metadata,
    path: &Path,
) -> Result<Response<BoxBody>, Infallible> {
    let content_length = metadata.len();

    // Create stream from file: ReaderStream yields Bytes chunks
    let reader_stream = ReaderStream::new(file);
    // Convert each Bytes chunk into hyper Frame
    let frame_stream = reader_stream.map_ok(Frame::data);
    // Wrap stream into hyper-compatible body
    let body = StreamBody::new(frame_stream);
    // Box the body for type erasure and error normalization
    let boxed_body: BoxBody = body.map_err(|e| e.into()).boxed();

    // Basic content-type detection (minimal for example)
    let content_type = path
        .extension()
        .and_then(|ext| ext.to_str())
        .map(|ext| match ext.to_lowercase().as_str() {
            "html" | "htm" => "text/html",
            "css" => "text/css",
            "js" => "application/javascript",
            "json" => "application/json",
            "png" => "image/png",
            "jpg" | "jpeg" => "image/jpeg",
            "gif" => "image/gif",
            "svg" => "image/svg+xml",
            _ => "application/octet-stream",
        })
        .unwrap_or("application/octet-stream");

    let mut response = Response::new(boxed_body);
    response.headers_mut().insert(CONTENT_LENGTH, content_length.into());
    response.headers_mut().insert(CONTENT_TYPE, HeaderValue::from_static(content_type));
    Ok(response)
}

// Handle HTTP requests
async fn handle(req: Request<Incoming>) -> Result<Response<BoxBody>, Infallible> {
    // Only allow GET requests
    if req.method() != Method::GET {
        return Ok(not_found());
    }

    // Basic path traversal protection
    let req_path = req.uri().path();
    if req_path.contains("..") || req_path.contains("~") {
        return Ok(not_found());
    }

    // Resolve requested path against current directory
    let base_dir = PathBuf::from(".");
    let mut file_path = if req_path == "/" {
        base_dir.join("index.html")
    } else {
        base_dir.join(req_path.trim_start_matches('/'))
    };

    // Security: normalize path and verify it stays within base directory
    file_path = match dunce::canonicalize(&file_path) {
        Ok(p) => p,
        Err(_) => return Ok(not_found()),
    };

    let base_canon = match dunce::canonicalize(&base_dir) {
        Ok(p) => p,
        Err(_) => return Ok(not_found()),
    };

    if !file_path.starts_with(&base_canon) {
        return Ok(not_found());
    }

    // Attempt to open file
    let file = match tokio::fs::File::open(&file_path).await {
        Ok(f) => f,
        Err(_) => return Ok(not_found()),
    };

    // Get file metadata
    let metadata = match file.metadata().await {
        Ok(m) => m,
        Err(_) => return Ok(not_found()),
    };

    // Reject directories
    if metadata.is_dir() {
        return Ok(not_found());
    }

    // Stream file as response body
    file_to_response_body(file, metadata, &file_path).await
