#[derive(Debug, Clone)]
pub struct EventSender {
    tx: broadcast::Sender<Event>,
}

impl EventSender {
    pub fn send(&self, event: Event) {
        // Ignore send errors (receiver lag/drop)
        let _ = self.tx.send(event);
    }
}

pub struct EventStreamFactory {
    tx: broadcast::Sender<Event>,
}

impl EventStreamFactory {
    /// Returns stream that yields broadcast errors directly
    /// Critical: Stream continues on Lagged errors, terminates on Closed
    pub fn all_events(&self) -> impl Stream<Item = Result<Event, broadcast::error::RecvError>> + '_ {
        BroadcastStream::new(self.tx.subscribe())
    }
}

/// Sends events until cancellation token is triggered
async fn send_events(sender: EventSender, token: CancellationToken) {
    let mut interval = tokio::time::interval(Duration::from_secs(1));
    let mut count = 0;

    loop {
        tokio::select! {
            _ = token.cancelled() => {
                println!("[Sender] Cancellation received, stopping sends");
                break;
            }
            _ = interval.tick() => {
                count += 1;
                sender.send(format!("Event #{}", count));
                println!("[Sender] Sent event #{}", count);
            }
        }
    }
}

/// Consumes event stream, exits cleanly on channel closure
async fn consume_stream(stream: impl Stream<Item = Result<Event, broadcast::error::RecvError>>) {
    pin_mut!(stream);

    while let Some(item) = stream.next().await {
        match item {
            Ok(event) => println!("[Consumer] Received: {}", event),
            Err(broadcast::error::RecvError::Closed) => {
                println!("[Consumer] Channel closed by sender - exiting cleanly");
                break;
