// ===== MUTABLE ITERATOR (USES UNSAFE - SAFE WHEN USED CORRECTLY) =====
pub struct ArrayMutIterator<'a, T> {
    data_ptr: *mut T,
    dims: &'a [usize],
    index: usize,
    len: usize,
    _marker: PhantomData<&'a mut T>,
}

impl<'a, T> Iterator for ArrayMutIterator<'a, T> {
    type Item = (Vec<usize>, &'a mut T);

    fn next(&mut self) -> Option<Self::Item> {
        if self.index >= self.len {
            return None;
        }
        // Compute n-dimensional index BEFORE creating mutable reference
        let nd_index = linear_to_nd(self.index, self.dims);

        // SAFETY:
        // 1. `data_ptr` originates from a valid `&mut [T]` with length `len`
        // 2. `index` is verified to be < `len` (bounds-checked above)
        // 3. Each element is accessed exactly once (index increments monotonically)
        // 4. No aliasing: iterator holds exclusive access to the array data
        // 5. Lifetime `'a` matches the original borrow of the Array
        let element_ref = unsafe { &mut *self.data_ptr.add(self.index) };
        self.index += 1;
        Some((nd_index, element_ref))
    }
}

