    let mut arr = Array::new(vec![1, 2, 3, 4], vec![2, 2]);

    println!("=== Immutable iteration ===");
    for (idx, val) in arr.iter() {
        println!("Index {:?}, value: {}", idx, val);
    }

    println!("\n=== Mutable iteration (doubling values) ===");
    for (idx, val) in arr.iter_mut() {
        *val *= 2;
        println!("Modified index {:?}, new value: {}", idx, val);
    }

    println!("\n=== Final array state ===");
    for (idx, val) in arr.iter() {
        println!("Index {:?}, value: {}", idx, val);
    }

    // Verify results
    assert_eq!(arr.store, vec![2, 4, 6, 8]);
    println!("\n✅ All operations completed successfully!");
}

