http = "1.0"
futures-util = "0.3"",
  "main.rs": "use axum::{
    extract::{
        ws::{Message, WebSocket, WebSocketUpgrade},
        Path,
    },
    middleware::{self, Next},
    response::{IntoResponse, Response},
    routing::get,
    Router,
};
use http::{header::ORIGIN, Request, StatusCode};
use std::net::SocketAddr;
use tower_http::cors::{CorsLayer, Any};
use http::header::CONTENT_TYPE;
use http::Method;

#[tokio::main]
async fn main() {
    // Configure CORS layer for non-WebSocket routes (doesn't block WebSocket upgrades)
    let cors_layer = CorsLayer::new()
        .allow_origin("https://www.example.com".parse::<http::HeaderValue>().unwrap())
        .allow_methods([Method::GET, Method::POST])
        .allow_headers([CONTENT_TYPE]);

    // Build router with origin-check middleware applied ONLY to WebSocket route
    let app = Router::new()
        .route(
            "/client/:session_id",
            get(ws_handler).layer(middleware::from_fn(check_origin)),
        )
        .layer(cors_layer);

    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    println!("\nServer starting at http://{}", addr);
    println!("WebSocket endpoint: ws://localhost:3000/client/test123");
    println!("Allowed origin: https://www.example.com\n");

    let listener = tokio::net::TcpListener::bind(addr).await.unwrap();
    axum::serve(listener, app).await.unwrap();
}

/// Middleware to validate Origin header for WebSocket upgrades
/// Applied ONLY to /client/:session_id route via route-specific layer
async fn check_origin<B>(
    req: Request<B>,
    next: Next<B>,
) -> Result<Response, StatusCode> {
    // Extract and validate Origin header (case-insensitive comparison)
    let origin = req
        .headers()
        .get(ORIGIN)
        .and_then(|v| v.to_str().ok())
        .ok_or(StatusCode::FORBIDDEN)?;

    // In production: parse URL, validate host/scheme/port properly
    // This example uses simple case-insensitive string match
    if !origin.eq_ignore_ascii_case("https://www.example.com") {
        eprintln!("❌ Rejected connection from invalid origin: {}", origin);
        return Err(StatusCode::FORBIDDEN);
    }

    println!("✅ Accepted connection from origin: {}", origin);
    Ok(next.run(req).await)
}

/// WebSocket handler (no origin check needed - middleware already validated)
async fn ws_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
) -> impl IntoResponse {
    println!("➡️  Upgrading WebSocket for session: {}", session_id);
    ws.on_upgrade(move |socket| handle_socket(socket, session_id))
}

/// WebSocket message handler (simple echo)
async fn handle_socket(mut socket: WebSocket, session_id: String) {
    println!("🔌 WebSocket connected for session: {}", session_id);

    while let Some(msg) = socket.recv().await {
        match msg {
            Ok(Message::Text(text)) => {
                println!("📨 Received text ({}): {}", session_id, text);
                if socket.send(Message::Text(text)).await.is_err() {
                    break;
                }
            }
            Ok(Message::Binary(data)) => {
                println!("📦 Received binary data ({} bytes)", data.len());
                if socket.send(Message::Binary(data)).await.is_err() {
                    break;
                }
            }
            Ok(Message::Close(_)) => {
                println!("CloseOperation received for session {}", session_id);
                break;
            }
            Ok(_) => continue,
            Err(e) => {
                eprintln!("❌ WebSocket error for session {}: {}", session_id, e);
                break;
            }
        }
    }

    println!("🔌 WebSocket disconnected for session: {}\n", session_id);
}"
}

