  "main.rs": "use ouroboros::self_referencing;
use serde::Deserialize;
use std::sync::Arc;
use tokio;

/// Zero-copy deserialized struct with borrowed references
#[derive(Deserialize, Debug)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

/// Self-referential container that safely binds the JSON buffer
/// to the deserialized references. Enabled for Send/Sync to cross task boundaries.
#[self_referencing(send, sync)]
struct SharedMyData {
    owner: Arc<String>,
    #[borrows(owner)]
    #[covariant]
    data: MyData<'this>,
}

#[tokio::main]
async fn main() {
    // Simulate received JSON payload (e.g., from TCP stream)
    let json_payload = r#"{"data": "zero-copy", "more_data": "no_cloning"}"#.to_string();
    let json_buffer = Arc::new(json_payload);

    // Deserialize ONCE into self-referential struct
    // Lifetime of references is safely bound to the Arc'd buffer
    let shared_data = SharedMyDataBuilder {
        owner: json_buffer.clone(),
        data_builder: |owner| {
            // &**owner converts &Arc<String> → &String → &str
            serde_json::from_str(&**owner)
                .expect("Failed to deserialize JSON payload")
        },
    }
    .build();

    // Wrap in Arc for cheap cloning across tasks
    let shared = Arc::new(shared_data);

    // Spawn multiple tasks sharing the ZERO-COPY deserialized data
    let task1 = tokio::spawn({
        let handle = shared.clone();
        async move {
            handle.with_data(|data| {
                println!("[Task 1] data='{}', more_data='{}'", data.data, data.more_data);
            });
        }
    });

    let task2 = tokio::spawn({
        let handle = shared.clone();
        async move {
            handle.with_data(|data| {
                println!("[Task 2] data='{}', more_data='{}'", data.data, data.more_data);
            });
        }
    });

    // Wait for all tasks to complete
    let _ = tokio::join!(task1, task2);
    println!("\n✅ Successfully shared zero-copy deserialized data across tasks!");
    println!("   - Original string buffer cloned 0 times (only Arc refcounts incremented)");
    println!("   - Deserialization performed exactly once");
    println!("   - No unsafe code used");
}"
}

