  "main.rs": "use std::fs;
use std::path::PathBuf;
use serde::{Deserialize, Deserializer};
use serde_json::Value;

fn deserialize_path_list<'de, D>(deserializer: D) -> Result<Vec<PathBuf>, D::Error>
where
    D: Deserializer<'de>,
{
    let value = Value::deserialize(deserializer)?;

    match value {
        Value::Array(arr) => {
            let mut paths = Vec::new();
            for item in arr {
                match item {
                    Value::String(s) => paths.push(PathBuf::from(s)),
                    _ => return Err(serde::de::Error::custom("expected string in array")),
                }
            }
            Ok(paths)
        }
        Value::Object(obj) => {
            if let Some(ref_value) = obj.get("$ref") {
                if let Some(ref_str) = ref_value.as_str() {
                    let (file_path, json_pointer) = ref_str
                        .split_once('#')
                        .ok_or_else(|| serde::de::Error::custom("invalid $ref format: missing '#'"))?;

                    let content = fs::read_to_string(file_path)
                        .map_err(|e| serde::de::Error::custom(format!("failed to read file '{}': {}", file_path, e)))?;

                    let referenced_value: Value = serde_json::from_str(&content)
                        .map_err(|e| serde::de::Error::custom(format!("failed to parse JSON in file '{}': {}", file_path, e)))?;

                    let target_value = if json_pointer.is_empty() {
                        &referenced_value
                    } else {
                        referenced_value
                            .pointer(json_pointer)
                            .ok_or_else(|| serde::de::Error::custom(format!("JSON pointer '{}' not found in file '{}'", json_pointer, file_path)))?
                    };

                    if let Value::Array(arr) = target_value {
                        let mut paths = Vec::new();
                        for item in arr {
                            if let Value::String(s) = item {
                                paths.push(PathBuf::from(s));
                            } else {
                                return Err(serde::de::Error::custom("expected string in referenced array"));
                            }
                        }
                        Ok(paths)
                    } else {
                        Err(serde::de::Error::custom(format!(
                            "value at JSON pointer '{}' in file '{}' is not an array",
                            json_pointer, file_path
                        )))
                    }
                } else {
                    Err(serde::de::Error::custom("$ref value must be a string"))
                }
            } else {
                Err(serde::de::Error::custom("expected object containing '$ref' key"))
            }
        }
        _ => Err(serde::de::Error::custom("expected an array or an object with a '$ref' key")),
    }
