use anyhow::{anyhow, Result};
use std::{io::BufRead, path::PathBuf};

// ========================================
// CUSTOM ARCHIVE ASSET & LOADER
// ========================================

/// Represents an archive file (like WAD/ZIP) with lazy-accessible entries
/// Stores only the index metadata + raw bytes (not decoded assets)
#[derive(Debug, Clone, serde::Deserialize, serde::Serialize)]
pub struct Archive {
    /// Maps entry name (e.g., "textures/wall1") to (offset, size) in raw_data
    pub index: HashMap<String, (usize, usize)>,
    /// Raw bytes of the ENTIRE archive file (kept in memory for random access)
    /// For huge archives, replace with file path + async file seeking in production
    pub raw_data: Vec<u8>,
}

impl Asset for Archive {}

/// Loader for ".lazyarchive" files
/// Parses header to build index WITHOUT decoding contained assets
#[derive(Default)]
pub struct ArchiveLoader;

impl AssetLoader for ArchiveLoader {
    async fn load<'a>(
        &'a self,
        mut reader: &'a mut bevy::asset::io::Reader,
        _settings: &'a bevy::asset::Settings,
        _load_context: &'a mut LoadContext,
    ) -> Result<LoadedAsset, anyhow::Error> {
        // Read entire archive file into memory (header + data)
        // For massive archives (>1GB), consider memory-mapped files in production
        let mut bytes = Vec::new();
        reader.read_to_end(&mut bytes).await?;

        // Parse header to build index (cheap operation)
        let index = parse_archive_header(&bytes)?;

        let archive = Archive {
            index,
            raw_data: bytes,
        };

        Ok(LoadedAsset::new(archive))
    }

    fn extensions(&self) -> &[&str] {
        &["lazyarchive"]
    }
}

/// Parses simple text-based header:
/// Line 1: entry_count
/// Next N lines: "name offset size"
fn parse_archive_header(data: &[u8]) -> Result<HashMap<String, (usize, usize)>> {
    let mut cursor = std::io::Cursor::new(data);
    let mut reader = std::io::BufReader::new(&mut cursor);
    let mut line = String::new();

    // Read entry count
    reader.read_line(&mut line)?;
    let entry_count: usize = line.trim().parse().map_err(|_| anyhow!("Invalid entry count"))?;
    line.clear();

    // Parse each entry
    let mut index = HashMap::new();
    for _ in 0..entry_count {
        reader.read_line(&mut line)?;
        let parts: Vec<&str> = line.trim().split(' ').collect();
        if parts.len() != 3 {
            return Err(anyhow!("Invalid entry format"));
        }
        let name = parts[0].to_string();
        let offset: usize = parts[1].parse()?;
        let size: usize = parts[2].parse()?;
        index.insert(name, (offset, size));
        line.clear();
    }

    Ok(index)
}

// ========================================
// LAZY ASSET EXTRACTION SYSTEM
// ========================================

/// Resource to track extraction requests
#[derive(Resource, Default)]
struct ExtractionQueue(Vec<(String, String)>); // (archive_path, entry_name)

/// Request extraction of an asset from an archive
fn request_extraction(
    mut commands: Commands,
    asset_server: Res<AssetServer>,
    mut queue: ResMut<ExtractionQueue>,
) {
    // Example: Request "test.txt" from "test.lazyarchive" on startup
    if queue.0.is_empty() {
        queue.0.push(("test.lazyarchive".to_string(), "test.txt".to_string()));
        // Load archive asset (triggers ArchiveLoader)
        let _handle = asset_server.load::<Archive>("test.lazyarchive");
    }
}

/// System that lazily extracts requested assets from loaded archives
fn process_extraction_queue(
    mut queue: ResMut<ExtractionQueue>,
    archives: Res<Assets<Archive>>,
    asset_server: Res<AssetServer>,
    mut materials: ResMut<Assets<ColorMaterial>>,
    mut commands: Commands,
    mut extracted: Local<bool>,
) {
    if *extracted {
        return;
    }

    for (archive_path, entry_name) in queue.0.drain(..) {
        // Get archive handle (using path as label)
        let archive_handle = asset_server.get_handle::<Archive>(&archive_path);

        if let Some(archive) = archives.get(&archive_handle) {
            if let Some(&(offset, size)) = archive.index.get(&entry_name) {
                // LAZY EXTRACTION: Only decode THIS entry now
                if offset + size <= archive.raw_data.len() {
                    let entry_data = &archive.raw_data[offset..offset + size];

                    // Example: Handle as text (for demo)
                    if entry_name.ends_with(".txt") {
                        if let Ok(text) = std::str::from_utf8(entry_data) {
                            info!("✨ Lazy-loaded text from archive: '{}'", text.trim());
                            *extracted = true;
                            continue;
                        }
                    }

                    // Example: Handle as PNG image (real-world use case)
                    if entry_name.ends_with(".png") {
                        if let Ok(image) = bevy::image::Image::from_buffer(
                            entry_data,
                            bevy::image::ImageType::Extension("png"),
                        ) {
                            let image_handle = materials.add(image.into());
                            // Spawn sprite with extracted texture
                            commands.spawn(SpriteBundle {
                                sprite: Sprite {
                                    custom_size: Some(Vec2::new(100.0, 100.0)),
                                    ..default()
                                },
                                material: image_handle,
                                ..default()
                            });
                            info!("✨ Lazy-loaded texture '{}' from archive", entry_name);
                            *extracted = true;
                            continue;
                        }
                    }

                    warn!("Unsupported entry type or invalid data: {}", entry_name);
                } else {
                    error!("Entry offset out of bounds: {}", entry_name);
                }
            } else {
                error!("Entry not found in archive: {}", entry_name);
            }
        } else {
            // Archive not loaded yet - requeue for next frame
            queue.0.push((archive_path, entry_name));
        }
    }
}

// ========================================
// ARCHIVE GENERATION (for self-contained demo)
// ========================================

fn generate_test_archive(assets_dir: &PathBuf) -> Result<()> {
    let archive_path = assets_dir.join("test.lazyarchive");
    if archive_path.exists() {
        return Ok(());
    }

    // Create minimal archive with:
    // - 1 text entry ("test.txt")
    // - 1 tiny PNG entry (1x1 red pixel) for texture demo
    let header = "2\n";
    let text_entry = "test.txt 28 12\n"; // Offset 28 = len(header + text_entry + png_entry_line)
    let png_entry = "pixel.png 47 80\n"; // Offset 47 = 28 + len(png data header)

    // Tiny 1x1 red PNG (80 bytes)
    let png_data: [u8; 80] = [
        0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A, 0x00, 0x00, 0x00, 0x0D, 0x49, 0x48, 0x44, 0x52,
        0x00, 0x00, 0x00, 0x01, 0x00, 0x00, 0x00, 0x01, 0x08, 0x02, 0x00, 0x00, 0x00, 0x90, 0x77, 0x53,
        0xDE, 0x00, 0x00, 0x00, 0x0C, 0x49, 0x44, 0x41, 0x54, 0x78, 0x9C, 0x62, 0x62, 0x62, 0x62,
        0x00, 0x00, 0x00, 0xFF, 0xFF, 0x03, 0x00, 0x00, 0x06, 0x00, 0x05, 0x7F, 0xA5, 0x7F, 0x00,
        0x00, 0x00, 0x00, 0x49, 0x45, 0x4E, 0x44, 0xAE, 0x42, 0x60, 0x82,
