// ========================================
// MAIN APP
// ========================================

fn main() {
    // Generate test archive in assets folder (self-contained demo)
    let manifest_dir = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    let assets_dir = manifest_dir.join("assets");
    generate_test_archive(&assets_dir).expect("Failed to generate test archive");

