fn main() -> io::Result<()> {
    // Spawn PTY with minimal shell (works on macOS)
    let mut session = Session::spawn_command(
        std::process::Command::new("/bin/bash")
            .arg("--norc")
            .arg("--noprofile"),
    )
    .expect("Failed to spawn bash");

