    session
        .set_nonblocking(true)
        .expect("Failed to set non-blocking mode");

    // Channel for safe cross-thread communication
    let (tx, rx) = channel::<String>();

    // Dedicated I/O thread owns the Session (no mutex needed)
    let io_thread = thread::spawn(move || {
        let mut session = session; // Take ownership
        let mut buf = [0u8; 4096];

        loop {
            // Process ALL pending writes first
            while let Ok(data) = rx.try_recv() {
                if let Err(e) = session.send(&data) {
                    if let Some(io_err) = e.io_error() {
                        // Handle non-blocking write contention
                        if io_err.kind() == std::io::ErrorKind::WouldBlock {
                            eprintln!("[PTY] Write blocked (buffer full), retrying next cycle");
                            // Re-queue unwritten data (critical for reliability)
                            let _ = rx.send(data);
                            thread::sleep(Duration::from_millis(1));
                        } else {
                            eprintln!("[PTY] Write error: {}", io_err);
                            return Err(io::Error::new(io_err.kind(), "PTY write failed"));
                        }
                    } else {
                        eprintln!("[PTY] Non-IO write error: {}", e);
                        return Err(io::Error::new(io::ErrorKind::Other, "PTY write failed"));
                    }
                }
            }

            // Non-blocking read attempt
            match session.read(&mut buf) {
                Ok(n) if n > 0 => {
                    io::stdout().write_all(&buf[..n])?;
                    io::stdout().flush()?;
                }
                Ok(_) => {
                    println!("\n[PTY] Session closed by child process");
                    break;
                }
                Err(e) => {
                    if let Some(io_err) = e.io_error() {
                        if io_err.kind() == std::io::ErrorKind::WouldBlock {
                            // Yield CPU when no data available
                            thread::sleep(Duration::from_millis(5));
                        } else {
                            eprintln!("[PTY] Read error: {}", io_err);
                            break;
                        }
                    } else {
                        eprintln!("[PTY] Non-IO read error: {}", e);
                        break;
                    }
                }
            }
        }
        Ok(())
    });

    println!("PTY session active. Type commands below.");
    println!("Type 'exit' to terminate the shell session.\n");

    // Main thread handles user input
    let mut input = String::new();
    loop {
        input.clear();
        print!("$ ");
        io::stdout().flush()?;

        match io::stdin().read_line(&mut input) {
            Ok(0) => break,
            Ok(_) => {
                // Forward input to PTY thread (including newline)
                if tx.send(input.clone()).is_err() {
                    break; // Channel closed
                }
                if input.trim() == "exit" {
                    break;
                }
            }
            Err(e) => {
                eprintln!("Input error: {}", e);
                break;
            }
        }
    }

    // Cleanup
    println!("\nShutting down PTY session...");
    drop(tx); // Close channel to signal thread
    let _ = io_thread.join();
    println!("PTY session terminated.");
    Ok(())
}
