    fn meta(&self) -> ResourceMeta;
    fn group(dynamic_type: &Self::DynamicType) -> Cow<str>;
    fn kind(dynamic_type: &Self::DynamicType) -> Cow<str>;
}

pub struct ResourceMeta {
    pub name: Option<String>,
}

// Example resource implementation
#[derive(Debug, Clone)]
struct ExampleResource {
    name: String,
}

#[derive(Debug, Clone, Default)]
struct ExampleDynamicType;

impl Resource for ExampleResource {
    type DynamicType = ExampleDynamicType;

    fn meta(&self) -> ResourceMeta {
        ResourceMeta {
            name: Some(self.name.clone()),
        }
    }

    fn group(_dt: &ExampleDynamicType) -> Cow<str> {
        Cow::Borrowed("apps") // Simulates crate-provided borrowed string
    }

    fn kind(_dt: &ExampleDynamicType) -> Cow<str> {
        Cow::Borrowed("deployments") // Simulates crate-provided borrowed string
    }
}

// FIXED: Removed lifetime parameter and store owned strings
// This avoids self-referential struct issues while maintaining safety
#[derive(Debug, Clone)]
pub struct ResourceRef<R: Resource>
where
    R::DynamicType: Default,
{
    type_: PhantomData<R>,
    dynamic_type: R::DynamicType,
    group: Option<String>,
    kind: String,
    name: String,
}

impl<R: Resource> ResourceRef<R>
where
    R::DynamicType: Default,
{
    pub fn new(resource: R) -> Self {
        let name = resource
            .meta()
            .name
            .as_deref()
            .expect("Resource must have a name");
        Self::new_named(name)
    }

    pub fn new_named(name: &str) -> Self {
        let dynamic_type = R::DynamicType::default();

        // Convert Cows to owned strings immediately
        // Solves lifetime issue: no references to local `dynamic_type`
        let group_cow = R::group(&dynamic_type);
        let kind_cow = R::kind(&dynamic_type);

        let group = if group_cow.is_empty() {
            None
        } else {
            Some(group_cow.into_owned())
        };
        let kind = kind_cow.into_owned();

        Self {
            type_: PhantomData,
            dynamic_type,
            group,
            kind,
            name: name.to_string(),
        }
    }

    pub fn group(&self) -> Option<&str> {
        self.group.as_deref()
    }

    pub fn kind(&self) -> &str {
        &self.kind
    }

    pub fn name(&self) -> &str {
        &self.name
    }
}

fn main() {
    // Test 1: Create via new_named (avoids local variable lifetime issue)
    let ref1 = ResourceRef::<ExampleResource>::new_named("web-server");
    println!("Created via new_named:");
    println!("  Name: {}", ref1.name());
    println!("  Kind: {}", ref1.kind());
    println!("  Group: {:?}\n", ref1.group());

    // Test 2: Create via new (validates full workflow)
    let resource = ExampleResource {
        name: "db-primary".to_string(),
    };
    let ref2 = ResourceRef::new(resource);
    println!("Created via new:");
    println!("  Name: {}", ref2.name());
    println!("  Kind: {}", ref2.kind());
    println!("  Group: {:?}\n", ref2.group());

    // Verify no lifetime errors occur during usage
    println!("Success! No lifetime errors. Struct stores owned data safely.");
}"
}

