use radiate::tree::{NodeType, Op};
use rand::SeedableRng;
use rand_xoshiro::Xoshiro256PlusPlus;

fn main() {
    // Define custom operator: sqrt(max(x, 0)) + 1.0 (safe for negative inputs)
    let sqrtplusone = Op::custom(
        "sqrtplusone".to_string(),
        Box::new(|args| {
            let x = args[0].max(0.0); // Prevent NaN from negative sqrt
            x.sqrt() + 1.0
        }),
        1, // Arity: 1 argument
    );

    // Create dataset: approximate f(x) = x^2 + x + 1.0 for x in [0.0, 0.9]
    let dataset: Vec<(Vec<f64>, f64)> = (0..10)
        .map(|i| {
            let x = i as f64 * 0.1;
            let y = x * x + x + 1.0;
            (vec![x], y)
        })
        .collect();

    // Configure operator store with custom operator
    let store = vec![
        (
            NodeType::Vertex,
            vec![
                Op::add(),
                Op::sub(),
                Op::mul(),
                Op::pow(),
                sqrtplusone, // Include custom operator here
            ],
        ),
        (
            NodeType::Leaf,
            vec![
                Op::var(0),      // Input variable x0
                Op::constant(1.0),
                Op::constant(2.0),
            ],
        ),
    ];

    // Initialize RNG with fixed seed for reproducibility
    let seed = [0u8; 32];
    let mut rng = Xoshiro256PlusPlus::from_seed(seed);

    // Create population (100 individuals, max depth 4)
    let mut population = Population::new(
        &mut rng,
        &store,
        100,
        4,
        dataset.len(),
    );
    population.set_objective(Objective::Minimize);

    // Evolve for 10 generations
    for gen in 0..10 {
        population.evolve(&mut rng, &dataset, 0.1, 0.9, 0.1);
        if let Some(best) = population.best() {
            println!(
                "Generation {}: Fitness = {:.6}",
                gen,
                best.fitness().unwrap_or(f64::INFINITY)
            );
        }
    }

    // Display final result
