        println!("\nBest solution found:");
        println!("Expression: {}", best);
        println!("Fitness (MSE): {:.8}", best.fitness().unwrap_or(f64::INFINITY));

        // Verify custom operator usage
        let contains_custom = format!("{}", best).contains("sqrtplusone");
        println!("Uses custom operator: {}", if contains_custom { "YES" } else { "no" });
    }
}
