use std::future::Future;
use std::pin::Pin;

/// Context shared with async workloads
pub struct Context(i32);

/// Event carrying async work to execute with Context
pub enum InnerAsyncEvent {
    DoWithContext {
        block: Box<
            dyn for<'a> Fn(
                &'a mut Context,
            ) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
                + Send,
        >,
    },
}

/// Macro to cleanly wrap async logic for Context
///
/// Usage: `async_context_block!(|ctx| { /* async body */ })`
/// - Captured variables must be `Send`
/// - Body executes in an async block with mutable Context access
macro_rules! async_context_block {
    (|$ctx:ident| $($body:tt)*) => {
        Box::new(move |$ctx: &mut Context| {
            Box::pin(async move { $($body)* })
        })
    };
}

/// Helper to send async work to worker thread
pub fn with_context_async(
    work_sender: &mut Sender<InnerAsyncEvent>,
    block: Box<
        dyn for<'a> Fn(&'a mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
            + Send,
    >,
) {
    let _ = work_sender.send(InnerAsyncEvent::DoWithContext { block });
}

#[tokio::main]
async fn main() {
    let (mut tx, mut rx) = mpsc::channel(10);

    // Example 1: Using helper function + macro (clean syntax)
    with_context_async(&mut tx, async_context_block!(|ctx| {
        ctx.0 += 1;
        println!("[Worker] Incremented: {}", ctx.0);
    }));

    // Example 2: Direct event construction with macro
    let event = InnerAsyncEvent::DoWithContext {
        block: async_context_block!(|ctx| {
            tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
            ctx.0 *= 2;
            println!("[Worker] Doubled: {}", ctx.0);
        }),
    };
    tx.send(event).await.unwrap();

    // Example 3: Capturing Send-able environment variables
    let multiplier = 3;
    with_context_async(&mut tx, async_context_block!(|ctx| {
        ctx.0 *= multiplier;
        println!("[Worker] Multiplied by {}: {}", multiplier, ctx.0);
    }));

    drop(tx); // Close channel

    // Worker thread processing events
    tokio::spawn(async move {
        let mut ctx = Context(0);
        println!("[Worker] Starting with context value: {}", ctx.0);

        while let Some(event) = rx.recv().await {
            match event {
                InnerAsyncEvent::DoWithContext { block } => {
                    block(&mut ctx).await;
                }
            }
        }

        println!("[Worker] Final context value: {}", ctx.0);
    })
    .await
    .unwrap();

    println!("[Main] All work completed!");
}"
}

