  "main.rs": "use azure_core::new_http_client;
use azure_storage_blobs::prelude::*;
use azure_storage_blobs::clients::ContainerClient;
use reqwest::Client as ReqwestClient;
use serde::{Deserialize, Serialize};
use std::env;
use std::sync::Arc;
use tracing::{info, warn};

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TradeData {
    // Minimal fields to match typical trade JSON structure
    // Adjust fields to match your actual AzureRawTradeData schema
    pub id: String,
    pub symbol: String,
    pub price: f64,
    pub quantity: f64,
    pub timestamp: String,
}

#[derive(Serialize)]
struct TokenRequest<'a> {
    grant_type: &'a str,
    client_id: &'a str,
    client_secret: &'a str,
    scope: &'a str,
}

#[derive(Deserialize)]
struct TokenResponse {
    access_token: String,
}

const CONCURRENCY_LIMIT: usize = 64; // Optimized for I/O-bound operations

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Initialize logging
    tracing_subscriber::fmt()
        .with_env_filter(tracing_subscriber::EnvFilter::from_default_env())
        .init();

    dotenv::dotenv().ok();

    match fetch_trades_from_azure_optimized().await {
        Ok(trades) => {
            info!("Successfully downloaded {} trades", trades.len());
            Ok(())
        }
        Err(e) => {
            eprintln!("Fatal error: {}", e);
            std::process::exit(1);
        }
    }
}

async fn get_oauth_token(
    tenant_id: &str,
    client_id: &str,
    client_secret: &str,
) -> Result<String, Box<dyn std::error::Error>> {
    let token_url = format!("https://login.microsoftonline.com/{}/oauth2/v2.0/token", tenant_id);
    let params = TokenRequest {
        grant_type: "client_credentials",
        client_id,
        client_secret,
        scope: "https://storage.azure.com/.default",
    };

    // Reuse shared client from main pipeline
    let client = ReqwestClient::builder()
        .pool_max_idle_per_host(100)
        .build()?;

    let res = client
        .post(&token_url)
        .form(&params)
        .send()
        .await?;

    let status = res.status();
    let body = res.text().await?;

    if !status.is_success() {
        return Err(format!("Token request failed: {} - {}", status, body).into());
    }

    let token_res: TokenResponse = serde_json::from_str(&body)?;
    Ok(token_res.access_token)
}

async fn list_blob_names(
    container_client: &ContainerClient,
    prefix: &str,
) -> Result<Vec<String>, Box<dyn std::error::Error>> {
    let start = std::time::Instant::now();
    let mut names = Vec::new();
    let mut stream = container_client.list_blobs().prefix(prefix.to_string()).into_stream();

    while let Some(response) = stream.next().await {
        let page = response?;
        for blob in page.blobs.blobs() {
            if blob.name.ends_with(".json") {
                names.push(blob.name.clone());
            }
        }
    }

    info!("Listed {} blobs for prefix '{}' in {:.2}s", 
          names.len(), prefix, start.elapsed().as_secs_f32());
    Ok(names)
}

async fn process_blob(
    container_client: Arc<ContainerClient>,
    blob_name: String,
) -> Option<TradeData> {
    let blob_client = container_client.blob_client(&blob_name);

    match blob_client.get_content().await {
        Ok(data) => {
            match serde_json::from_slice::<TradeData>(&data) {
                Ok(trade) => Some(trade),
                Err(e) => {
                    warn!("JSON parse failed for {}: {}", blob_name, e);
                    None
                }
            }
        }
        Err(e) => {
            warn!("Download failed for {}: {}", blob_name, e);
            None
        }
    }
}

pub async fn fetch_trades_from_azure_optimized() -> Result<Vec<TradeData>, Box<dyn std::error::Error>> {
    let total_start = std::time::Instant::now();
    info!("Starting optimized Azure blob download");

    // Load environment variables
    let tenant_id = env::var("AZURE_TENANT_ID")?;
    let client_id = env::var("AZURE_CLIENT_ID")?;
    let client_secret = env::var("AZURE_CLIENT_SECRET")?;
    let storage_account = env::var("AZURE_ACCOUNT_NAME")?;
    let container_name = env::var("AZURE_CONTAINER_NAME")?;
    let prefix_opt = env::var("AZURE_PREFIX_OPT")?;
    let prefix_fut = env::var("AZURE_PREFIX_FUT")?;

    // Get token
    let auth_start = std::time::Instant::now();
    let token = get_oauth_token(&tenant_id, &client_id, &client_secret).await?;
    info!("Authentication completed in {:.2}s", auth_start.elapsed().as_secs_f32());

    // Create optimized pipeline with shared HTTP client
    let http_client = new_http_client();
    let credentials = azure_storage::StorageCredentials::bearer_token(token);
    let blob_service = BlobServiceClient::new_with_http_client(
        storage_account,
        credentials,
        http_client,
    );
    let container_client = blob_service.container_client(container_name);

    // List ALL blob names first (critical optimization)
    let list_start = std::time::Instant::now();
    let (blobs_opt, blobs_fut) = futures::join!(
        list_blob_names(&container_client, &prefix_opt),
        list_blob_names(&container_client, &prefix_fut),
    );
    let mut all_blobs = blobs_opt?;
    all_blobs.extend(blobs_fut?);
    info!("Total blobs to process: {} (listed in {:.2}s)", 
          all_blobs.len(), list_start.elapsed().as_secs_f32());

    // Process ALL blobs with controlled concurrency (critical optimization)
    let download_start = std::time::Instant::now();
    let container_ref = Arc::new(container_client);

    let trades: Vec<TradeData> = futures::stream::iter(all_blobs)
        .map(|name| {
            let client = container_ref.clone();
            async move { process_blob(client, name).await }
        })
        .buffer_unordered(CONCURRENCY_LIMIT)
        .filter_map(|x| async { x })
        .collect()
        .await;

    info!("Downloaded and parsed {} trades in {:.2}s", 
          trades.len(), download_start.elapsed().as_secs_f32());
    info!("TOTAL EXECUTION TIME: {:.2}s", total_start.elapsed().as_secs_f32());

    Ok(trades)
}"
}

