  "Cargo.toml": "[package]
name = "try_poll_example"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["full"] }
futures = "0.3"",
  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll};

/// Result of attempting to poll a future synchronously
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Attempts to poll a future *once* in the current context.
/// 
/// # Safety
/// - Uses a no-op waker. Only safe for futures that:
///   1. Don't require waking after returning Pending (we move pending futures to a new task)
///   2. Overwrite registered wakers on subsequent polls (true for most well-behaved futures)
/// - Caller MUST handle Pending case by moving future to new task
/// - Future MUST be Unpin (required for safe pinning via Pin::new)
fn try_poll<F>(future: &mut F) -> TryPollResult<F::Output>
where
    F: Future + Unpin,
{
    // Use no-op waker: safe because pending futures are moved to new task with proper waker
    let waker = futures::task::noop_waker_ref();
    let mut cx = Context::from_waker(waker);

    match Pin::new(future).poll(&mut cx) {
        Poll::Ready(output) => TryPollResult::Ready(output),
        Poll::Pending => TryPollResult::Pending,
    }
}

#[tokio::main]
async fn main() {
    println!("=== Example 1: Immediately ready future ===");
    let mut immediate_future = async { 42 };

    match try_poll(&mut immediate_future) {
        TryPollResult::Ready(val) => println!("✅ Got value synchronously: {}", val),
        TryPollResult::Pending => println!("❌ Unexpected pending state"),
    }

    println!("\n=== Example 2: Pending future (sleep) ===");
    let mut sleep_future = tokio::time::sleep(tokio::time::Duration::from_millis(50));

    match try_poll(&mut sleep_future) {
        TryPollResult::Ready(_) => println!("❌ Sleep completed immediately (unexpected)"),
        TryPollResult::Pending => {
            println!("⏳ Future not ready - spawning task to handle");
            tokio::spawn(async move {
                sleep_future.await;
                println!("✅ Sleep completed in spawned task");
            });
        }
    }

    // Allow time for spawned task to complete
    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
    println!("\n✅ Main function completed successfully");
}"
}

