fn yield_signals(shutdown: Arc<AtomicBool>, sender: Sender<Message>) {
    // Create signal iterator (may fail if signals already registered)
    let mut signals = match Signals::new(&[SIGINT, SIGTERM]) {
        Ok(s) => s,
        Err(e) => {
            eprintln!("Failed to register signals: {}", e);
            return;
        }
    };

    loop {
        // Check shutdown flag FIRST to minimize delay
        if shutdown.load(Ordering::Relaxed) {
            break;
        }

        // Non-blocking check for pending signals
        for sig in signals.pending() {
            if sender.send(Message::Signal(sig)).is_err() {
                // Receiver dropped, exit cleanly
                shutdown.store(true, Ordering::Relaxed);
                return;
            }
            // Immediately trigger shutdown on SIGINT/SIGTERM
            if sig == SIGINT || sig == SIGTERM {
                let _ = sender.send(Message::Quit);
            }
        }

        // Short sleep to avoid busy-waiting while remaining responsive
        thread::sleep(Duration::from_millis(10));
