/// Computes local-space rotation to align gizmo (+Z normal) with specified cube face
fn get_face_rotation(local_normal: Vec3) -> Quat {
    // Round to nearest cardinal axis with sign
    let abs_normal = local_normal.abs();
    let axis = if abs_normal.x > abs_normal.y && abs_normal.x > abs_normal.z {
        Vec3::X * local_normal.x.signum()
    } else if abs_normal.y > abs_normal.z {
