    match axis {
        Vec3 { x: 1.0, y: 0.0, z: 0.0 } => Quat::from_rotation_y(-std::f32::consts::FRAC_PI_2), // +X face
        Vec3 { x: -1.0, y: 0.0, z: 0.0 } => Quat::from_rotation_y(std::f32::consts::FRAC_PI_2),  // -X face
