use tower_http::cors::CorsLayer;
use std::net::SocketAddr;

/// Handler for WebSocket connections (origin already validated by middleware)
async fn client_handler(ws: WebSocketUpgrade, Path(_session_id): Path<String>) -> impl IntoResponse {
    ws.on_upgrade(|socket| async {
        handle_socket(socket).await;
    })
}

/// Minimal WebSocket handler logic
async fn handle_socket(mut socket: WebSocket) {
    let _ = socket.send(Message::Text("Connected".to_string())).await;
    let _ = socket.close().await;
}

/// Middleware to validate Origin header for WebSocket routes
async fn check_origin(
    req: Request<Body>,
    next: Next,
) -> Result<Response, StatusCode> {
    // Get Origin header value
    let origin = req.headers().get("origin");

    // Validate against allowed origin (exact match)
    if let Some(origin_val) = origin {
        // HeaderValue implements PartialEq<&str> - safe for ASCII origins
        if origin_val == "https://www.example.com" {
            return Ok(next.run(req).await);
        }
    }

    // Reject invalid/missing origin
    Err(StatusCode::FORBIDDEN)
}

#[tokio::main]
async fn main() {
    // Build router with:
    // 1. Origin validation middleware applied ONLY to WebSocket route
    // 2. CORS layer for non-WebSocket routes (doesn't affect WS)
    let app = Router::new()
        .route(
            "/client/:session_id",
            get(client_handler).layer(middleware::from_fn(check_origin))
        )
        .layer(
            CorsLayer::new()
