    println!("WebSocket endpoint: ws://localhost:3000/client/test");
    println!("Valid origin: https://www.example.com");
    println!("Invalid origin test: Use browser devtools to modify Origin header");

    axum::Server::bind(&addr)
        .serve(app.into_make_service())
        .await
        .unwrap();
}"
