native-pty = "0.10.0"
nix = "0.29.0"
libc = "0.2.155"

# Tauri dependencies (minimal for backend demonstration)
tauri = { version = "2.0.0-rc", features = ["unstable"] }
serde = "1.0.203"
serde_json = "1.0.117"

# Async runtime for non-blocking I/O handling
# (Required for Tauri v2's async command execution)
tokio = { version = "1.38.0", features = ["full"] }

