[profile.release]
opt-level = 3
lto = true",
  "main.rs": "//! Tauri PTY Concurrency Solution
//! Demonstrates safe full-duplex PTY communication using FD splitting
//! and async channels to avoid mutex contention during blocking I/O.
//!
//! Run with: cargo run
//! Test by typing in terminal or waiting for auto-sent commands.
//!
//! Key solution elements:
//! 1. Split PTY master FD into dedicated read/write handles
//! 2. Non-blocking I/O with readiness polling (no mutex during I/O)
//! 3. Async writer channel to prevent Tauri command blocking
//! 4. Dedicated reader thread with edge-triggered readiness checks
//! 5. Proper FD lifecycle management

use std::{
    fs::File,
    io::{Read, Write},
    os::unix::io::{AsRawFd, FromRawFd, RawFd},
    sync::Arc,
    time::Duration,
};

use flume::{bounded, Receiver, Sender};
use native_pty::{openpty, Child};
use nix::{
    fcntl::{fcntl, FcntlArg, OFlag},
    unistd::{dup, close},
};
use tauri::{Emitter, Manager};

/// Configure FD for non-blocking operation
fn set_nonblocking(fd: RawFd) -> nix::Result<()> {
    let flags = fcntl(fd, FcntlArg::F_GETFL)?;
    let flags = OFlag::from_bits_truncate(flags) | OFlag::O_NONBLOCK;
    fcntl(fd, FcntlArg::F_SETFL(flags))?;
    Ok(())
}

/// Split PTY master into independent read/write handles
fn split_pty_master(master: Box<dyn native_pty::MasterPty>) -> (File, File) {
    unsafe {
        let raw_fd = master.as_raw_fd();
        // Duplicate FDs before master is dropped
        let read_fd = dup(raw_fd).expect("Failed to dup read FD");
        let write_fd = dup(raw_fd).expect("Failed to dup write FD");

        // Configure both FDs as non-blocking
        set_nonblocking(read_fd).expect("Failed to set read FD non-blocking");
        set_nonblocking(write_fd).expect("Failed to set write FD non-blocking");

        // Original master FD closes when dropped, duplicates remain valid
        drop(master);

        // Convert to owned File handles
        (File::from_raw_fd(read_fd), File::from_raw_fd(write_fd))
    }
}

/// PTY Agent managing full-duplex communication
struct PtyAgent {
    _child: Child, // Keep child alive
    writer_tx: Sender<String>,
}

impl PtyAgent {
    fn new(app_handle: tauri::AppHandle) -> Self {
        // Open PTY and configure child process
        let pair = openpty(None, None).expect("Failed to open PTY");

        // Configure child command (using cat for predictable echo behavior)
        let mut cmd = std::process::Command::new("/bin/cat");
        cmd.env("TERM", "xterm-256color");

        // Spawn child attached to PTY slave
        let child = pair
            .slave
            .spawn_command(&mut cmd)
            .expect("Failed to spawn child");

        // Split master FD into dedicated read/write handles
        let (read_file, write_file) = split_pty_master(pair.master);

        // Create async channel for writes (prevents Tauri command blocking)
        let (writer_tx, writer_rx) = bounded(100);

        // ===== READER THREAD =====
        // Dedicated thread for reading PTY output
        // * No mutex held during I/O operations
        // * Non-blocking reads with readiness checks
        // * Direct event emission to frontend
        std::thread::spawn(move || {
            let mut buf = [0u8; 4096];
            let mut read_file = read_file;

            loop {
                match read_file.read(&mut buf) {
                    Ok(0) => break, // EOF - child terminated
                    Ok(n) => {
                        let output = String::from_utf8_lossy(&buf[..n]).to_string();
                        // Emit directly to frontend (thread-safe)
                        let _ = app_handle.emit("agent-output", output);
                    }
                    Err(ref e) if e.kind() == std::io::ErrorKind::WouldBlock => {
                        // No data available - yield CPU
                        std::thread::sleep(Duration::from_millis(10));
                    }
                    Err(e) => {
                        eprintln!("PTY read error: {}", e);
                        break;
                    }
                }
            }
            let _ = app_handle.emit("agent-output", "[PTY session closed]\n");
        });

        // ===== WRITER THREAD =====
        // Dedicated thread for handling writes
        // * Processes commands from channel
        // * Non-blocking writes with retry logic
        // * Prevents Tauri command thread from blocking
        std::thread::spawn(move || {
            let mut write_file = write_file;

            for cmd in writer_rx {
                let mut bytes = cmd.as_bytes();
                while !bytes.is_empty() {
                    match write_file.write(bytes) {
                        Ok(n) => bytes = &bytes[n..],
                        Err(ref e) if e.kind() == std::io::ErrorKind::WouldBlock => {
                            std::thread::sleep(Duration::from_millis(5));
                        }
                        Err(e) => {
                            eprintln!("PTY write error: {}", e);
                            return;
                        }
                    }
                }
            }
        });

        PtyAgent {
            _child: child,
            writer_tx,
        }
    }

    /// Send data to PTY (non-blocking - returns immediately)
    fn send(&self, data: String) {
        // Channel send is non-blocking with bounded buffer
        // Drops command if buffer full (prevents deadlock)
        let _ = self.writer_tx.try_send(data);
    }
}

#[tauri::command]
async fn send_to_agent(
    message: String,
    state: tauri::State<'_, Arc<PtyAgent>>,
) -> Result<(), String> {
    state.send(message);
    Ok(())
}

fn main() {
    // Initialize PTY agent with app handle
    tauri::Builder::default()
        .setup(|app| {
            // Create agent and store in managed state
            let agent = Arc::new(PtyAgent::new(app.handle()));
            app.manage(agent);

