use std::sync::Arc;
use std::thread;

/// Simulates the replacement of atomic-polyfill::fetch_add using critical-section
/// Demonstrates correct usage of Ordering::Relaxed INSIDE critical section
fn fetch_add_relaxed(counter: &AtomicUsize) -> usize {
    critical_section::with(|_| {
        // Relaxed ordering is SAFE here because:
        // 1. Critical section provides full synchronization barriers at entry/exit
        // 2. No other thread/core can access counter during this section
        // 3. Critical section boundaries enforce visibility guarantees
        let old_val = counter.load(Ordering::Relaxed);
        counter.store(old_val + 1, Ordering::Relaxed);
        old_val
    })
}

fn main() {
    println!("=== Testing critical-section replacement for fetch_add ===\n");

    // Single-threaded correctness test
    let counter_single = AtomicUsize::new(10);
    assert_eq!(fetch_add_relaxed(&counter_single), 10);
    assert_eq!(fetch_add_relaxed(&counter_single), 11);
    assert_eq!(counter_single.load(Ordering::Relaxed), 12);
