/// Object-safe trait for remote repository actions
/// Key changes for dyn compatibility:
/// - Async methods replaced with boxed futures
/// - Path references changed to owned PathBuf to avoid lifetime issues in futures
/// - Futures explicitly require Send for thread safety
pub trait RemoteActions {
    fn change_path(
        &mut self,
        from: PathBuf,
        to: PathBuf,
    ) -> Pin<Box<dyn Future<Output = Result<()>> + Send>>;

    fn remove_repo(
