        path: PathBuf,
    ) -> Pin<Box<dyn Future<Output = Result<()>> + Send>>;

    fn get_element(&self, num: usize) -> Result<String>;
}

/// No-op strategy for testing (stateless)
#[derive(Default)]
struct NoopStrategy;

impl RemoteActions for NoopStrategy {
    fn change_path(
        &mut self,
        from: PathBuf,
        to: PathBuf,
    ) -> Pin<Box<dyn Future<Output = Result<()>> + Send>> {
        Box::pin(async move {
            println!("[NOOP] Would rename: {:?} -> {:?}", from, to);
            Ok(())
        })
    }

    fn remove_repo(
        &mut self,
        path: PathBuf,
    ) -> Pin<Box<dyn Future<Output = Result<()>> + Send>> {
        Box::pin(async move {
            println!("[NOOP] Would remove repo: {:?}", path);
            Ok(())
        })
    }

    fn add_repo(
        &mut self,
        path: PathBuf,
    ) -> Pin<Box<dyn Future<Output = Result<()>> + Send>> {
        Box::pin(async move {
            println!("[NOOP] Would add repo: {:?}", path);
            Ok(())
        })
    }

    fn get_element(&self, num: usize) -> Result<String> {
        Ok(format!("noop-element-{}", num))
    }
}

/// Production strategy (simulated with cloneable state)
struct ProductionStrategy {
    host: String,
}

impl ProductionStrategy {
    fn new(host: String) -> Self {
        Self { host }
    }
}

impl RemoteActions for ProductionStrategy {
    fn change_path(
        &mut self,
        from: PathBuf,
        to: PathBuf,
    ) -> Pin<Box<dyn Future<Output = Result<()>> + Send>> {
        let host = self.host.clone();
        Box::pin(async move {
            println!("[PROD] {}: Renaming {:?} -> {:?}", host, from, to);
            // Simulate async I/O
            tokio::time::sleep(tokio::time::Duration::from_millis(50)).await;
            Ok(())
        })
    }

    fn remove_repo(
        &mut self,
        path: PathBuf,
    ) -> Pin<Box<dyn Future<Output = Result<()>> + Send>> {
        let host = self.host.clone();
        Box::pin(async move {
            println!("[PROD] {}: Removing repo {:?}", host, path);
            tokio::time::sleep(tokio::time::Duration::from_millis(30)).await;
            Ok(())
        })
    }

    fn add_repo(
        &mut self,
        path: PathBuf,
    ) -> Pin<Box<dyn Future<Output = Result<()>> + Send>> {
        let host = self.host.clone();
        Box::pin(async move {
            println!("[PROD] {}: Adding repo {:?}", host, path);
            tokio::time::sleep(tokio::time::Duration::from_millis(30)).await;
            Ok(())
        })
    }

    fn get_element(&self, num: usize) -> Result<String> {
        if num < 5 {
            Ok(format!("prod-element-{}-on-{}", num, self.host))
        } else {
            Err(anyhow!("Invalid element index: {}", num))
        }
    }
}

#[tokio::main]
async fn main() -> Result<()> {
    println!("=== Testing with NoopStrategy (trait object) ===");
    let mut actions: Box<dyn RemoteActions> = Box::new(NoopStrategy::default());

    // Async methods via trait object
    actions.change_path("old/repo".into(), "new/repo".into()).await?;
    actions.remove_repo("stale/repo".into()).await?;
    actions.add_repo("fresh/repo".into()).await?;

    // Sync method
    println!("Element[0]: {}", actions.get_element(0)?);

    println!("\n=== Testing with ProductionStrategy (trait object) ===");
    let mut actions: Box<dyn RemoteActions> = Box::new(ProductionStrategy::new("git.internal".to_string()));

    actions.change_path("project-a".into(), "project-b".into()).await?;
    actions.remove_repo("deprecated".into()).await?;
    actions.add_repo("new-service".into()).await?;

    println!("Element[2]: {}", actions.get_element(2)?);

    // Demonstrate error handling
    match actions.get_element(99) {
        Ok(_) => println!("Unexpected success"),
        Err(e) => println!("Expected error: {}", e),
    }

    println!("\n✅ All dyn-compatible trait operations completed successfully!");
    Ok(())
}"
}

