  "main.rs": "use chrono::{DateTime, NaiveDateTime, Utc};

/// Parses LanceDB ISO date strings (with or without fractional seconds) to milliseconds since Unix epoch
fn date_string_to_int(d: &str) -> Result<i64, String> {
    // Try formats: with fractional seconds first (more specific), then without
    let formats = [
        "%Y-%m-%dT%H:%M:%S%.f", // Handles ".409", ".017", etc. (1-9 fractional digits)
        "%Y-%m-%dT%H:%M:%S",     // Handles strings without fractional seconds
    ];

    for format in &formats {
        if let Ok(ndt) = NaiveDateTime::parse_from_str(d, format) {
            // Convert to UTC DateTime (Unix timestamps are UTC-based)
            let dt: DateTime<Utc> = DateTime::from_utc(ndt, Utc);
            // Return total milliseconds since epoch (truncates sub-millisecond)
            return Ok(dt.timestamp_millis());
        }
    }

    Err(format!("Failed to parse date string: '{}'", d))
}

fn main() {
    let test_cases = vec![
        "1970-01-01T00:00:00",
        "2025-08-02T17:35:41.409",
        "2025-08-04T01:48:44.017",
        "2025-08-04T23:02:20.584",
        "2025-08-05T00:08:57.350",
        "2025-08-10T18:31:26.628",
    ];

    println!("Parsing LanceDB date strings to milliseconds since Unix epoch:\n");
    for case in test_cases {
        match date_string_to_int(case) {
            Ok(ts) => println!("✓ '{}' → {} ms", case, ts),
            Err(e) => println!("✗ '{}' → Error: {}", case, e),
        }
    }

    // Verify epoch value
    if let Ok(epoch) = date_string_to_int("1970-01-01T00:00:00") {
        println!("\nEpoch check: 1970-01-01T00:00:00 = {} ms (expected 0)", epoch);
    }
}"
