dioxus = { version = "0.7", features = ["web"] }
dioxus-web = "0.7"
",
  "main.rs": "use dioxus::prelude::*;
use dioxus::events::MouseEvent;

/// Context shared across draggable components
#[derive(Clone, Copy)]
struct DragContext {
    /// Current mouse position (x, y) in SVG coordinates
    current_mouse: Signal<(f64, f64)>,
    /// ID of currently dragged element (None = no active drag)
    dragged_id: Signal<Option<usize>>,
}

/// Provider component that captures global drag events
#[component]
fn DragProvider(children: Element) -> Element {
    let current_mouse = use_signal(|| (0.0, 0.0));
    let dragged_id = use_signal(|| None::<usize>);

    // Provide drag context to child components
    use_context_provider(|| DragContext {
        current_mouse,
        dragged_id,
    });

    rsx! {
        div {
            width: "100%",
            height: "100%",
            // Prevent text selection during drag
            style: "user-select: none; -webkit-user-select: none; touch-action: none;",

            // Global drag tracking events
            onmousemove: move |evt: MouseEvent| {
                if dragged_id.read().is_some() {
                    let coords = evt.element_coordinates();
                    current_mouse.set((coords.x, coords.y));
                }
            },
            onmouseup: move |_| {
                dragged_id.set(None);
            },
            onmouseleave: move |_| {
                dragged_id.set(None);
            },

            {children}
        }
    }
}

/// Draggable SVG point component
#[derive(Props, Clone, PartialEq)]
struct PointProps {
    id: usize,   // Unique identifier for drag tracking
    x: f64,      // Initial x position
    y: f64,      // Initial y position
    r: f64,      // Circle radius
}

#[component]
fn Point(props: PointProps) -> Element {
    // Local position state (only updated during drag)
    let mut pos = use_signal(|| (props.x, props.y));
    let drag_ctx = use_context::<DragContext>();
    let id = props.id;

    // Efficiently update position ONLY when this point is dragged
    // This effect only triggers re-renders for the actively dragged point
    use_effect(use_reactive!((drag_ctx.dragged_id, drag_ctx.current_mouse) => {
        if *drag_ctx.dragged_id.read() == Some(id) {
            pos.set(*drag_ctx.current_mouse.read());
        }
    }));

    rsx! {
        circle {
            cx: pos.read().0,
            cy: pos.read().1,
            r: props.r,
            fill: "#2563eb",
            stroke: "#1e40af",
            stroke_width: "0.5",
            // Start drag on mousedown
            onmousedown: move |evt: MouseEvent| {
                evt.prevent_default();
                drag_ctx.dragged_id.set(Some(id));
            },
            // Visual feedback
            onmouseenter: move |_| {},
            onmouseleave: move |_| {},
            cursor: "move",
        }
    }
}

/// Main application component
fn app() -> Element {
    rsx! {
        // Global styles for full viewport coverage
        style { {r#"
            html, body, #main {
                width: 100%;
                height: 100%;
                margin: 0;
                padding: 0;
                overflow: hidden;
            }
            svg {
                touch-action: none; /* Critical for touch devices */
            }
        "#} }

