                width: "100%",
                height: "100%",
                viewBox: "0 0 100 100",
                // Background to capture events across entire SVG
                rect {
                    width: "100%",
                    height: "100%",
                    fill: "#f3f4f6",
                    stroke: "#e5e7eb",
                    stroke_width: "0.5",
                }
                // Draggable points with unique IDs
                Point { id: 0, x: 30.0, y: 40.0, r: 4.0 }
                Point { id: 1, x: 70.0, y: 60.0, r: 4.0 }
                Point { id: 2, x: 50.0, y: 20.0, r: 4.0 }

                // Decorative grid
                g {
                    stroke: "#9ca3af",
                    stroke_width: "0.1",
                    opacity: "0.5",
                    for i in 0..=10 {
                        line { x1: "{i*10}", y1: "0", x2: "{i*10}", y2: "100" }
                        line { x1: "0", y1: "{i*10}", x2: "100", y2: "{i*10}" }
                    }
                }
            }
        }
    }
}

fn main() {
    // Launch web application
    dioxus_web::launch(app);
}
"
