    Int(i32),
    Binary {
        left: Box&lt;Expr&gt;,
        op: BinOp,
        right: Box&lt;Expr&gt;,
    },
}

fn parse_mul_op&lt;'a&gt;() -&gt; impl Parser&lt;'a, &amp;'a str, BinOp&gt; {
    just('*').to(BinOp::Mul)
        .or(just('/').to(BinOp::Div))
