impl<'a, T> ArrayViewMutIterator<'a, T> {
    /// Create iterator from array and dimension iterators
    ///
    /// # Safety
    /// Caller must ensure:
    /// - All generated cartesian indices are valid and unique
    /// - No aliasing occurs during iteration
    pub unsafe fn new<I>(
        array: &'a mut Array<T>,
        dim_iters: Vec<I>,
    ) -> Self
    where
        I: DimIterator,
    {
        // Precompute all linear indices upfront
        let mut linear_indices = Vec::new();
        let mut current: Vec<Option<usize>> = vec![None; dim_iters.len()];
        let mut iters: Vec<_> = dim_iters.into_iter().map(|it| it.clone()).collect();

        'outer: loop {
            // Advance first dimension
            current[0] = iters[0].next();

            // Handle carry-over for multi-dimensional iteration
            for i in 0..current.len() {
                if current[i].is_none() {
                    if i == current.len() - 1 {
                        break 'outer;
                    }
                    // Reset current dimension and advance next
                    iters[i] = dim_iters[i].clone();
                    current[i] = iters[i].next();
                    if i + 1 < current.len() {
                        current[i + 1] = iters[i + 1].next();
                    }
                } else {
                    break;
                }
            }

            // Convert valid cartesian index to linear index
            let cartesian: Vec<usize> = current.iter().map(|&x| x.unwrap()).collect();
            linear_indices.push(array.cartesian_to_linear(&cartesian));
        }

        ArrayViewMutIterator {
            data_ptr: array.store.as_mut_ptr(),
            linear_indices,
            current: 0,
            _phantom: PhantomData,
        }
    }
