  "main.rs": "use serde::Deserialize;
use serde_json::Value;
use std::error::Error;
use std::fs;
use std::path::{Path, PathBuf};

/// Resolve JSON Pointer (RFC 6901) - simplified implementation for this example
/// Handles object keys and array indices. Does NOT handle URL escaping (~0, ~1) for brevity.
fn get_by_pointer(value: &Value, pointer: &str) -> Result<Value, Box<dyn Error>> {
    if pointer.is_empty() {
        return Ok(value.clone());
    }

    // Split pointer tokens (skip leading empty token from "/")
    let tokens: Vec<&str> = pointer
        .split('/')
        .skip(1)
        .collect();

    let mut current = value;
    for token in tokens {
        current = match current {
            Value::Object(map) => map
                .get(token)
                .ok_or_else(|| format!("Key '{}' not found in JSON object", token))?,
            Value::Array(arr) => {
                let idx: usize = token
                    .parse()
                    .map_err(|_| format!("'{}' is not a valid array index", token))?;
                arr.get(idx)
                    .ok_or_else(|| format!("Array index {} out of bounds", idx))?
            }
            _ => return Err("Cannot traverse non-container JSON value".into()),
        };
    }
    Ok(current.clone())
}

/// Recursively resolve all `$ref` references in the JSON value
fn resolve_refs(value: &mut Value, base_dir: &Path) -> Result<(), Box<dyn Error>> {
    // Check if current node is a `$ref` object
    if let Value::Object(map) = value {
        if map.contains_key("$ref") {
            let ref_str = map
                .get("$ref")
                .and_then(|v| v.as_str())
                .ok_or("$ref value must be a string")?;

            // Split into file path and JSON pointer fragment
            let (file_path_str, json_pointer) = match ref_str.find('#') {
                Some(idx) => (&ref_str[..idx], &ref_str[idx + 1..]),
                None => (ref_str, ""),
            };

            // Resolve referenced file path
            let abs_ref_path = base_dir.join(file_path_str);
            let ref_content = fs::read_to_string(&abs_ref_path)
                .map_err(|e| format!("Failed to read referenced file '{}': {}", abs_ref_path.display(), e))?;
            let ref_doc: Value = serde_json::from_str(&ref_content)
                .map_err(|e| format!("Invalid JSON in '{}': {}", abs_ref_path.display(), e))?;

            // Extract value using JSON pointer
            let resolved_val = if json_pointer.is_empty() {
                ref_doc
            } else {
                get_by_pointer(&ref_doc, json_pointer)
                    .map_err(|e| format!("Pointer resolution failed in '{}': {}", abs_ref_path.display(), e))?
            };

            // Replace $ref object with resolved value
            *value = resolved_val;
            // Recursively resolve any nested $refs in the new value
            return resolve_refs(value, base_dir);
        }
    }

    // Traverse children for further resolution
    match value {
        Value::Object(map) => {
            for v in map.values_mut() {
                resolve_refs(v, base_dir)?;
            }
        }
        Value::Array(arr) => {
            for v in arr.iter_mut() {
                resolve_refs(v, base_dir)?;
            }
        }
        _ => {}
    }
    Ok(())
}

#[derive(Deserialize, Debug)]
struct A {
    path_list: Vec<PathBuf>,
}

fn main() -> Result<(), Box<dyn Error>> {
    // Read and parse b.json
    let b_content = fs::read_to_string("b.json")?;
    let mut json_value: Value = serde_json::from_str(&b_content)?;

    // Resolve all $ref references (using current dir as base)
    resolve_refs(&mut json_value, Path::new("."))?;

    // Deserialize resolved JSON into target struct
    let a_obj: A = serde_json::from_value(json_value)?;

    // Output resolved paths
    for path in &a_obj.path_list {
        println!("{}", path.display());
    }

    Ok(())
}"
}

