/// Returns:
/// - EventSender: for sending events (holds one sender clone)
/// - EventStreamFactory: for creating subscriber streams (holds original sender)
fn events_channel() -> (EventSender, EventStreamFactory) {
    let (tx, _) = broadcast::channel(10);
