#[derive(Debug, Clone)]
struct EventSender {
    tx: broadcast::Sender<Event>,
}

impl EventSender {
    fn send(&self, event: Event) {
        let _ = self.tx.send(event);
    }
}

#[derive(Clone)]
struct EventStreamFactory {
    tx: broadcast::Sender<Event>,
}

impl EventStreamFactory {
    /// Creates a stream of events for SSE clients
    /// Returns raw BroadcastStream - errors indicate channel closure or lag
    fn all_events(&self) -> BroadcastStream<Event> {
        BroadcastStream::new(self.tx.subscribe())
    }
}

