use serde::Deserialize;
use std::fmt;

#[derive(Debug)]
struct A {
    x: usize,
    b: Vec<B>,
}

#[derive(Debug)]
enum B {
    Number(u32),
}

// Custom deserializer for B (handles primitive numbers)
impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct BVisitor;
        impl<'de> Visitor<'de> for BVisitor {
            type Value = B;
            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("a number for B")
            }
            fn visit_u32<E>(self, v: u32) -> Result<Self::Value, E> {
                Ok(B::Number(v))
            }
            fn visit_u64<E>(self, v: u64) -> Result<Self::Value, E>
            where
                E: de::Error,
            {
                if v <= u32::MAX as u64 {
                    Ok(B::Number(v as u32))
                } else {
                    Err(E::custom("u64 value too large for u32"))
                }
            }
            // Handle signed integers that fit in u32
            fn visit_i64<E>(self, v: i64) -> Result<Self::Value, E>
            where
                E: de::Error,
            {
                if v >= 0 && v <= u32::MAX as i64 {
                    Ok(B::Number(v as u32))
                } else {
                    Err(E::custom("invalid number for B"))
                }
            }
        }
        // Deserialize any integer type into B
        deserializer.deserialize_any(BVisitor)
    }
}

// Custom deserializer for A (handles nested Vec<B>)
impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        // Helper enum for field identification (avoids stringly-typed keys)
        enum Field {
            X,
            B,
        }

        // Deserialize field names into Field enum
        impl<'de> Deserialize<'de> for Field {
            fn deserialize<D>(deserializer: D) -> Result<Field, D::Error>
            where
                D: Deserializer<'de>,
            {
                struct FieldVisitor;
                impl<'de> Visitor<'de> for FieldVisitor {
                    type Value = Field;
                    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                        formatter.write_str("\"x\" or \"b\"")
                    }
                    fn visit_str<E>(self, value: &str) -> Result<Field, E>
                    where
                        E: de::Error,
                    {
                        match value {
                            "x" => Ok(Field::X),
                            "b" => Ok(Field::B),
                            _ => Err(de::Error::unknown_field(value, &["x", "b"])),
                        }
                    }
                }
                deserializer.deserialize_identifier(FieldVisitor)
            }
        }

        struct AVisitor;
        impl<'de> Visitor<'de> for AVisitor {
            type Value = A;
            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("struct A with fields \"x\" and \"b\"")
            }

            fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut x = None;
                let mut b = None;

                while let Some(key) = map.next_key()? {
                    match key {
                        Field::X => {
                            if x.is_some() {
                                return Err(de::Error::duplicate_field("x"));
                            }
                            x = Some(map.next_value()?);
                        }
                        Field::B => {
                            if b.is_some() {
                                return Err(de::Error::duplicate_field("b"));
                            }
                            // Critical line: Deserialize Vec<B> using B's custom deserializer
                            // Serde automatically uses B's Deserialize impl for each element
                            b = Some(map.next_value()?);
                        }
                    }
                }

                // Ensure required fields are present
                let x = x.ok_or_else(|| de::Error::missing_field("x"))?;
                let b = b.ok_or_else(|| de::Error::missing_field("b"))?;
                Ok(A { x, b })
            }
        }

        // Start deserialization process for struct
        deserializer.deserialize_struct("A", &["x", "b"], AVisitor)
    }
}

fn main() {
    // Valid input: keys match Field enum variants exactly
    let json_data = r#"{"x": 42, "b": [10, 20, 30]}"#;

    match serde_json::from_str::<A>(json_data) {
        Ok(a) => println!("Success! Deserialized A: {:?}", a),
        Err(e) => eprintln!("Deserialization failed: {}", e),
    }

    // Demonstrate error handling for invalid key (addresses user's runtime error concern)
    let invalid_json = r#"{"x": 1, "B": [1]}"#; // Note capital 'B'
    match serde_json::from_str::<A>(invalid_json) {
        Ok(_) => {},
        Err(e) => println!("\nError with invalid key (case-sensitive): {}", e),
    }

    // Demonstrate B's custom deserializer handling different number types
    let mixed_numbers = r#"{"x": 100, "b": [5, 100000, -1]}"#;
    match serde_json::from_str::<A>(mixed_numbers) {
        Ok(a) => println!("\nMixed numbers handled: {:?}", a.b),
        Err(e) => println!("\nError with invalid number in B: {}", e),
    }
}"
}

