use nix::poll::{poll, PollFd, PollFlags};
use nix::unistd::dup;
use std::fs::File;
use std::io::{Read, Write};
use std::os::unix::io::{AsRawFd, FromRawFd};
use std::sync::{Arc, Mutex};
use std::thread;
use std::time::Duration;

/// Fixed Agent implementation demonstrating safe concurrent PTY access
/// Solves mutex contention by:
/// 1. Duplicating PTY master FD for dedicated reader thread
/// 2. Using non-blocking poll() instead of blocking read()
/// 3. Eliminating mutex dependency in reader path
struct Agent {
    session: Arc<Mutex<Session>>,
}

impl Agent {
    fn new() -> Result<Self, Box<dyn std::error::Error>> {
        // Spawn PTY with cat (simple echo program that waits for input)
        let (mut session, _child) = Session::spawn_command(
            std::process::Command::new("cat")
        )?;

        // CRITICAL FIX: Duplicate master FD BEFORE moving into mutex
        // This gives reader independent access without contending for session lock
        let master_fd = session.get_file_handle().as_raw_fd();
        let dup_fd = dup(master_fd)?;
        let read_file = unsafe { File::from_raw_fd(dup_fd) };

        let session_arc = Arc::new(Mutex::new(session));
        let session_clone = session_arc.clone();

        // Spawn dedicated reader thread with OWNED FD (no mutex required)
        thread::spawn(move || {
            let mut buf = [0u8; 1024];
            let fd = read_file.as_raw_fd();
            let mut poll_fds = vec![PollFd::new(fd, PollFlags::POLLIN | PollFlags::POLLHUP)];

            loop {
                // Efficiently wait for data WITHOUT blocking mutex
                if let Err(e) = poll(&mut poll_fds, -1) {
                    eprintln!("[READER] Poll error: {}", e);
                    break;
                }

                let revents = poll_fds[0].revents().unwrap_or(PollFlags::empty());

                // Handle hangup (process exited)
                if revents.contains(PollFlags::POLLHUP) {
                    println!("[READER] PTY closed by child process");
                    break;
                }

                // Only read when data is actually available
                if revents.contains(PollFlags::POLLIN) {
                    match read_file.read(&mut buf) {
                        Ok(0) => break, // EOF
                        Ok(n) => {
                            let output = String::from_utf8_lossy(&buf[..n]);
                            print!("[READER] {}", output);
                            std::io::stdout().flush().ok();
                        }
                        Err(e) if e.kind() == std::io::ErrorKind::WouldBlock => continue,
                        Err(e) => {
                            eprintln!("[READER] Read error: {}", e);
                            break;
                        }
                    }
                }
            }
            // read_file drops here, closing duplicated FD cleanly
        });

        Ok(Agent { session: session_clone })
    }

    /// Simulates Tauri command handler - minimal lock time
    fn send(&self, data: &str) -> Result<(), Box<dyn std::error::Error>> {
        // Mutex held ONLY for actual write operation (microseconds)
        // NOT held during PTY buffer wait or network latency
        let mut session = self.session.lock().unwrap();
        session.send(data)?;
        Ok(())
    }
}

