  "main.rs": "use std::future::Future;
use std::pin::Pin;
use tokio::sync::mpsc::{self, Sender};
use tokio::task;

/// Context type used in async operations
pub struct Context(i32);

/// Event carrying async work to execute with Context
pub enum InnerAsyncEvent {
    DoWithContext {
        block: Box<
            dyn for<'a> Fn(
                    &'a mut Context,
                ) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
                + Send,
        >,
    },
}

/// Helper function to send async work with minimal boilerplate
/// 
/// Takes ownership of a pre-wrapped async block (use `async_context_block!` macro)
fn send_with_context_async(
    sender: &mut Sender<InnerAsyncEvent>,
    block: Box<
        dyn for<'a> Fn(&'a mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>> + Send,
    >,
) {
    sender
        .send(InnerAsyncEvent::DoWithContext { block })
        .expect("Channel should be open");
}

/// Macro to cleanly wrap async logic for Context
/// 
/// Usage: `async_context_block!(ctx, { /* async code using ctx */ })`
/// Expands to properly boxed closure + future with correct lifetimes
macro_rules! async_context_block {
    ($ctx:ident, $body:expr) => {
        Box::new(move |$ctx: &mut Context| Box::pin(async move { $body }))
    };
}

#[tokio::main]
async fn main() {
    let (mut tx, mut rx) = mpsc::channel(10);

    // ✨ Clean usage: macro handles all boxing/lifetimes ✨
    send_with_context_async(
        &mut tx,
        async_context_block!(ctx, {
            // Real async work with Context
            tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
            ctx.0 += 1;
            println!("[Worker] Context updated to: {}", ctx.0);
        }),
    );

    // Spawn handler task (simulates worker thread)
    let handle = task::spawn(async move {
        if let Some(event) = rx.recv().await {
            let mut ctx = Context(42); // Initial value
            match event {
                InnerAsyncEvent::DoWithContext { block } => {
                    println!("[Handler] Starting work with initial value: {}", ctx.0);
                    block(&mut ctx).await;
                }
            }
            ctx
        } else {
            Context(-1)
        }
    });

    let result = handle.await.expect("Task should complete");
    println!("[Main] Final context value: {} (expected 43)", result.0);
    assert_eq!(result.0, 43, "Context should be incremented");
}
"
}

