{
  "Cargo.toml": "[package]
name = "rehydrate-span-example"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1.30", features = ["full"] }
tracing = "0.1"
tracing-subscriber = { version = "0.3", features = ["env-filter"] }
tracing-opentelemetry = "0.22"
opentelemetry = "0.22"
opentelemetry_sdk = "0.22"
opentelemetry-stdout = "0.15"",
  "main.rs": "use std::sync::Arc;
use std::time::Duration;
use opentelemetry::{global, KeyValue};
use opentelemetry_sdk::{
    export::trace::stdout::new_stdout_exporter,
    trace::{TracerProvider, Config},
    Resource,
};
use tracing::{info_span, Instrument};
use tracing_opentelemetry::OpenTelemetrySpanExt;
use tracing_subscriber::{layer::SubscriberExt, Registry};

/// Context holding parent span for propagation across async boundaries
#[derive(Clone)]
struct RequestContext {
    parent_span: tracing::Span,
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    // ===== SETUP TRACING WITH OPENTELEMETRY STDOUT EXPORTER =====
    // Configure OpenTelemetry SDK with stdout exporter
    let exporter = new_stdout_exporter();
    let provider = TracerProvider::builder()
        .with_simple_exporter(exporter)
        .with_config(
            Config::default().with_resource(Resource::new(vec![
                KeyValue::new("service.name", "pingora-proxy-example"),
                KeyValue::new("telemetry.sdk.name", "opentelemetry"),
            ])),
        )
        .build();

    // Create OpenTelemetry tracer
    let tracer = provider.tracer("tracing-opentelemetry");

    // Build tracing subscriber with OpenTelemetry layer
    let telemetry_layer = tracing_opentelemetry::layer().with_tracer(tracer);
    let subscriber = Registry::default().with(telemetry_layer);

    // Set global tracing subscriber
    tracing::subscriber::set_global_default(subscriber)?;

    // Ensure OpenTelemetry provider is shut down cleanly
    global::set_tracer_provider(provider.clone());

    // ===== SIMULATE REQUEST LIFECYCLE =====
    println!("\n=== Starting request lifecycle simulation ===\n");
    println!("Expected span hierarchy:");
    println!("|-- request (parent) ----------------------------------------|");
    println!("  |-- stage1 --|");
    println!("               |-- stage2 --|");
    println!("                            |-- upstream --|");
    println!("\nActual OpenTelemetry spans will appear below in JSON:\n");

    // Create parent span for entire request
    let parent_span = info_span!("request", method = "GET", path = "/api/data");

    // Store parent span in context for propagation
    let context = Arc::new(RequestContext {
        parent_span: parent_span.clone(),
    });

    // STAGE 1: Authentication
    let ctx1 = context.clone();
    let stage1 = async move {
        // Create child span with EXPLICIT parent reference
        let span = info_span!(parent: ctx1.parent_span.clone(), "stage1", stage = "auth");
        async move {
            tokio::time::sleep(Duration::from_millis(15)).await;
            tracing::info!("Validating authentication tokens");
            tokio::time::sleep(Duration::from_millis(10)).await;
        }
        .instrument(span)
        .await
    };

    // STAGE 2: Routing
    let ctx2 = context.clone();
    let stage2 = async move {
        let span = info_span!(parent: ctx2.parent_span.clone(), "stage2", stage = "routing");
        async move {
            tokio::time::sleep(Duration::from_millis(12)).await;
            tracing::info!("Determining upstream destination");
            tokio::time::sleep(Duration::from_millis(8)).await;
        }
        .instrument(span)
        .await
    };

    // UPSTREAM: Proxy to backend
    let ctx3 = context.clone();
    let upstream = async move {
        let span = info_span!(parent: ctx3.parent_span.clone(), "upstream", target = "backend-api");
        async move {
            tokio::time::sleep(Duration::from_millis(20)).await;
            tracing::info!("Forwarding request to upstream service");
            tokio::time::sleep(Duration::from_millis(15)).await;
            tracing::info!("Received response from upstream");
        }
        .instrument(span)
        .await
    };

    // Execute stages SEQUENTIALLY (simulating Pingora's stage execution)
    // Critical: Each stage uses .instrument() with span created from stored parent
    stage1.await;
    stage2.await;
    upstream.await;

    // Explicitly drop context to end parent span lifetime
    drop(context);

    // Allow time for spans to flush to stdout
    tokio::time::sleep(Duration::from_millis(100)).await;

    // Shutdown OpenTelemetry provider cleanly
    provider.shutdown();

    println!("\n=== Request lifecycle complete ===");
    println!("\n✅ Key implementation points:");
    println!("1. Parent span stored in context (Arc for Send/Sync)");
    println!("2. Each stage creates span with `parent: context.parent_span.clone()`");
    println!("3. Stage futures wrapped with `.instrument(span)`");
    println!("4. Parent span outlives all child spans via context cloning");
    println!("\n💡 For Pingora: Store RequestContext in your event context struct");
    println!("   and apply this pattern in each stage handler.");

    Ok(())
}"
}

