const fn generate_zobrist_seeds(seed: u64) -> [u64; 781] {
    // Prevent zero state (would lock PRNG)
    let mut state = if seed == 0 { 1 } else { seed };
    let mut result = [0u64; 781];
    let mut i = 0;
    while i < 781 {
        let (new_state, val) = xorshift64star_next(state);
        result[i] = val;
        state = new_state;
        i += 1;
    }
    result
}

// Fixed seed ensures identical values across all builds
pub static ZOBRIST_SEEDS: [u64; 781] = generate_zobrist_seeds(4174800045971885562);

fn main() {
    println!("Zobrist seeds (deterministic across builds):\n");
    println!("First 3 seeds:");
    for i in 0..3 {
        println!("  [{}] = 0x{:016x}", i, ZOBRIST_SEEDS[i]);
    }
    println!("\nMiddle seed [390]: 0x{:016x}", ZOBRIST_SEEDS[390]);
    println!("Last seed [780]:   0x{:016x}", ZOBRIST_SEEDS[780]);

    // Verification
    assert_eq!(ZOBRIST_SEEDS.len(), 781);
    println!("\n✅ Verified: {} seeds generated deterministically at compile time", ZOBRIST_SEEDS.len());
    println!("💡 Values remain identical across all builds with seed 4174800045971885562");
}"
}

