/// Converts LanceDB ISO date string (with or without fractional seconds) to milliseconds since UNIX epoch
fn date_string_to_int(d: &str) -> Result<i64, String> {
    // Try parsing with fractional seconds (requires literal dot before %f)
    if let Ok(ndt) = NaiveDateTime::parse_from_str(d, "%Y-%m-%dT%H:%M:%S.%f") {
        let dt: DateTime<Utc> = DateTime::from_utc(ndt, Utc);
        return Ok(dt.timestamp_millis());
    }
    // Try parsing without fractional seconds
    if let Ok(ndt) = NaiveDateTime::parse_from_str(d, "%Y-%m-%dT%H:%M:%S") {
        let dt: DateTime<Utc> = DateTime::from_utc(ndt, Utc);
        return Ok(dt.timestamp_millis());
    }
    Err(format!("Failed to parse date string: '{}'", d))
}

