        "2023-01-01T12:30:45.12",
        "2023-01-01T12:30:45.123456",
    ];

    println!("Converting LanceDB date strings to milliseconds since UNIX epoch:\n");
    for (i, date_str) in test_cases.iter().enumerate() {
