  "main.rs": "use bevy::{
    prelude::*,
    render::render_resource::{Extent3d, TextureDimension, TextureFormat, TextureUsages},
};
use std::{
    collections::HashMap,
    fs::{self, File},
    io::{Seek, SeekFrom, Write},
    path::Path,
    sync::Arc,
};
use anyhow::{Context, Result};
use memmap2::Mmap;

// ===== CUSTOM ASSET TYPE =====
#[derive(TypePath, Asset)]
struct LazyArchive {
    data: Arc<Mmap>,
    index: HashMap<String, (u64, u64)>, // name -> (offset, size)
}

// ===== CUSTOM ASSET LOADER =====
struct LazyArchiveLoader;

impl AssetLoader for LazyArchiveLoader {
    type Asset = LazyArchive;
    type Settings = ();
    type Error = anyhow::Error;

    fn load(&self, _: &[u8], load_context: &mut LoadContext) -> Result<Self::Asset, Self::Error> {
        // Get filesystem path (works for disk-based assets during development)
        let asset_path = load_context.path();
        let manifest_dir = Path::new(env!("CARGO_MANIFEST_DIR"));
        let asset_file_path = manifest_dir.join("assets").join(asset_path);

        // Memory-map the file (OS handles paging - truly lazy)
        let file = File::open(&asset_file_path)
            .with_context(|| format!("Failed to open archive: {:?}", asset_file_path))?;
        let mmap = unsafe { Mmap::map(&file)? };

        // Parse index header (minimal validation)
        if mmap.len() < 4 {
            return Err(anyhow::anyhow!("Archive too small for header"));
        }
        let asset_count = u32::from_le_bytes(mmap[0..4].try_into().unwrap()) as usize;
        let mut index = HashMap::new();
        let mut pos = 4;

        for _ in 0..asset_count {
            if pos + 4 > mmap.len() {
                return Err(anyhow::anyhow!("Incomplete asset name length"));
            }
            let name_len = u32::from_le_bytes(mmap[pos..pos + 4].try_into().unwrap()) as usize;
            pos += 4;

            if pos + name_len + 16 > mmap.len() {
                return Err(anyhow::anyhow!("Incomplete asset entry"));
            }
            let name = std::str::from_utf8(&mmap[pos..pos + name_len])
                .context("Invalid UTF-8 in asset name")?
                .to_string();
            pos += name_len;

            let offset = u64::from_le_bytes(mmap[pos..pos + 8].try_into().unwrap());
            pos += 8;
            let size = u64::from_le_bytes(mmap[pos..pos + 8].try_into().unwrap());
            pos += 8;

            index.insert(name, (offset, size));
        }

        Ok(LazyArchive {
            data: Arc::new(mmap),
            index,
        })
    }

    fn extensions(&self) -> &[&str] {
        &["lazy"]
    }
}

// ===== SETUP: Generate test archive =====
fn generate_test_archive() -> Result<()> {
    const ARCHIVE_PATH: &str = "assets/test_archive.lazy";
    if Path::new(ARCHIVE_PATH).exists() {
        return Ok(());
    }

    fs::create_dir_all("assets")?;
    let mut file = File::create(ARCHIVE_PATH)?;

    // Header: 2 assets
    file.write_all(&2u32.to_le_bytes())?;

    // Asset 1: "red_pixel"
    let name1 = "red_pixel";
    file.write_all(&(name1.len() as u32).to_le_bytes())?;
    file.write_all(name1.as_bytes())?;
    let offset1_pos = file.stream_position()?;
    file.write_all(&0u64.to_le_bytes())?; // offset placeholder
    file.write_all(&4u64.to_le_bytes())?; // size

    // Asset 2: "blue_pixel"
    let name2 = "blue_pixel";
    file.write_all(&(name2.len() as u32).to_le_bytes())?;
    file.write_all(name2.as_bytes())?;
    let offset2_pos = file.stream_position()?;
    file.write_all(&0u64.to_le_bytes())?;
    file.write_all(&4u64.to_le_bytes())?;

    // Data section
    let data_start = file.stream_position()?;
    file.write_all(&[255, 0, 0, 255])?; // red
    let blue_start = file.stream_position()?;
    file.write_all(&[0, 0, 255, 255])?; // blue

    // Patch offsets
    file.seek(SeekFrom::Start(offset1_pos))?;
    file.write_all(&data_start.to_le_bytes())?;
    file.seek(SeekFrom::Start(offset2_pos))?;
    file.write_all(&blue_start.to_le_bytes())?;

    println!("✅ Generated test archive at {}", ARCHIVE_PATH);
    Ok(())
}

// ===== RUNTIME: Load specific asset from archive =====
#[derive(Resource)]
struct AssetLoadState {
    archive_loaded: bool,
    sprite_spawned: bool,
}

fn load_specific_asset(
    mut commands: Commands,
    asset_server: Res<AssetServer>,
    archives: Res<Assets<LazyArchive>>,
    mut images: ResMut<Assets<Image>>,
    mut state: ResMut<AssetLoadState>,
) {
    if state.sprite_spawned {
        return;
    }

    // Load archive handle (triggers loading)
    let archive_handle: Handle<LazyArchive> = asset_server.load("test_archive.lazy");

    // Wait for archive metadata to load
    if !state.archive_loaded && asset_server.is_loaded_with_dependencies(&archive_handle) {
        state.archive_loaded = true;
        println!("✅ Archive metadata loaded. Extracting 'red_pixel'...");
    }

    if !state.archive_loaded {
        return;
    }

    // Extract specific asset from archive
    if let Some(archive) = archives.get(&archive_handle) {
        if let Some(&(offset, size)) = archive.index.get("red_pixel") {
            let data = &archive.data[offset as usize..(offset + size) as usize];

            // Create 1x1 image from raw bytes
            let image = Image::new(
                Extent3d {
                    width: 1,
                    height: 1,
                    depth_or_array_layers: 1,
                },
                TextureDimension::D2,
                data.to_vec(),
                TextureFormat::Rgba8UnormSrgb,
                TextureUsages::TEXTURE_BINDING | TextureUsages::COPY_DST,
            );

            let image_handle = images.add(image);

            // Spawn visible sprite
            commands.spawn(SpriteBundle {
                texture: image_handle,
                transform: Transform::from_scale(Vec3::splat(64.0)),
                ..default()
            });

            println!("✅ Loaded 'red_pixel' ({} bytes) and spawned sprite!", size);
            state.sprite_spawned = true;
        } else {
            warn!("Asset 'red_pixel' not found in archive");
        }
    }
}

fn setup(mut commands: Commands) {
    commands.spawn(Camera2dBundle::default());
    println!("🚀 Starting lazy archive demo...");
    println!("ℹ️  Archive contains 2 assets but only 'red_pixel' is loaded");
}

fn main() -> Result<()> {
    // Generate archive BEFORE Bevy starts (avoids asset system conflicts)
    generate_test_archive()?;

    App::new()
        .insert_resource(AssetLoadState {
            archive_loaded: false,
            sprite_spawned: false,
        })
        .add_plugins(DefaultPlugins.set(AssetPlugin {
            // Critical: Prevent Bevy from loading entire archive as bytes
            watch_for_changes: false,
            ..default()
        }))
        .init_asset::<LazyArchive>()
        .register_asset_loader(LazyArchiveLoader)
        .add_systems(Startup, setup)
        .add_systems(Update, load_specific_asset)
        .run();

    Ok(())
}"
}

