  "main.rs": "use anyhow::{Context, Result};
use cms::content_info::ContentInfo;
use cms::signed_data::SignedData;
use std::env;
use std::fs;

fn main() -> Result<()> {
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        anyhow::bail!("Usage: {} <der_file>", args[0]);
    }
    let file_path = &args[1];

    let body = fs::read(file_path)
        .with_context(|| format!("Failed to read file: {}", file_path))?;

    let ci = ContentInfo::from_der(&body)
        .with_context(|| "Failed to parse ContentInfo from DER")?;

    if ci.content_type != cms::signed_data::SIGNED_DATA_OID {
        anyhow::bail!("ContentInfo is not signedData. OID: {}", ci.content_type);
    }

    let sd = SignedData::from_der(ci.content.as_bytes())
        .with_context(|| "Failed to parse SignedData from ContentInfo content")?;

    println!("✅ Successfully decoded SCEP PKIOperation message!");
    println!("   SignedData version: {}", sd.version);
    println!("   Digest algorithms: {}", sd.digest_algorithms.len());
    println!("   Encapsulated content type: {}", sd.encap_content_info.content_type);
    println!(
        "   Certificates: {}",
        sd.certificates.as_ref().map_or(0, |c| c.len())
    );
    println!("   SignerInfos: {}", sd.signer_infos.len());

    Ok(())
}"
}

