    async fn connect_to_database(&self, db_name: &str) -> Result<tokio_postgres::Client, Error> {
        let conn_str = format!(
            "host=localhost port={} user=postgres password={} dbname={}",
            self.db_config.port,
            self.db_config.postgres_password,
