/// Safe to move/send because owner is heap-allocated (Box) and references
/// remain valid after moves. Implements Send/Sync when inner types allow.
#[self_referencing]
struct JsonBundle {
    json: String,
    #[borrows(json)]
    #[not_covariant] // Required for &str references in self-referential structs
    data: MyData<'this>,
}

