    // Simulate received JSON payload (e.g., from TCP stream)
    let json_payload = r#"{"data": "zero-copy", "more_data": "no_cloning"}"#.to_string();

    // Deserialize ONCE into self-referential bundle
    // - json field owns the raw string
    // - data field holds references into json field
    // - no string cloning occurs
    let bundle = JsonBundleBuilder {
        json: json_payload,
        data_builder: |json_str| {
            serde_json::from_str(json_str)
