use signal_hook::iterator::Signals;
use signal_hook::consts::{SIGINT, SIGTERM};

#[derive(Debug)]
enum Message {
    Quit,
}

fn yield_signals(sender: Sender<Message>, stop_flag: Arc<AtomicBool>) {
    if let Ok(mut signals) = Signals::new(&[SIGINT, SIGTERM]) {
        while !stop_flag.load(Ordering::Relaxed) {
            for sig in signals.pending() {
                if sig == SIGINT || sig == SIGTERM {
                    sender.send(Message::Quit).ok();
                }
            }
            thread::sleep(Duration::from_millis(50));
        }
    }
}

fn yield_keys(sender: Sender<Message>, stop_flag: Arc<AtomicBool>) {
    // Enter raw mode (automatically exits raw mode when dropped)
    let mut stdout = io::stdout().into_raw_mode().unwrap();
    write!(stdout, "{}{}Press 'q' to quit\r\n", termion::clear::All, termion::cursor::Goto(1, 1)).unwrap();
    stdout.flush().unwrap();

    let mut stdin = async_stdin().bytes();

    while !stop_flag.load(Ordering::Relaxed) {
        match stdin.next() {
            Some(Ok(b)) if b == b'q' => {
                sender.send(Message::Quit).ok();
            }
            Some(Err(_)) => break,
            _ => thread::sleep(Duration::from_millis(10)),
        }
    }
}

fn main() {
    let (tx, rx) = mpsc::channel();
    let stop_flag = Arc::new(AtomicBool::new(false));

    // Spawn signal handler thread
    let sig_stop = stop_flag.clone();
    let sig_tx = tx.clone();
    let signal_thread = thread::spawn(move || yield_signals(sig_tx, sig_stop));

    // Spawn key input thread
    let key_stop = stop_flag.clone();
    let key_tx = tx.clone();
    let key_thread = thread::spawn(move || yield_keys(key_tx, key_stop));

    // Main event loop
    for msg in rx.iter() {
