  "main.rs": "use std::future::Future;
use std::task::{Context, Poll};
use std::time::Duration;

/// Tries to poll the future once. If ready, returns the value.
/// If pending, spawns a Tokio task to await the future and calls `pending_handler` with the result.
/// Returns `Some(value)` if ready, `None` if pending (task spawned).
fn try_poll_or_spawn<F, R, FPending>(future: F, pending_handler: FPending) -> Option<R>
where
    F: Future<Output = R> + Send + 'static,
    FPending: FnOnce(R) + Send + 'static,
{
    // Create no-op waker (safe since we only poll once; pending futures move to new task)
    let waker = std::task::Waker::noop();
    let mut cx = Context::from_waker(&waker);
    let mut pinned = Box::pin(future);

    match pinned.as_mut().poll(&mut cx) {
        Poll::Ready(val) => Some(val),
        Poll::Pending => {
            tokio::spawn(async move {
                let val = pinned.await;
                pending_handler(val);
            });
            None
        }
    }
}

#[tokio::main]
async fn main() {
    println!("=== Test 1: Ready Future ===");
    let res = try_poll_or_spawn(
        async { "Ready immediately!" },
        |v| println!("[TASK] Should not execute: {}", v),
    );
    match res {
        Some(v) => println!("[MAIN] Got ready value: {}", v),
        None => println!("[MAIN] Unexpected pending"),
    }

    println!("\n=== Test 2: Pending Future ===");
    let res = try_poll_or_spawn(
        async {
            tokio::time::sleep(Duration::from_millis(50)).await;
            "Completed after delay!"
        },
        |v| println!("[TASK] Spawned task got value: {}", v),
    );
    match res {
        Some(v) => println!("[MAIN] Unexpected ready: {}", v),
        None => println!("[MAIN] Future pending; handling in spawned task"),
    }

    // Allow time for spawned task to complete
    tokio::time::sleep(Duration::from_millis(100)).await;
    println!("\n[MAIN] Exiting");
}"
}

