};

/// Handler for '.' and ',' keys that deletes preceding whitespace before inserting
struct DotCommaHandler {
    ch: char,
}

impl ConditionalEventHandler for DotCommaHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();

        // Only examine text before cursor
        let line_before_cursor = &line[..pos];

        // Find last non-whitespace character before cursor
        if let Some(last_non_ws_idx) = line_before_cursor
            .rfind(|c: char| !c.is_whitespace())
        {
            // Calculate whitespace characters between last non-WS char and cursor
            let whitespace_count = pos - (last_non_ws_idx + 1);

            if whitespace_count > 0 {
                // 1. Kill whitespace region (backwards from cursor)
                let kill_cmd = Cmd::Edit(EditCommand::Kill(Movement::BackwardChar(
                    whitespace_count as RepeatCount,
                )));

                // 2. Insert the character (., etc.)
                let insert_cmd = Cmd::SelfInsert(1, self.ch);

                // Execute both commands sequentially
                return Some(Cmd::Macro(vec![kill_cmd, insert_cmd]));
            }
        }

        // No whitespace to clean: let default handler insert character
        None
    }
}

/// Minimal helper with SQL-like completion that appends space on unique match
struct SqlHelper;

impl Completer for SqlHelper {
    type Candidate = Pair;

    fn complete(
        &self,
        line: &str,
        pos: usize,
        _ctx: &Context<'_>,
    ) -> Result<(usize, Vec<Self::Candidate>)> {
        // Find start of current word
        let word_start = line[..pos]
            .rfind(|c: char| c.is_whitespace())
            .map(|i| i + 1)
            .unwrap_or(0);
        let word = &line[word_start..pos];

        // Simple completion candidates with trailing space
        let candidates = match word {
            "bo" => vec![Pair {
                display: "book".into(),
                replacement: "book ".into(), // Note trailing space
            }],
            "au" => vec![Pair {
                display: "author".into(),
                replacement: "author ".into(),
            }],
            "ti" => vec![Pair {
                display: "title".into(),
                replacement: "title ".into(),
            }],
            _ => vec![],
        };

        Ok((word_start, candidates))
    }
}

impl Hinter for SqlHelper {
    type Hint = String;
    fn hint(&self, _line: &str, _pos: usize, _ctx: &Context<'_>) -> Option<Self::Hint> {
        None
    }
}

impl Highlighter for SqlHelper {
    fn highlight<'l>(&self, line: &'l str, _pos: usize) -> std::borrow::Cow<'l, str> {
        std::borrow::Cow::Borrowed(line)
    }
}

impl Validator for SqlHelper {
    fn validate(
        &self,
        _ctx: &mut rustyline::validate::ValidationContext,
    ) -> Result<rustyline::validate::ValidationResult> {
        Ok(rustyline::validate::ValidationResult::Valid(None))
    }
}

// Required blank implementation
impl rustyline::Helper for SqlHelper {}

fn main() -> Result<()> {
    let config = Config::builder()
        .completion_type(CompletionType::List)
        .build();

    let mut editor = Editor::with_config(config)?;
    editor.set_helper(Some(SqlHelper));

    // Bind '.' and ',' to our smart handler
    editor.bind_sequence(
        KeyEvent::new('.', Modifiers::NONE),
        EventHandler::Conditional(Box::new(DotCommaHandler { ch: '.' })),
    );
    editor.bind_sequence(
        KeyEvent::new(',', Modifiers::NONE),
        EventHandler::Conditional(Box::new(DotCommaHandler { ch: ',' })),
    );

    println!("\n=== Rustyline Cursor Positioning Demo ===");
    println!("Type 'bo' then TAB to complete 'book '");
    println!("Then press '.' - cursor should stay AFTER the dot");
    println!("Try: bo<TAB>.ti<TAB>\n");

    loop {
        match editor.readline("zql> ") {
            Ok(line) => {
                println!("Executed: {}", line.trim());
                editor.add_history_entry(line.as_str())?;
            }
            Err(ReadlineError::Interrupted) => {
                println!("\nInterrupted");
                break;
            }
            Err(ReadlineError::Eof) => {
                println!("\nEOF");
                break;
            }
            Err(err) => {
                eprintln!("\nError: {:?}", err);
                break;
            }
        }
    }
    Ok(())
}"
}

