use http::{header::ORIGIN, Request, StatusCode};
use tower_http::cors::CorsLayer;

/// Middleware to validate Origin header for WebSocket connections
/// Blocks requests missing Origin header or with unauthorized origin
async fn validate_websocket_origin<B>(
    req: Request<B>,
    next: Next<B>,
) -> Result<Response, StatusCode> {
    let origin = req
        .headers()
        .get(ORIGIN)
        .and_then(|v| v.to_str().ok());

    // In production: parse origin properly, handle ports, case-insensitivity, and allowlists
    match origin {
        Some("https://www.example.com") => Ok(next.run(req).await),
        _ => Err(StatusCode::FORBIDDEN),
    }
}

/// WebSocket handler (no origin check needed - handled by middleware)
async fn ws_handler(ws: WebSocketUpgrade) -> impl IntoResponse {
    ws.on_upgrade(handle_websocket)
}

/// Simple echo WebSocket handler for demonstration
async fn handle_websocket(mut socket: WebSocket) {
    while let Some(Ok(msg)) = socket.recv().await {
        if socket.send(msg).await.is_err() {
            break;
        }
    }
}

#[tokio::main]
async fn main() {
    // CORS layer for non-WebSocket routes (browsers ignore CORS for WebSocket,
    // but this protects other endpoints and sets headers on upgrade responses)
    let cors_layer = CorsLayer::new()
        .allow_origin("https://www.example.com".parse::<http::HeaderValue>().unwrap())
        .allow_methods([http::Method::GET, http::Method::POST])
        .allow_headers([http::header::CONTENT_TYPE]);

    // Router with origin validation applied ONLY to WebSocket route
    let app = Router::new()
        .route(
            "/ws",
            get(ws_handler).layer(middleware::from_fn(validate_websocket_origin)),
        )
        .layer(cors_layer);

    let listener = tokio::net::TcpListener::bind("127.0.0.1:3000")
        .await
        .unwrap();
    println!("Server running at http://{}", listener.local_addr().unwrap());
    axum::serve(listener, app).await.unwrap();
}"
