    let mut tokens = Vec::new();
    let mut current = String::new();
    let mut in_single_quote = false;
    let mut in_token = false;

    for c in s.chars() {
        if in_single_quote {
            if c == '\'' {
                in_single_quote = false;
            } else {
                current.push(c);
            }
        } else {
            match c {
                '\'' => {
                    in_single_quote = true;
                    in_token = true;
                }
                ' ' | '\t' | '\n' | '\r' => {
                    if in_token {
                        tokens.push(current);
                        current = String::new();
                        in_token = false;
                    }
                }
                _ => {
                    current.push(c);
                    in_token = true;
                }
            }
        }
    }

    // Push final token if actively building one (handles well-formed input per problem constraints)
    if in_token || in_single_quote {
        tokens.push(current);
    }

    tokens
}

