/// Rewrites import paths: flattens `vexide::devices::X` to `vexide::X`
/// Handles edge cases:
/// - `vexide::devices::{a,b}` → `vexide::{a,b}`
/// - `vexide::devices` (with children) → `vexide` + children promoted
/// - `vexide::devices` (leaf) → removed
/// - Preserves wildcards, aliases, and nested structures
fn rewrite_imports(root: &SyntaxNode) -> String {
    let mut edits = Vec::new();
    let source_text = root.text().to_string();

    // Process every `use` item in the file
    for use_item in root.descendants().filter_map(ast::Use::cast) {
        if let Some(use_tree) = use_item.use_tree() {
            if let Some(new_tree) = process_use_tree(&use_tree) {
                // Only replace if tree changed
                if new_tree.syntax().to_string() != use_tree.syntax().to_string() {
                    edits.push((
                        use_tree.syntax().text_range(),
                        new_tree.syntax().to_string(),
                    ));
                }
            } else {
                // Remove entire use item if tree was eliminated
                edits.push((use_item.syntax().text_range(), String::new()));
            }
        }
    }

    // Apply edits in reverse order to maintain valid offsets
    let mut result_chars: Vec<char> = source_text.chars().collect();
    for (range, replacement) in edits.iter().rev() {
        let start = range.start().into();
        let end = range.end().into();
        result_chars.splice(start..end, replacement.chars());
    }

    result_chars.into_iter().collect()
}

/// Processes a single UseTree node recursively
fn process_use_tree(tree: &ast::UseTree) -> Option<ast::UseTree> {
    use ra_ap_syntax::ast::make;

    let has_wildcard = tree.star_token().is_some();
    let alias = tree.alias();
    let path = tree.path();
    let children = tree.use_tree_list();

    // Case 1: Node has a path we need to transform
    if let Some(p) = path {
        let path_str = p.to_string();
        if path_str.starts_with("vexide::devices") {
            let segments: Vec<&str> = path_str.split("::").collect();

            // Subcase A: Exactly "vexide::devices" with children → promote children to "vexide"
            if segments.len() == 2 && children.is_some() {
                let new_children = children.and_then(process_use_tree_list);
                return Some(make::use_tree(
                    make::path_from_str("vexide"),
                    alias,
                    new_children,
                    has_wildcard,
                ));
            }
            // Subcase B: Exactly "vexide::devices" with NO children → remove node
            else if segments.len() == 2 {
                return None;
            }
            // Subcase C: Longer path (e.g., "vexide::devices::smart") → remove "devices" segment
            else if segments.len() > 2 {
                let new_path_str = format!("vexide::{}", segments[2..].join("::"));
                let new_children = children.and_then(process_use_tree_list);
                return Some(make::use_tree(
                    make::path_from_str(&new_path_str),
                    alias,
                    new_children,
                    has_wildcard,
                ));
            }
        }
    }

    // Case 2: Process children recursively (handles grouped imports like `use {a, b}`)
    let new_children = children.and_then(process_use_tree_list);

    // Rebuild node with original path (if exists) and processed children
    // Only keep node if it has content after processing
    if path.is_none() && new_children.is_none() && !has_wildcard {
        return None;
    }

    Some(make::use_tree(
        path.map(|p| make::path_from_str(&p.to_string())),
        alias,
        new_children,
        has_wildcard,
    ))
