    let mut new_trees = Vec::new();
    for tree in list.use_trees() {
        if let Some(processed) = process_use_tree(&tree) {
            new_trees.push(processed);
        }
    }

    if new_trees.is_empty() {
        None
    } else {
        Some(make::use_tree_list(new_trees))
    }
}

fn main() {
