use std::io::{self, Read};
use syn::{visit_mut::VisitMut, Item, UseTree};

/// Rewrites import paths by removing `::devices` segment after `vexide`
struct DeviceFlattener;

impl VisitMut for DeviceFlattener {
    fn visit_use_tree_mut(&mut self, tree: &mut UseTree) {
        // Process children first (depth-first)
        syn::visit_mut::visit_use_tree_mut(self, tree);

        // Handle path patterns starting with vexide::devices
        if let UseTree::Path(path) = tree {
            if path.ident == "vexide" {
                if let UseTree::Path(next_path) = &mut *path.tree {
                    if next_path.ident == "devices" {
                        // Replace `vexide::devices::X` with `vexide::X`
                        *tree = (*next_path.tree).clone();
                        return;
                    }
                } else if let UseTree::Group(group) = &mut *path.tree {
                    // Handle `vexide::{devices, ...}`
                    // Filter out standalone `devices` items in the group
                    group.items.retain(|item| {
                        !matches!(item,
                            UseTree::Name(name) if name.ident == "devices" ||
                            UseTree::Path(p) if p.ident == "devices"
                        )
                    });

                    // If group becomes empty after filtering, replace with nothing
                    if group.items.is_empty() {
                        *tree = UseTree::Path(syn::UsePath {
                            ident: syn::Ident::new("vexide", path.ident.span()),
                            tree: Box::new(UseTree::Group(group.clone())),
                        });
                    }
                }
            }
        }
    }

    // Remove entire `use vexide::devices;` statements
    fn visit_item_mut(&mut self, item: &mut Item) {
        if let Item::Use(use_item) = item {
            if let UseTree::Path(path) = &use_item.tree {
                if path.ident == "vexide" {
                    if let UseTree::Path(next_path) = &*path.tree {
                        if next_path.ident == "devices" && matches!(&*next_path.tree, UseTree::Name(_)) {
                            // Replace invalid import with empty macro (will be filtered later)
                            *item = Item::Macro(syn::ItemMacro {
                                attrs: vec![],
                                ident: None,
                                mac: syn::Macro {
                                    path: syn::Path::from(syn::Ident::new("__REMOVED__", use_item.span())),
                                    bang_token: Default::default(),
                                    delimiter: syn::MacroDelimiter::Brace(Default::default()),
                                    tokens: quote::quote! {},
                                },
                                semi_token: Some(Default::default()),
                            });
                            return;
                        }
                    }
                }
            }
        }
        syn::visit_mut::visit_item_mut(self, item);
    }
}

fn main() -> io::Result<()> {
    let mut code = String::new();
    io::stdin().read_to_string(&mut code)?;

    // Fallback regex cleanup for edge cases syn might miss
    let regex_cleanup = Regex::new(r"\bvexide::devices(?:::|$)").unwrap();
    let code = regex_cleanup.replace_all(&code, "vexide");

    // Parse with syn (preserves most structure)
    let mut file = syn::parse_file(&code).expect("Failed to parse Rust code");

    // Apply AST transformations
    DeviceFlattener.visit_file_mut(&mut file);

    // Remove placeholder items created during transformation
    file.items.retain(|item| !matches!(item, Item::Macro(m) if m.mac.path.segments.first().map_or(false, |s| s.ident == "__REMOVED__")));

    // Print reformatted code
    let output = quote::quote!(#file).to_string();

    // Final cleanup: remove empty group artifacts
    let empty_group_fix = Regex::new(r"\{\s*,\s*").unwrap();
    let output = empty_group_fix.replace_all(&output, "{");
    let empty_group_fix = Regex::new(r",\s*\}").unwrap();
    let output = empty_group_fix.replace_all(&output, "}");
    let consecutive_commas = Regex::new(r",\s*,").unwrap();
    let output = consecutive_commas.replace_all(&output, ",");

    print!("{}", output);
    Ok(())
}
"
}

