{
  "Cargo.toml": "[package]
name = "vexide-import-rewriter"
version = "0.1.0"
edition = "2021"

[dependencies]
# Uses rust-analyzer's syntax crate directly from git
# Note: Update 'rev' to a recent commit if compilation fails
syntax = { git = "https://github.com/rust-lang/rust-analyzer", rev = "6d6e80a" }",
  "main.rs": "use syntax::{
    ast::{self, make},
    edit::SyntaxEditor,
    AstNode, SourceFile, SyntaxNode,
};
use std::io::{self, Read};

/// Rewrites imports to flatten `vexide::devices::X` → `vexide::X`
fn rewrite_imports(editor: &mut SyntaxEditor, root: &SyntaxNode) {
    for use_item in root.descendants().filter_map(ast::Use::cast) {
        if let Some(use_tree) = use_item.use_tree() {
            process_use_tree(editor, &use_tree, "");
        }
    }
}

/// Recursively processes a use tree node with accumulated parent path context
fn process_use_tree(editor: &mut SyntaxEditor, tree: &ast::UseTree, parent_path: &str) {
    // Track current path context for nested trees
    let current_path = if let Some(path) = tree.path() {
        let path_str = path.to_string();
        if parent_path.is_empty() {
            path_str
        } else {
            format!("{}::{}", parent_path, path_str)
        }
    } else {
        parent_path.to_string()
    };

    // Handle path replacement logic
    if let Some(path_node) = tree.path() {
        let path_str = path_node.to_string();
        let new_path = if current_path.starts_with("vexide::devices::") {
            // Case: vexide::devices::smart::X → vexide::smart::X
            let suffix = &current_path["vexide::devices".len()..];
            Some(format!("vexide{}", suffix))
        } else if current_path == "vexide::devices" {
            // Case: vexide::devices::* → vexide::*
            // Case: vexide::devices::{...} → vexide::{...}
            if tree.star_token().is_some() || tree.use_tree_list().is_some() {
                Some("vexide".to_string())
            } else {
                // Invalid standalone `use vexide::devices;` - remove path
                None
            }
        } else if parent_path == "vexide" && path_str == "devices" {
            // Nested case under vexide: {devices::{...}} → promote children
            if let Some(list) = tree.use_tree_list() {
                // Replace entire `devices::{...}` node with its children
                // Children paths are already relative to devices (e.g., "smart")
                // They'll be processed recursively with parent_path="vexide"
                for child in list.use_trees() {
                    // Recurse into children with updated context
                    process_use_tree(editor, &child, "vexide");
                }
                // Remove the "devices" path node itself
                editor.delete(path_node.syntax());
                return;
            } else if tree.star_token().is_some() {
                // vexide::{devices::*} → vexide::*
                Some("vexide".to_string())
            } else {
                // Standalone `devices` under vexide with no children/star - remove
                editor.delete(tree.syntax());
                return;
            }
        } else if parent_path == "vexide" && path_str.starts_with("devices::") {
            // Nested case: vexide::{devices::smart} → vexide::{smart}
            Some(path_str["devices::".len()..].to_string())
        } else {
            None
        };

        // Apply path replacement if determined
        if let Some(new_path_str) = new_path {
            if !new_path_str.is_empty() {
                let new_path_node = make::path_from_str(&new_path_str);
                editor.replace(path_node.syntax(), new_path_node.syntax());
            } else {
                editor.delete(path_node.syntax());
            }
        }
    }

    // Recurse into nested use trees with updated path context
    if let Some(list) = tree.use_tree_list() {
        for child in list.use_trees() {
            process_use_tree(editor, &child, &current_path);
        }
    }
}

fn main() -> io::Result<()> {
    // Read entire stdin
    let mut code = String::new();
    io::stdin().read_to_string(&mut code)?;

    // Parse Rust code
    let source_file = SourceFile::parse(&code).ok();
    let root = match source_file {
        Some(sf) => sf.syntax().clone(),
        None => {
            eprintln!("Error: Failed to parse input as valid Rust code");
            return Ok(());
        }
    };

    // Apply rewrites
    let mut editor = SyntaxEditor::new();
    rewrite_imports(&mut editor, &root);
    let new_root = editor.edit(&root);

    // Output transformed code
    print!("{}", new_root);
    Ok(())
}
"
}

