name = "gizmo_rotation_example"
version = "0.1.0"
edition = "2021"

[dependencies]
bevy = "0.13"",
  "main.rs": "use bevy::prelude::*;

#[derive(Component)]
struct Cube;

fn main() {
    App::new()
        .add_plugins(DefaultPlugins.set(GizmoPlugin::default()))
        .add_systems(Startup, setup)
        .add_systems(Update, draw_gizmo)
        .run();
}

fn setup(
    mut commands: Commands,
    mut meshes: ResMut<Assets<Mesh>>,
    mut materials: ResMut<Assets<StandardMaterial>>,
) {
    // Spawn rotated cube with marker component
    commands.spawn((
        PbrBundle {
            mesh: meshes.add(Cuboid::default()),
            material: materials.add(Color::rgb(0.8, 0.7, 0.6)),
            transform: Transform::from_rotation(Quat::from_euler(
                EulerRot::XYZ,
                std::f32::consts::PI / 6.0, // 30°
                std::f32::consts::PI / 4.0, // 45°
                std::f32::consts::PI / 8.0, // 22.5°
            )),
            ..default()
        },
        Cube,
    ));

    // Spawn camera
    commands.spawn(Camera3dBundle {
        transform: Transform::from_translation(Vec3::new(3.0, 3.0, 3.0))
            .looking_at(Vec3::ZERO, Vec3::Y),
        ..default()
    });

    // Add ambient light
    commands.insert_resource(AmbientLight {
        brightness: 0.5,
        ..default()
    });
}

fn draw_gizmo(
    mut gizmos: Gizmos,
    cube_query: Query<&GlobalTransform, With<Cube>>,
) {
    if let Ok(global_tf) = cube_query.get_single() {
        // Decompose transform (ignores scale for normal calculations)
        let (_, cube_rot, cube_pos) = global_tf.to_scale_rotation_translation();

        // Simulate raycast hit on front face (local +Z)
        let local_normal = Vec3::Z;
        let world_normal = (cube_rot * local_normal).normalize();
        let face_center = cube_pos + world_normal * 0.5;

        // Convert world normal back to cube's local space for axis rounding
        let local_normal_computed = cube_rot.inverse() * world_normal;
        let (rounded_normal, axis, sign) = round_to_axis(local_normal_computed);

        // Select local tangent vectors based on hit face
        let (tangent1_local, tangent2_local) = match (axis, sign) {
            (0, 1.0) => (Vec3::Y, Vec3::Z),      // +X face
            (0, -1.0) => (Vec3::Y, -Vec3::Z),    // -X face
            (1, 1.0) => (Vec3::Z, Vec3::X),      // +Y face
            (1, -1.0) => (-Vec3::Z, Vec3::X),    // -Y face
            (2, 1.0) => (Vec3::X, Vec3::Y),      // +Z face (front)
            (2, -1.0) => (Vec3::X, -Vec3::Y),    // -Z face (back)
            _ => (Vec3::X, Vec3::Y),
        };

        // Transform tangents to world space
        let tangent1_world = (cube_rot * tangent1_local).normalize();
        let tangent2_world = (cube_rot * tangent2_local).normalize();

        // Construct orthonormal basis (ensures right-handed system)
        let z_axis = world_normal;
        let x_axis = tangent1_world;
        // Recompute y-axis to guarantee orthogonality with actual normal
        let y_axis = z_axis.cross(x_axis).normalize();

        // Build rotation matrix from basis vectors
        let mat = Mat3::from_cols(x_axis, y_axis, z_axis);
        let gizmo_rotation = Quat::from_rotation_mat3(&mat);

        // Draw gizmo slightly offset to avoid z-fighting
        let gizmo_transform = Transform::from_translation(face_center + world_normal * 0.01)
            .with_rotation(gizmo_rotation);

        gizmos.rect(
            gizmo_transform.to_isometry(),
            Vec2::new(1.0, 1.0),
            Color::WHITE,
        );
    }
}

/// Rounds a vector to the nearest axis-aligned direction
fn round_to_axis(v: Vec3) -> (Vec3, usize, f32) {
    let abs_x = v.x.abs();
    let abs_y = v.y.abs();
    let abs_z = v.z.abs();

    // Determine dominant axis
    let (axis, _) = if abs_x > abs_y && abs_x > abs_z {
        (0, abs_x)
    } else if abs_y > abs_z {
        (1, abs_y)
    } else {
        (2, abs_z)
    };

    // Get component value and sign for dominant axis
    let comp = match axis {
        0 => v.x,
        1 => v.y,
        2 => v.z,
        _ => 0.0,
    };
    let sign = if comp >= 0.0 { 1.0 } else { -1.0 };

    // Create rounded normal vector
    let rounded = match axis {
        0 => Vec3::new(sign, 0.0, 0.0),
        1 => Vec3::new(0.0, sign, 0.0),
        2 => Vec3::new(0.0, 0.0, sign),
        _ => Vec3::ZERO,
    };

    (rounded, axis, sign)
}"
