  "main.rs": "fn tokenize(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current = String::new();
    let mut in_single_quote = false;
    let mut token_active = false; // Tracks if current token has content (chars or quote boundaries)

    for c in input.chars() {
        if in_single_quote {
            if c == '\'' {
                in_single_quote = false;
                token_active = true; // Closing quote activates token (even if empty)
            } else {
                current.push(c);
                token_active = true;
            }
        } else {
            match c {
                '\'' => {
                    in_single_quote = true;
                    token_active = true; // Entering quote activates token
                }
                c if c.is_whitespace() => {
                    if token_active {
                        tokens.push(current);
                        current = String::new();
                        token_active = false;
                    }
                    // Skip whitespace when no active token
                }
                _ => {
                    current.push(c);
                    token_active = true;
                }
            }
        }
    }

    // Push final token if active
    if token_active {
        tokens.push(current);
    }

    tokens
}

