        // Get tangent vectors aligned with cube's edges for this face
        let (local_t1, local_t2) = get_tangents_for_normal(local_normal);
        let world_t1 = (cube_transform.rotation * local_t1).normalize();
        let world_t2 = (cube_transform.rotation * local_t2).normalize();

        // Construct orthonormal basis for gizmo:
        // X = first tangent (cube's local X direction on face)
        // Y = second tangent (cube's local Y direction on face)
        // Z = face normal (matches raycast direction)
        let z = world_normal;
        let x = world_t1;
        let y = world_t2;

