        }
    } else if n.z.abs() > 0.9 {
        if n.z > 0.0 {
            (Vec3::X, Vec3::Y)  // +Z face
        } else {
            (Vec3::Y, Vec3::X)  // -Z face
        }
    } else {
        // Fallback for non-axis-aligned (shouldn't happen in block builder)
        (Vec3::X, Vec3::Y)
    }
}
