/// Collect edits for paths needing rewriting within a use tree
fn collect_path_edits(use_tree: &ast::UseTree, edits: &mut Vec<(TextRange, String)>) {
    // Process current node's path if exists
    if let Some(path) = use_tree.path() {
        if let Some(new_path) = rewrite_path(&path) {
            edits.push((path.syntax().text_range(), new_path.to_string()));
        }
    }

    // Recurse into nested use trees
    if let Some(list) = use_tree.use_tree_list() {
        for child in list.use_trees() {
            collect_path_edits(&child, edits);
        }
    }
}

/// Rewrite path: remove 'devices' segment when path starts with 'vexide::devices'
fn rewrite_path(path: &ast::Path) -> Option<ast::Path> {
    let segments: Vec<_> = path.segments().collect();

    // Must have at least 2 segments to match 'vexide::devices'
    if segments.len() < 2 {
        return None;
    }

    // Check first two segments exactly match target
    let first = segments[0].to_string();
    let second = segments[1].to_string();
    if first != "vexide" || second != "devices" {
